-- Poems batch 165
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('72a000ef-a805-44e0-8399-60a9999a8dab','閏月二日雨三日復雨寄斯遠三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','夏雨多驟止，晚灑苦易乾。',72,'全唐诗/poet.song.164000.json','["夏雨多驟止，晚灑苦易乾。", "陰乎不能釋，膏爾殊未闌。", "疎疎政簷溜，浩浩忽木端。", "沈疴頓如失，甘寢不自安。", "遲明復大集，平地如湧湍。", "戲作擁鼻調，以歌田父歡。"]'),
('8dd6aa6e-910c-4f48-ae7a-2653f551ce47','閏月二日雨三日復雨寄斯遠三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','無人南澗遊，老我北窗卧。',72,'全唐诗/poet.song.164000.json','["無人南澗遊，老我北窗卧。", "雨爲洗炎蒸，身成起頹惰。", "幽花曜叢叢，新竹排箇箇。", "是中有餘詩，獨唱誰其和。", "懷君固非遠，念我當數過。", "蟬噪晚聲清，螢飛新月破。"]'),
('75b65159-7d23-4eeb-b4de-a92f3f5937ba','閏七月五日雨中記所見','趙蕃','宋','宋诗','song-poetry','','[]','雨來山爲昏，雨罷山如洗。',96,'全唐诗/poet.song.164000.json','["雨來山爲昏，雨罷山如洗。", "秋風欻已高，長空澹如水。", "其誰知此樂，勝處屬幽子。", "登臨無所詣，溪樓成徙倚。", "沙鷗意氣逸，衝烟棲復起。", "是身困覉束，沿戲直愧爾。", "平生耽佳句，此癖殆至死。", "得酒忽詩成，頹然自醒醉。"]'),
('2202333a-bb7c-430c-81b9-4f0fc1dcc85f','連雨獨飲偶書四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','緣山灌木長，遶舍芳草積。',48,'全唐诗/poet.song.164000.json','["緣山灌木長，遶舍芳草積。", "敢希陶淵明，自謂張仲蔚。", "出門無所詣，閉戶聊自得。", "簡編或倦𠙆，壺觴恣酣適。"]'),
('ed365d2b-19f4-425f-8080-13e020682260','連雨獨飲偶書四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','自昔嗜酒徒，往往皆能詩。',48,'全唐诗/poet.song.164000.json','["自昔嗜酒徒，往往皆能詩。", "詩亦何與酒，胡爲必相資。", "我詩既不工，我酒還復漓。", "頹然亦復醉，信筆輒書之。"]'),
('fdf1974c-5657-4c66-8c0e-938e7c50ed48','連雨獨飲偶書四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','人無送酒錢，官無種秫田。',48,'全唐诗/poet.song.164000.json','["人無送酒錢，官無種秫田。", "鄰家頼可賒，醉過春風顛。", "春風急雨顛，梅黄更連連。", "不念陋巷士，其貧類顔淵。"]'),
('cecd6b63-1153-4507-afaf-70189d154750','連雨獨飲偶書四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','伯倫無他文，一頌自不朽。',48,'全唐诗/poet.song.164000.json','["伯倫無他文，一頌自不朽。", "淵明飲酒詩，乃至二十首。", "未易多寡論，俱能金石壽。", "我乏二子辭，徒然老耽酒。"]'),
('52d94d10-93da-4771-8074-10562dd95a1c','寒雨感懷呈斯遠三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','窮冬固多悲，凍雨仍併作。',120,'全唐诗/poet.song.164000.json','["窮冬固多悲，凍雨仍併作。", "真成晝連夜，直欲寐無覺。", "其陰似春仲，其令豈天錯。", "林棲未歸休，蕭寺猶旅泊。", "孰寬留滯懷，政頼朋友樂。", "梅華開且半，芒屨曾未著。", "溪亭縱微吟，破屋成細酌。", "悠然起遐心，彼哉羞好爵。", "淵明念田園，幼輿志丘壑。", "坐釣有羊裘，峩冠自麟閣。"]'),
('3bca94a3-262d-4f6f-a26b-555ebb3c341f','寒雨感懷呈斯遠三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','少讀隠逸傳，雅意煙霞人。',120,'全唐诗/poet.song.164000.json','["少讀隠逸傳，雅意煙霞人。", "居官早自縛，半世幾沒身。", "青衫類枯葉，兩鬢如爛銀。", "人知趨走苦，己重疾病湮。", "歸微三徑資，尚竊太倉陳。", "鄰里有伏臘，弟兄無越秦。", "况此交友高，而能朝夕親。", "君還志遠遊，所願猶逡巡。", "我乃歎寡與，未易論苦辛。", "勿道車馬乏，勿嫌風雨頻。"]'),
('fbe1c564-edf9-461c-82c7-69ca8b9d62ae','寒雨感懷呈斯遠三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','平生幾交游，念往常恍惚。',120,'全唐诗/poet.song.164000.json','["平生幾交游，念往常恍惚。", "始從五州數，却自他邦述。", "徐州殞川魚，葉縣飛鳬舄。", "吳興罷童迎，漢殿空履跡。", "鯨魚渺洪波，長城墮立壁。", "元龍漫豪氣，子雲終執戟。", "詩壇絕韓呂，詩友無道釋。", "文章固能傳，事業竟何得。", "是皆我深知，半亦君舊識。", "更將寫其心，悲甚不能筆。"]'),
('f10a0874-be26-4fd4-b5f2-b5d8019b4773','是夕雨大作復呈潘提舉','趙蕃','宋','宋诗','song-poetry','','[]','雲行方陸離，月出重蔽虧。',168,'全唐诗/poet.song.164000.json','["雲行方陸離，月出重蔽虧。", "旋聽隠其響，已見沛然馳。", "信有誰能禦，那云鼓再衰。", "天瓢快傾瀉，旱魃勇鞭笞。", "卧想歌謠疾，頓寬車戽疲。", "中宵猶颯沓，既曉尚紛披。", "五日能如一，有年端可期。", "旱頭今已破，雨脚不難垂。", "使者豈爲德，天心茲可知。", "在予非赫赫，於汝要熙熙。", "始急救荒法，終傳喜雨詩。", "但須觀氣象，不必問蓍龜。", "米賤行當復，物生斯得宜。", "寧容倦游者，侘傺獨天涯。"]'),
('9978ab64-a3bd-476d-9054-bd91f52d15a2','招明叔','趙蕃','宋','宋诗','song-poetry','','[]','平原拙生事，數月且食粥。',168,'全唐诗/poet.song.164000.json','["平原拙生事，數月且食粥。", "蠋也巧於貧，晚食以當肉。", "士窮見節義，不以富貴卜。", "用志苟如此，寧有憂不足。", "我生本寒士，犁鉏起窮谷。", "顧惟疎野姿，動輒當忤俗。", "得祿本甚微，奪去蓋聊復。", "雖云出無車，定免赤其族。", "在我無所念，於君果何辱。", "而君終日間，惘惘形面目。", "幼穉悉遣歸，不慮瓶無粟。", "大兒頗類吾，藜羹甘半菽。", "庭前既除草，窗外亦栽菊。", "屬君早來過，束書期共讀。"]'),
('36b6cf46-3704-4243-bdef-0798ebb2fb9e','再用前韻','趙蕃','宋','宋诗','song-poetry','','[]','田家雖賤勞，豐歲飽餐粥。',168,'全唐诗/poet.song.164000.json','["田家雖賤勞，豐歲飽餐粥。", "儒士筆以耕，相形無食肉。", "我生文字盟，向日交友卜。", "自從此邦來，得君一夔足。", "作詩非野格，悟坡更參谷。", "字法皆有師，翩翩信超俗。", "誰云前輩遠，解使神觀復。", "鸞乃鳳之徒，蕙乃蘭之族。", "惟我甚亡頼，於何能見辱。", "又何與於人，嗔君刺在目。", "寒窗夜沉沉，燈燼落金粟。", "芻薪價益高，窘狀稭然菽。", "相看一何有，有子所送菊。", "何以得今夕，把君詩過讀。"]'),
('e767f5e5-5a56-4a9c-8171-d7603c4faa29','十四日二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','梅開在高岡，仰望不可攀。',72,'全唐诗/poet.song.164000.json','["梅開在高岡，仰望不可攀。", "微風一動摇，落片紛斕斑。", "下者隠幽閟，叢然榛棘間。", "著根近溪流，墮地即水灣。", "是物佳莫匹，在處堪解顔。", "扶藜曳芒屩，永日不得還。"]'),
('1c7834f5-e305-48e5-8235-ce89998ec08e','十四日二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','窮冬無苦寒，寬我欠裘褐。',72,'全唐诗/poet.song.164000.json','["窮冬無苦寒，寬我欠裘褐。", "裘褐苟不備，道有猶絺葛。", "童奴忽告言，薪盡米復竭。", "市糴不可賒，囊錢顧安得。", "詩成詎堪煮，梅望當止渴。", "一笑謝兒曹，爾饑由我拙。"]'),
('6de5d41f-5815-4d88-9638-bf865cbf0f86','十二月七日病題四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','曉枕聞屐聲，方知夜來雨。',48,'全唐诗/poet.song.164000.json','["曉枕聞屐聲，方知夜來雨。", "遥憐江南梅，玉立勝越女。", "林深笑成暗，溪淺照亦俯。", "想象不勝情，吾寧久羈旅。"]'),
('23a61541-64c7-48c0-920e-a136e205f2a2','十二月七日病題四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','前朝困壺觴，昨日强撐拄。',48,'全唐诗/poet.song.164000.json','["前朝困壺觴，昨日强撐拄。", "今晨不能支，謁告報公府。", "噤瘁苦春寒，廉纖真雪雨。", "病狀雖摧頹，猶思鷗鷺舉。"]'),
('f3415421-ef17-4f7d-9972-fb7be82f795d','十二月七日病題四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','一代數百年，作者不數人。',48,'全唐诗/poet.song.164000.json','["一代數百年，作者不數人。", "桃李非不芳，梅花獨清真。", "是故吾黨士，愛之踰等倫。", "詩成欲何屬，目斷楚江濱。"]'),
('3ad5391e-bc39-4750-972b-a133637aa93c','十二月七日病題四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','酒亦不難止，無以寄吾興。',48,'全唐诗/poet.song.164000.json','["酒亦不難止，無以寄吾興。", "縱然酒可止，詩恐不受命。", "二者必相須，未易相負勝。", "所以千載人，不能除此病。"]'),
('654b68af-3470-4776-a8ae-53f4ff4aa48c','天帚竹','趙蕃','宋','宋诗','song-poetry','','[]','自離竹隠居，借宅亦多種。',72,'全唐诗/poet.song.164000.json','["自離竹隠居，借宅亦多種。", "周旋雖不乏，瀟灑常入夢。", "猗歟此窗綠，輟自口腹奉。", "別之亦幾年，似困鳥雀鬨。", "茲晨蹔來歸，溉掃何妨痛。", "竹隠從未還，風猷入吾用。"]'),
('2d3d4daa-1aef-4653-8709-4d0a4243e44c','悼竹','趙蕃','宋','宋诗','song-poetry','','[]','此君如高人，風節常凌厲。',168,'全唐诗/poet.song.164000.json','["此君如高人，風節常凌厲。", "雖經隆冬中，正色不少替。", "春今盡正月，萌蘗且次第。", "天公出奇手，白晝變昏翳。", "初飛佛場花，繼灑鮫人涕。", "羣兒顧驚走，老眼亦睥睨。", "是時凡草木，掩抑若自衛。", "惟君獨傲然，略不威嚴霽。", "太剛竟摧折，乃悟非善計。", "追懷周旋久，於此增懔悷。", "其生既冤死，其死可輕弊。", "當爲殺青簡，更以色絲綴。", "盡書卓行人，出入生死際。", "作我座右銘，蘄能免於戾。"]'),
('a6981d54-0326-44bd-8444-681e6e846fee','次韻斯遠投宿招賢道店對竹再用前韻見懷二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','興懷王子猷，匪但一朝夕。',48,'全唐诗/poet.song.164000.json','["興懷王子猷，匪但一朝夕。", "看君愛主意，與渠蓋連璧。", "詩成辱持贈，絕勝梧桐滴。", "我句本非儔，分光藉鄰壁。"]'),
('c75563bf-d7cc-45f8-9587-5b4eabd6e46a','次韻斯遠投宿招賢道店對竹再用前韻見懷二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君行日未昏，意適先投宿。',48,'全唐诗/poet.song.164000.json','["君行日未昏，意適先投宿。", "世有疾走人，奔波寧自足。", "遥知琢詩際，聲韻驚鄰曲。", "寄謝主人翁，取將宜刻竹。"]'),
('4e3577f4-c079-4049-911d-adcca3831cb7','明叔以僕護筍不除作長句爲調次韻','趙蕃','宋','宋诗','song-poetry','','[]','春風逞夭邪，爛漫吹已足。',120,'全唐诗/poet.song.164000.json','["春風逞夭邪，爛漫吹已足。", "維暮筍乃生，如亂更約束。", "吾人爲之寄，詎可謾弗錄。", "况其耿介姿，政已不可辱。", "去云解籜後，爲我呈新綠。", "新詩急拜賜，句解先我欲。", "我豈兒女曹，撫玩斯同俗。", "又殊市井輩，狥利蘄盡劚。", "要當去留間，明見妨意曲。", "分餉可得多，但令舂脫粟。"]'),
('a799074e-702e-4ff0-b856-c4bf2d8d71a0','有懷竹隠之筍復用前韻','趙蕃','宋','宋诗','song-poetry','','[]','我家章泉旁，生事苦不足。',120,'全唐诗/poet.song.164000.json','["我家章泉旁，生事苦不足。", "惟餘數畝地，有竹森似束。", "別來夢寐之，詩語見編錄。", "况當萌茁時，孰杜樵採辱。", "官居亦何有，有此數竿綠。", "定應好事人，知我來此欲。", "不然朝暮間，何計能醫俗。", "尚嫌地形淺，筍夥當掘斸。", "不能助幽深，何况增詰曲。", "袖短舞難長，吾俸五斗粟。"]'),
('1fed3e1f-d477-4d2a-848d-33a403a4c48e','徐提幹爲沈運使種竹於上饒新居昭禮有詩蕃同作','趙蕃','宋','宋诗','song-poetry','','[]','玉谿佳山水，不減閬州南。',144,'全唐诗/poet.song.164000.json','["玉谿佳山水，不減閬州南。", "新居助幽深，所欠萬竹參。", "徐郎亦好事，知公幽趣耽。", "過溪買龍雛，雲根破烟嵐。", "地形擇便宜，土壤泉亦甘。", "春雷一番筍，要戒園翁饞。", "鄰里約來往，要須開徑三。", "風月無常主，平分未爲貪。", "定有王子猷，造門不輿藍。", "嘯詠忘主賓，用意端不凡。", "政爾功名迫，此事未易譚。", "待公幅巾歸，我亦脫青衫。"]'),
('2dbd34d9-8dc8-4ed2-8efb-077f7f2d6813','至節矣猶未見梅頗形思渴書呈斯遠滕兄主簿前日書來亦問梅花消息併此奉簡','趙蕃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','言歸雖故棲，雅志亦良友。',144,'全唐诗/poet.song.164000.json','["言歸雖故棲，雅志亦良友。", "奈何數詩筒，不得屢杯酒。", "縱云三十里，每見莫能久。", "是以朝暮間，相思輒成又。", "去年梅花作，佳處猶在口。", "今年梅花期，撫事纔轉首。", "翩思接中屨，兀若限林藪。", "君行集彤庭，我政安甕牖。", "西湖覓林逋，東閣懷杜叟。", "寒歲識松堅，同心見蘭臭。", "前朝習鑿齒，書來問安否。", "併話羅浮山，抗塵應抖擻。"]'),
('915cfdf4-98d4-46de-a700-7042c78b5fd7','三月三十日余有章貢之役陳明叔嚴從禮載酒見餞於白泉張伯永繼至','趙蕃','宋','宋诗','song-poetry','','[]','相從數月間，已復兩爲別。',84,'全唐诗/poet.song.164000.json','["相從數月間，已復兩爲別。", "此身竟何有，百年終是客。", "近役不隔州，音問可絡繹。", "江南虛成市，白泉强名剎。", "何勞共追餞，令我滋不悅。", "觴行期月上，月上尊已側。", "我卧四壁空，君歸度舟闊。"]'),
('e7728626-6f03-45c5-a13b-8b50ccb60dbd','僕自北門放舟過溥子而告行坐間出示上蔡景迂兩先生墨帖具道先世契之詳益重其別爲成是詩','趙蕃','宋','宋诗','song-poetry','','[]','扁舟過辭君，落日繫高柳。',144,'全唐诗/poet.song.164000.json','["扁舟過辭君，落日繫高柳。", "愧君惜遠別，留我飲以酒。", "夜深不知罷，感歎屢執手。", "書題見晁謝，光怪森在牖。", "憶昔蓬山老，實與文靖友。", "同登靖康朝，諫疏猶在不。", "吾人世其家，樹立敢自後。", "君才真杞梓，如我乃枯朽。", "漂流偶相值，稱我不容口。", "君今非少壯，我亦驚老醜。", "相逢定何日，相勉敢不厚。", "老農誠有言，良田務除莠。"]'),
('9656c7c6-717f-4d9e-9044-bf6ca8725cb0','中秋無月呈審知','趙蕃','宋','宋诗','song-poetry','','[]','前年中秋月，痁鬼方見虐。',180,'全唐诗/poet.song.164000.json','["前年中秋月，痁鬼方見虐。", "徹曙不得眠，搘爐親煮藥。", "子時過橋來，勞我非赴約。", "評詩雜精粗，有味勝大嚼。", "去年中秋月，應候痁復作。", "少休塘下寺，欲進悲足弱。", "喬松接修竹，聽雨仍落落。", "徘徊亦忘寐，孤詠同緯絡。", "漂流到今年，高興屬快閣。", "何期悼亡歸，舟並南山泊。", "前年呻吟地，追隨恍如昨。", "天公似憐我，爲遣雲垂幕。", "那知千家墀，慘澹對杯酌。", "不然適與值，用趣則相各。", "人世夫何常，明年定憂樂。"]'),
('76050848-cf95-4398-ab15-b46608f328f7','邂逅孫子儀於臨安喜而賦詩併懷子進子肅','趙蕃','宋','宋诗','song-poetry','','[]','車塵高沒人，欲障無能施。',72,'全唐诗/poet.song.164000.json','["車塵高沒人，欲障無能施。", "忽逢故人面，如濯清漣漪。", "客居縱荒凉，聊復具酒巵。", "勞苦數語外，論事仍索詩。", "長年口欲棘，一笑爲解頤。", "懷哉二難兄，何由會塤箎。"]'),
('f01cadeb-c1e8-4246-a711-8d956fdf0afc','次韻斯遠入城見迎','趙蕃','宋','宋诗','song-poetry','','[]','舟纔汭口過，山已鵝湖出。',108,'全唐诗/poet.song.164000.json','["舟纔汭口過，山已鵝湖出。", "檣隨鴉鵲興，纜與鷗鷺夕。", "青青玩魚藻，爛爛數灘石。", "經行盡吾舊，佳處悉不宅。", "有身漫漂流，有志空鬰積。", "題詩喜將見，重子深垂憶。", "吾儕信老大，觸事異疇昔。", "君能師友偕，我媿灑掃役。", "歲月又何如，駸駸戒輕擲。"]'),
('6ced07a5-d3e3-403a-9d20-b4de222d340b','九月晦日艤舟浴於昭真既罷同方元直成父弟兒姪遊徐巖南禪之新亭已乃絕溪而還','趙蕃','宋','宋诗','song-poetry','','[]','客子下水船，幽士登山屐。',156,'全唐诗/poet.song.164000.json','["客子下水船，幽士登山屐。", "二事莫與謀，聊復盡此日。", "山房富薪水，泥墐仍紙羃。", "沈痾快一洗，清吹生兩腋。", "徐巖舊所訪，舉步能歷歷。", "樹樹雖剪伐，苔蘚更襞積。", "蓋可買以居，惜哉無巨力。", "旁誰斫幽徑，復道精廬立。", "新亭踞其上，遠水山四壁。", "驟來落日挂，忽去昏鴉集。", "不惟我友俱，携子仍弟姪。", "民生固常苦，此適未易得。", "物役不可留，溪流還汰擊。"]'),
('ca73850a-c0df-4e88-9fc0-ebed8ddd9eae','文叔兄以泉州丈之亡自萍鄉奔赴歸途以書約相見會蕃留邑中得以合并時復聞袁州先生之訃哀傷之餘詩以敘別','趙蕃','宋','宋诗','song-poetry','','[]','一雪五日陰，冰凍吹不裂。',144,'全唐诗/poet.song.164000.json','["一雪五日陰，冰凍吹不裂。", "今晨定何朝，萬里來霽色。", "我將還山中，已駕還復輟。", "故人有書至，會面不可失。", "故人江西吏，何爲浙東役。", "慟哭竹林迴，我實門下客。", "去年送朝天，除書報三易。", "心知以病辭，豈料成死隔。", "東懷喪未赴，西望訃復得。", "追惟平生遊，語淚相隕雜。", "僧房幸小駐，聊以舒鬰結。", "酒固不成懽，梅開况當說。"]'),
('219c6738-ec1d-497e-93f3-9494b274d6f5','水淺','趙蕃','宋','宋诗','song-poetry','','[]','歲暮百日晴，江水三寸淺。',48,'全唐诗/poet.song.164000.json','["歲暮百日晴，江水三寸淺。", "褰裳步可涉，石子大如繭。", "沙乾蒲菼死，穴邃魚龍偃。", "會看桃浪來，一碧千里遠。"]'),
('afc42da5-9215-42fd-bc99-793b0dea121d','贛縣道中有懷晦庵用江東日暮雲爲韻作五詩寄之  其一','趙蕃','宋','宋诗','song-poetry','','[]','我行向何許，貢江與章江。',48,'全唐诗/poet.song.164000.json','["我行向何許，貢江與章江。", "悠悠異所見，俗變服亦龐。", "定遷本中州，來南已殊邦。", "况此接荒服，寸心那得降。"]'),
('6b3492b3-2965-4325-89bf-4db852d0e19b','贛縣道中有懷晦庵用江東日暮雲爲韻作五詩寄之  其二','趙蕃','宋','宋诗','song-poetry','','[]','此心如江水，日夜東復東。',48,'全唐诗/poet.song.164000.json','["此心如江水，日夜東復東。", "不惟愛吾廬，顧瞻幾臨風。", "今者款段馬，向來御史驄。", "在我何得失，人自分悴豐。"]'),
('522b4f61-0563-4fd8-9ae8-b831ab9a96d8','贛縣道中有懷晦庵用江東日暮雲爲韻作五詩寄之  其三','趙蕃','宋','宋诗','song-poetry','','[]','自往一寄書，俯仰又許日。',48,'全唐诗/poet.song.164000.json','["自往一寄書，俯仰又許日。", "豈無東歸便，值遇多卒卒。", "昔如馬口銜，欲去隨緩疾。", "今者身屬人，動步窘刀筆。"]'),
('63a35503-0211-4207-9e2c-8a250b27e9e9','贛縣道中有懷晦庵用江東日暮雲爲韻作五詩寄之  其四','趙蕃','宋','宋诗','song-poetry','','[]','去年過辭公，忽忽值春暮。',48,'全唐诗/poet.song.164000.json','["去年過辭公，忽忽值春暮。", "及今復茲時，而公在何處。", "荆溪坡之居，瀨上郊所賦。", "公能躡高蹤，我豈遺野趣。"]'),
('687e93f8-9de7-4d1e-9182-f8df09a7610c','贛縣道中有懷晦庵用江東日暮雲爲韻作五詩寄之  其五','趙蕃','宋','宋诗','song-poetry','','[]','半出未吐日，徐行欲歸雲。',48,'全唐诗/poet.song.164000.json','["半出未吐日，徐行欲歸雲。", "豈惟陰晴殊，政自凉燠分。", "物態故應爾，天機寧亦云。", "安得變淑氣，盡爲除楚氛。"]'),
('cdf96ed6-32ea-4c66-9156-6516c31a8437','晚行','趙蕃','宋','宋诗','song-poetry','','[]','侵晨畢先祀，將午趣疏飯。',48,'全唐诗/poet.song.164000.json','["侵晨畢先祀，將午趣疏飯。", "中途往固宿，顧影日未晚。", "逶迤行不盡，登頓力苦倦。", "馬言雖不通，吾意其自赧。"]'),
('d8cea5ab-476c-4999-8e53-bf2267e94512','施衢州除浙西提刑以詩寄餞三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昔公立螭坳，秉筆罔不書。',108,'全唐诗/poet.song.164000.json','["昔公立螭坳，秉筆罔不書。", "及乎上諫坡，論議無日虛。", "直言有不讎，柴桑念歸歟。", "高卧屬幾日，朱轓起閻閭。", "政成合入奏，返直承明廬。", "如何更持節，未使經綸攄。", "上心豈無謂，勞公重皇居。", "吏惡必剪刈，士良必吹噓。", "此自宰相事，於公定何如。"]'),
('09515cd0-099f-4b2d-8ed2-05f5ec7249a7','施衢州除浙西提刑以詩寄餞三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','六飛駐吳中，地實三輔比。',108,'全唐诗/poet.song.164000.json','["六飛駐吳中，地實三輔比。", "擇守固甚艱，况於部刺史。", "惟公治衢州，他郡蓋無是。", "豈惟教條清，坐見風俗美。", "邦畿四方本，王化所自始。", "俾公按連城，此責亦重矣。", "繡衣非古官，漢乃有直指。", "於今盜賊清，所繫獄事爾。", "讞議苟以平，遺公孫若子。"]'),
('623bd9d4-7a2d-4bea-8b2a-94dc6c423d74','施衢州除浙西提刑以詩寄餞三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','我客懷玉山，有如梓與桑。',108,'全唐诗/poet.song.164000.json','["我客懷玉山，有如梓與桑。", "地故隸江東，與衢蓋鄰疆。", "自公剖符來，亦既閲雨霜。", "非惟衢人安，我民亦小康。", "去年旱無收，閭里驚欲惶。", "匪藉衢粟輸，烏能免流亡。", "嗣聞被災郡，誅賞率亦當。", "况於惠比境，於今見何嘗。", "事雖鬰上聞，我民不公忘。"]'),
('b6fb5f00-3d91-42f2-ad9c-9a991153220e','偶詠不才明主棄多病故人疏之句感孟浩然事作孟浩然詩一首','趙蕃','宋','宋诗','song-poetry','','[]','吾評孟浩然，雅意作詩人。',48,'全唐诗/poet.song.164000.json','["吾評孟浩然，雅意作詩人。", "死經四百載，賦詩名愈新。", "爵祿豈不賞，不義寧賤貧。", "身雖遭放還，未必非得仁。"]'),
('3f5de6e8-9c34-447f-8655-b83705497f12','次韻全真所感','趙蕃','宋','宋诗','song-poetry','','[]','淡交異甘醴，雲雨相覆翻。',48,'全唐诗/poet.song.164000.json','["淡交異甘醴，雲雨相覆翻。", "二者固殊轍，終當戒多言。", "所遇既混殽，所防難每存。", "懷哉古之人，閉門或踰垣。"]'),
('834f2cce-2b50-41e1-a058-1b87520c137c','宿汪山之福田院','趙蕃','宋','宋诗','song-poetry','','[]','前身雲水僧，今世山林士。',48,'全唐诗/poet.song.164000.json','["前身雲水僧，今世山林士。", "遊方未能遍，行脚方自此。", "朝行或官程，夜宿必野寺。", "我自幽有期，人言癡了事。"]'),
('81143327-b2ac-48fe-b8c7-3542b0de1f68','聞潘衡有婢出適安福傳其法造墨甚精孫溫叟捧檄其縣詩從乞之','趙蕃','宋','宋诗','song-poetry','','[]','如聞墨潘氏，一派傳婢子。',156,'全唐诗/poet.song.164000.json','["如聞墨潘氏，一派傳婢子。", "世上多徇名，我曹寧貴耳。", "公其品題之，爲我致窗几。", "定知青出藍，未信橘爲枳。", "升堂與入室，亦喻接花理。", "又如淮王仙，鷄犬悉飛逝。", "况茲薪水供，得法信有是。", "我書初不工，爲詩長費紙。", "筆墨倘精妙，尚可令予起。", "誓將掃竈煤，頓頓燒寒葦。", "度日有不煩，掃煤復何自。", "公聞應大笑，士窮乃如此。", "非但我有求，知名渠自爾。"]'),
('60393638-707f-484a-8342-f594f7b81a39','久不看鏡鬚之白者衆矣得數語寄成父兼示兒姪','趙蕃','宋','宋诗','song-poetry','','[]','始白纔二三，今白乃四五。',96,'全唐诗/poet.song.164000.json','["始白纔二三，今白乃四五。", "蕭蕭十數莖，底用更縷數。", "年來悼亡悲，老至作詩苦。", "外形雖由中，不應遽如許。", "歎息計此身，幾何不埋土。", "而此尚低回，悄悄受羣侮。", "弟能教兒書，兒足事吾圃。", "吾豈不可歸，茲爲寄門戶。"]'),
('fa5b325f-aefc-4051-8950-fcdd17226e48','用前韻寄明叔','趙蕃','宋','宋诗','song-poetry','','[]','鬚白底用悲，我十君二五。',96,'全唐诗/poet.song.164000.json','["鬚白底用悲，我十君二五。", "亦莫問此身，寒暑堪幾數。", "別君春已夏，往往疏勞苦。", "况說買江天，重聽誦詩許。", "君德故有基，層臺繇累土。", "不問鴟鴞詩，猶謂民或侮。", "如我乃宜歸，舍農即爲圃。", "永與世俗辭，君來當勿戶。"]'),
('178b5a63-6e59-45fd-848e-a37358cc492d','曉晴','趙蕃','宋','宋诗','song-poetry','','[]','蓬窗昧陰晴，布衾寒氣穿。',48,'全唐诗/poet.song.164000.json','["蓬窗昧陰晴，布衾寒氣穿。", "起視天正霜，璧月儼似懸。", "空濛十日雨，冰天湛相連。", "氛翳一洗去，舊觀還山川。"]'),
('e868550e-9038-4811-b01f-b786d705d512','冬晴三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','冰雪四十日，朝光開曉霜。',48,'全唐诗/poet.song.164000.json','["冰雪四十日，朝光開曉霜。", "短褐忘藍縷，茅檐失荒凉。", "緬思江南梅，安得置汝傍。", "明朝儻更晴，一葦聊可杭。"]'),
('dfcd682e-6f22-4632-915e-29911b3bce3b','冬晴三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','吾家章泉村，有竹數十百。',48,'全唐诗/poet.song.164000.json','["吾家章泉村，有竹數十百。", "平時愛不伐，雪後多摧折。", "江東絕近書，未省有無雪。", "頗復念此君，誰歟撫霜節。"]'),
('192c385d-daeb-49be-969a-fbf4dbdecad9','冬晴三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','我家讀書堂，堂下才幾席。',48,'全唐诗/poet.song.164000.json','["我家讀書堂，堂下才幾席。", "常年曝背地，兄弟兼子姪。", "長者坐藜床，稚者把書帙。", "此段不可忘，何時復能集。"]'),
('16441a2d-0b2d-44b1-b0ee-834fc80648cd','斯遠生日','趙蕃','宋','宋诗','song-poetry','','[]','下湖有隠人，卜築自厥先。',240,'全唐诗/poet.song.164000.json','["下湖有隠人，卜築自厥先。", "官曾駕高車，屋乃無修椽。", "究觀諸郎貧，固知大夫賢。", "籯雖乏黄金，家故餘青氈。", "其季我與遊，於今幾何年。", "文得南澗賞，經從晦翁傳。", "味有陸子同，譽由吾輩宣。", "其人可知已，忤俗何病焉。", "今逢初度日，爲頌初度篇。", "君非黄叔度，殆似元魯山。", "見之意輒消，坐久歸忘旋。", "是資薰陶益，能使鄙吝捐。", "沖風足披挹，好句寧引牽。", "况復兩玉兒，共嬉郎罷前。", "潜魚必求深，鳴鶴終聞天。", "君當茂明德，食菊仍佩荃。", "我亦願黄髮，挹袂仍拍肩。", "濯足冰水流，振衣懷玉巔。", "世苟混氛濁，神其歆吉蠲。", "我老不足道，君乎斯勉旃。"]'),
('b5d63da7-cdb7-4120-ac8b-80cd3f228ce2','歐陽全真生日','趙蕃','宋','宋诗','song-poetry','','[]','舊聞新喻學，面勢如眉州。',96,'全唐诗/poet.song.164000.json','["舊聞新喻學，面勢如眉州。", "宜有妙人物，舉世讓一頭。", "君於文忠公，譜牒明派流。", "當時山公啟，有言曾未讎。", "在今人與門，推君兩俱優。", "分教固罔外，首善乃所由。", "南見屬初度，杯酒相獻酬。", "願君雲間鵠，聽我江上鷗。"]'),
('01a99013-f86e-45ad-aa3b-b457b8416dff','題鄭季奕火閣','趙蕃','宋','宋诗','song-poetry','','[]','朝來日當窗，晚矣猶未落。',48,'全唐诗/poet.song.164000.json','["朝來日當窗，晚矣猶未落。", "梅開怪璀璨，信是日初薄。", "勿云丈席地，可詠亦可酌。", "歲月與情懷，寧須問今昨。"]'),
('41143b7c-e539-484c-b541-0405dc68a6f1','養源齋','趙蕃','宋','宋诗','song-poetry','','[]','紅源初濫觴，其末千萬里。',96,'全唐诗/poet.song.164000.json','["紅源初濫觴，其末千萬里。", "婆娑數畝陰，歲月拱把爾。", "士之於爲學，豈得獨異彼。", "巋然九層臺，亦自抔土累。", "平生養源齋，曾詩與王記。", "二公死何年，夫子蓋老矣。", "向來之滔滔，今乃見涯涘。", "木殖歲云秋，實落材則美。"]'),
('ff31d89f-e8ff-4bea-bb60-fbcde170ea77','本齋','趙蕃','宋','宋诗','song-poetry','','[]','王子母之弟，徐子父之友。',96,'全唐诗/poet.song.164000.json','["王子母之弟，徐子父之友。", "徐學自贛翁，王則因病叟。", "遊目鄉閭中，孰若二士秀。", "爲汝名本齋，乞言置汝右。", "如病資藥石，如饑待糧糗。", "嗟余亦老矣，門戶百年舊。", "躬耕貧無田，爲圃聖所陋。", "家携一束書，勉汝期日懋。"]'),
('b6b89e2c-4e7f-4c53-b9f4-1b7739505a90','虛白','趙蕃','宋','宋诗','song-poetry','','[]','陳君作齋舍，謚之以虛白。',144,'全唐诗/poet.song.164000.json','["陳君作齋舍，謚之以虛白。", "惟虛白故生，此義無二說。", "人言莊周愚，我愛莊周達。", "東坡老仙翁，出語世津栰。", "亦嘗爲虛白，是乃道所集。", "莊蘇一等人，夫子蓋三益。", "惟虛定何虛，而室又何室。", "是取此蘧廬，而謂無一物。", "鑑明塵垢去，水靜鬢眉出。", "是中可觀妙，無但充遊息。", "何當過夫君，相與以終日。", "賓主兩嗒焉，不言而目擊。"]'),
('6d2f97f7-0f8c-489c-a975-cfa37ba7144d','二十六日與公擇步松嶺而返','趙蕃','宋','宋诗','song-poetry','','[]','青山招我來，松風送我去。',48,'全唐诗/poet.song.164000.json','["青山招我來，松風送我去。", "白髮頻脫幘，足適欲忘屨。", "春初更和悅，我亦除疾痼。", "莫作倥傯歸，茲遊已成屢。"]'),
('db549f4a-0b2c-496f-a80a-284dccf3ae5b','橋上聞薝葡香','趙蕃','宋','宋诗','song-poetry','','[]','曾聞薝葡林，自是佛世界。',48,'全唐诗/poet.song.164000.json','["曾聞薝葡林，自是佛世界。", "何許郁若風，飄颻能自在。", "不然山之靈，作意現奇怪。", "於此證香嚴，通途蓋亡礙。"]'),
('760bcde7-c704-4001-a3e2-2ada2b88d1eb','十有二月二日晚同向景先閲江船忽雨作從教授假蓋繼以詩來次韻','趙蕃','宋','宋诗','song-poetry','','[]','誰令類癡兒，乃是妨曰假。',48,'全唐诗/poet.song.164000.json','["誰令類癡兒，乃是妨曰假。", "君方遡歸鴻，我政專野馬。", "成詩忽能送，有酒胡不瀉。", "此段亦可傳，誰與妙揮灑。"]'),
('58e48da0-55f0-4719-a1ac-3345b24123ad','挽胡澹菴二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昔樂全公，暮爲老蘇表。',48,'全唐诗/poet.song.164000.json','["憶昔樂全公，暮爲老蘇表。", "載其辨姦論，此老一生了。", "澹庵夫何如，書有斬檜草。", "顧豈無他歟，言大可略小。"]'),
('bcc7ccd4-c4dc-43d0-b90a-bf5010ca6e36','挽胡澹菴二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','昔我曾大夫，嘗作舂陵適。',48,'全唐诗/poet.song.164000.json','["昔我曾大夫，嘗作舂陵適。", "時惟蕭子荆，袖書實見客。", "公經本蕭自，於義豈秦越。", "三年期掃門，竟欠今生識。"]'),
('0c068912-0a08-40ee-8931-1bdadeafdbe9','簡彥博審知','趙蕃','宋','宋诗','song-poetry','','[]','朝昏困薪水，寒暑念裘葛。',96,'全唐诗/poet.song.164000.json','["朝昏困薪水，寒暑念裘葛。", "度日少復佳，此歲又已卒。", "崎嶇向行旅，蹭蹬遭羈縶。", "故人肯留連，客况免羞澀。", "陰天苦錯莫，梅事去飄忽。", "要尋幽遐地，共作須臾集。", "徐陵峻詩壇，王衍深理窟。", "我獨媿其家，徒窮頼如壹。"]'),
('ffd2b87b-d8c6-4c89-9969-28401d047344','用招明叔之韻簡胡兄仲威并屬明叔','趙蕃','宋','宋诗','song-poetry','','[]','一白不盡茶，妙試在茗粥。',168,'全唐诗/poet.song.164000.json','["一白不盡茶，妙試在茗粥。", "相馬不舉肥，幹也更畫肉。", "士當何如觀，一語可以卜。", "我生嗜朋友，有餘補不足。", "要求棟梁具，必問澗與谷。", "瑟兮本希聲，何能娛世俗。", "陳君於爲文，筆力見往復。", "劇稱南郡胡，曰此吾類族。", "輿籃昨過之，懷刺今來辱。", "談間不須臾，未暇問以目。", "陳君有江閣，曠瞻不遺粟。", "非如昧者徒，白晝迷麥菽。", "何當約夫君，載酒擷杞菊。", "我記不足云，渠詩當細讀。"]'),
('fb0d34fc-c2e9-4602-84c9-9c4e52cda2c0','泊舟叫巖入法林院訪洪駒父留題','趙蕃','宋','宋诗','song-poetry','','[]','溪邊遵微徑，林下陟荒級。',48,'全唐诗/poet.song.164000.json','["溪邊遵微徑，林下陟荒級。", "逢僧衣藍縷，對面日曛黑。", "堂空若無人，巖淺僅容席。", "流傳昔聞詩，求訪今罔獲。"]'),
('946c11d6-282f-4c33-a31e-e12f72ab791c','次韻斯遠三十日見寄','趙蕃','宋','宋诗','song-poetry','','[]','窗明內晴景，書味真雋永。',96,'全唐诗/poet.song.164000.json','["窗明內晴景，書味真雋永。", "長年悔遠遊，紛蠹几莫整。", "子猷調固疏，竹可一日無。", "看渠姿爾瘦，瘦而何用腴。", "因茲想風度，朝夕如相晤。", "豈不欲就之，身羈未能去。", "詩來政此時，好處無涯圻。", "吟哦不自已，亭午墅雞啼。"]'),
('666653ba-128e-4a6a-aa1c-f2a7123f15dc','次韻在伯送行','趙蕃','宋','宋诗','song-poetry','','[]','白石何鑿鑿，白鳥何鶴鶴。',276,'全唐诗/poet.song.164000.json','["白石何鑿鑿，白鳥何鶴鶴。", "吾行甚悠悠，物境自廓廓。", "緬思友生良，頓使懷抱惡。", "別辭固丁寧，醒矣轉寂寞。", "近猶已欄檻，遠乃失城廓。", "重惟始相遇，夫豈世所樂。", "逮今信素交，是果天所酢。", "相期振古風，相與務天爵。", "興時山水憑，意或風月託。", "君亭足鷗鷺，我砌下鳥鵲。", "詩盟寄閒嬉，筆勢異强弱。", "君詩似陳黄，君字如張索。", "悠然正前瞻，渺矣已後落。", "譬猶層臺登，亦類中流泊。", "憐我狂而疏，誨我詳不略。", "是行亦流轉，敢謂逃束縛。", "移官儻可歸，故免聽鄰柝。", "閑員苟得去，自此投遠壑。", "要期終身遊，豈但今日約。", "吾曹念元賓，學子慕有若。", "至味匪鹽梅，至樂非管籥。", "四三分喜怒，非是論今昨。", "擾擾與膠膠，休休仍莫莫。"]'),
('0c96713c-7e4f-4e3f-9348-20a7169b2b5d','奉思斯遠兄成詩以寄','趙蕃','宋','宋诗','song-poetry','','[]','叢叢庭前萱，葉葉簷外蕉。',144,'全唐诗/poet.song.164000.json','["叢叢庭前萱，葉葉簷外蕉。", "何曾百憂釋，但覺中心焦。", "故人在何許，山川極吳楚。", "大江湧奔騰，重湖互吞吐。", "別來書不至，更望詩能寄。", "相從志若何，相去有如此。", "普天仰何大，一己俯何隘。", "胡爲自羅網，無事忽投械。", "憑高政悠悠，思遠忽不收。", "歸來重有感，立壁成幽幽。", "萱叢暗已歛，蕉葉抽未展。", "百憂攻余心，舐筆空喁噞。"]'),
('a43b9ea9-1071-41f3-8116-f610095857a4','以予與斯遠倡酬詩一卷寄錢伯同運使郎中二首  其一','趙蕃','宋','宋诗','song-poetry','','["\u534e\u5c71"]','公作廣信牧，我爲辰陽掾。',72,'全唐诗/poet.song.164000.json','["公作廣信牧，我爲辰陽掾。", "長沙趣歸程，臨汝甫再見。", "我今華嶽祠，公乘江東傳。", "雖能遞尺書，未易重會面。", "錢晁固世親，貴賤寧異眷。", "復此候寒溫，因之致詩卷。"]'),
('b6baf764-3482-4bc2-8882-7e4eb56c8f18','以予與斯遠倡酬詩一卷寄錢伯同運使郎中二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我家懷玉居，蓋自南渡初。',72,'全唐诗/poet.song.164000.json','["我家懷玉居，蓋自南渡初。", "元無五畝宅，僅保一束書。", "不調如釋之，何翅十年餘。", "但有四壁在，倦遊亦相如。", "况此方病卧，何繇瞻使車。", "所徯公嚬笑，以爲民慘舒。"]'),
('1db84af6-4abd-4dd9-993a-3f4436aaac82','次韻王照鄰去秋送行併呈滕彥真','趙蕃','宋','宋诗','song-poetry','','[]','風人伐木歌，詠寫求友聲。',240,'全唐诗/poet.song.164000.json','["風人伐木歌，詠寫求友聲。", "亦有脊令賦，月邁而日征。", "平時朝夕居，一旦離合情。", "何以著此情，賦詩兼軸盈。", "怪來擔肩重，忘去破橐輕。", "時時一披展，絕勝五色盲。", "今日復何日，霜檐曉爭明。", "青天盡開露，如見心目誠。", "鄙夫獨何爲，似覺幽憂攖。", "緬懷平生遊，多留定王城。", "晨出湘霧濕，夕歸湘浪平。", "王滕唱酬詩，我亦濫一名。", "別之今幾何，秋枯復春榮。", "素書渺不來，嘆我無魚烹。", "要賡舊貽詩，餖飣仍經營。", "定知他年見，不復刮目驚。", "檐前坐久如，四體醺欲酲。", "夢作扁舟去，湘西尋舊盟。", "曾微白首哀，但作青眼橫。", "山鳥何自鳴，欠伸巾尚傾。"]'),
('40c84541-74e6-4c3a-b348-b0422276c9a6','次韻酬吳德夫去秋送行之作','趙蕃','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u5199\u4eba", "\u9001\u522b", "\u54c1\u683c"]','湘西一盃酒，渺渺紅葉換。',240,'全唐诗/poet.song.164000.json','["湘西一盃酒，渺渺紅葉換。", "江東千里雲，落落黄犬歎。", "人生七十稀，百里九十半。", "初期枉車馬，近迺遺札翰。", "小遲君不肯，一出我豈憚。", "雖微辦雞黍，豈乏具薪炭。", "古風久不作，我友當力讚。", "舊詩况瓊玖，觸目屢璀璨。", "中馨稱蘭佩，外飾匪玉冠。", "初年已飛騰，中道翻歎惋。", "恐遺知己羞，遂許獨力斷。", "於茲樹風聲，何止評月旦。", "君如渥洼種，可以羈縶絆。", "我異淇園姿，猶睎歲時貫。", "君乎甚英爽，我也終浪漫。", "自應殊顯晦，寧復待剖判。", "湖山冰玉明，樓閣丹青煥。", "叩舷或乘舟，曳杖或登岸。", "君行定有得，我去何可愞。", "與想悠然時，却憶蒼然觀。"]'),
('a9a0ac3f-e032-4106-ba76-d1f648892109','次韻和答周伯壽送行','趙蕃','宋','宋诗','song-poetry','','[]','秋月日以明，秋風日以清。',180,'全唐诗/poet.song.164000.json','["秋月日以明，秋風日以清。", "秋今且云暮，而我遄東征。", "雖云別寓邦，且復遵故程。", "久結山水念，况關朋友情。", "惟昔未識初，聞風已先傾。", "一見辱與交，再焉許同盟。", "吾徒務切磋，俗士資飛鳴。", "我事太鹵莽，君爲久專精。", "我行政依劉，君言將入衡。", "要期一見重，可使萬戶輕。", "春風一轉首，南山各歸耕。", "君亦竟閉戶，坐閲水火爭。", "臨分枉題贈，至味如太羹。", "此意可虛辱，不然詎爲榮。", "去去復去去，行行重行行。"]'),
('2953ff3a-ad58-4654-acad-9ccbf1d529e3','次韻沈司法送行','趙蕃','宋','宋诗','song-poetry','','[]','坐上著孟嘉，不問知小異。',156,'全唐诗/poet.song.164000.json','["坐上著孟嘉，不問知小異。", "豈其眉睫殊，儻或偶相值。", "余生慕名流，得見忘履屣。", "雅聞東嘉州，儒服類洙泗。", "於今師友間，授受由原委。", "沈君蓋其徒，往往無不肄。", "嚮雖未云識，早已知名字。", "胡爲冠惠文，更復倉庫吏。", "人之不相知，擊磬與荷蕢。", "至其移怒時，水蟹或遭忌。", "人誰不君知，相與共愕眙。", "君方繫官曹，我乃赴幽事。", "別語縱可佳，離愁渺無地。"]'),
('db604748-b458-454d-8f57-a9e3cabd6a43','次韻潘端叔送行二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','君公隠牛儈，文休食馬磨。',144,'全唐诗/poet.song.164000.json','["君公隠牛儈，文休食馬磨。", "身則困空乏，道爲如切磋。", "昧者不知此，輕受鄭灼唾。", "遑乎欲奚爲，况覓陽春和。", "余惟素賤貧，學晚仍廢惰。", "念將求歲餘，要必取日課。", "向來四方遊，不辦一室坐。", "已深蕪穢遭，更值雪霜挫。", "茲行自棲遲，詎得嗟轗軻。", "固殊南山歸，敢曰東山卧。", "胡爲論知仁，乃復稱同過。", "我無歸去辭，君有歸來些。"]'),
('22a72df3-bf71-412e-834c-434262305963','次韻潘端叔送行二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君言不爲詩，乃有如許味。',144,'全唐诗/poet.song.164000.json','["君言不爲詩，乃有如許味。", "詩亦何與人，政恐傷吾氣。", "中懷松柏堅，外暴丹雘塈。", "君雖不我語，我亦長自畏。", "不惟費口頰，政爾悲腸胃。", "良由習未除，匪是真爲貴。", "君言固鄒魯，君筆猶漢魏。", "絕倒豈自文，善謔非加誹。", "贈言要有益，佩服當無既。", "勝私與致果，曰克仍曰毅。", "曾聞鄭渠鑿，終有秦畝溉。", "閔閔望其成，悠悠勿虛費。"]'),
('1052e6ce-467c-4732-8e01-49b80426bac6','次韻劉先生送行并令諸友及子侄同賦','趙蕃','宋','宋诗','song-poetry','','[]','斗食綴散吏，幽棲還故山。',48,'全唐诗/poet.song.164000.json','["斗食綴散吏，幽棲還故山。", "平生讀書志，欠此歷年閑。", "馬倦政長路，鷺饑方淺彎。", "吾師與吾友，高處若爲攀。"]'),
('58a41d83-f996-4c28-badc-a7955ad16238','呈趙常德四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','東南米最賤，舊說湖南北。',48,'全唐诗/poet.song.164000.json','["東南米最賤，舊說湖南北。", "及今身見之，價豈下江國。", "此行爲米來，對此增歎息。", "人謂使君賢，寧慮有失職。"]'),
('fc5adda9-98d6-44b7-a7e3-da2f9f38a51f','呈趙常德四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','朝廷不忘遠，徒欲得公重。',48,'全唐诗/poet.song.164000.json','["朝廷不忘遠，徒欲得公重。", "不然如公賢，久合居侍從。", "少須歲和豐，歸騎承天寵。", "看取武陵原，田耕麥米壟。"]'),
('235de326-fbd4-42f9-b5f6-5785dd37b011','呈趙常德四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','豐年易爲政，凶年易爲德。',48,'全唐诗/poet.song.164000.json','["豐年易爲政，凶年易爲德。", "政本拙催科，德乃足民食。", "蠻貊忠信行，田里愁歎息。", "德政祇如斯，何用求赫赫。"]'),
('2b466623-9ff0-4bf3-adf6-d8e89550d3c4','呈趙常德四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','將身付銓選，乃奉蠻府檄。',48,'全唐诗/poet.song.164000.json','["將身付銓選，乃奉蠻府檄。", "蠻語初未學，嶮絕聞人說。", "進前退不可，信有難如棘。", "所頼使君賢，餘波能普及。"]'),
('0b0220ad-bf65-489a-ae2a-88e337f77ab2','呈游子明二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','安仁山水縣，令君文章伯。',48,'全唐诗/poet.song.164000.json','["安仁山水縣，令君文章伯。", "林深蘭自吐，川媚珠所宅。", "絃歌導斯民，傳舍閲過客。", "口雖絕雌黄，眼顧分青白。"]'),
('d7f7ae6f-a922-4e4f-b75a-68f4e8dcea89','呈游子明二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','頻乘信州船，屢泊雲錦驛。',48,'全唐诗/poet.song.164000.json','["頻乘信州船，屢泊雲錦驛。", "登臨有勝絕，偃蹇費收拾。", "令君名能詩，公事多暇日。", "儻可付篇章，大勝資粟帛。"]'),
('851e374e-bfaa-4105-8455-4d4f9b801048','呈段元衡','趙蕃','宋','宋诗','song-poetry','','[]','君從桂林來，我欲衡陽去。',72,'全唐诗/poet.song.164000.json','["君從桂林來，我欲衡陽去。", "邂逅一尊同，飄流數年敘。", "我未長沙去，君復衡陽來。", "還思數年隔，更遣五言裁。", "我歸玉溪傍，君向靈山側。", "來往方自茲，飄流勿多惜。"]'),
('f1d46679-0ea7-4aae-a32a-99bdac5c07a1','呈賈新之兼簡謝子暢','趙蕃','宋','宋诗','song-poetry','','[]','擁衾困朝酲，著帽從宿諾。',84,'全唐诗/poet.song.164000.json','["擁衾困朝酲，著帽從宿諾。", "我家附東溪，君住窮北郭。", "俱悲壹無錢，獨媿喜好學。", "詩聲漫天壤，頭白尚丘壑。", "去鄉今幾年，末路得其託。", "相望固非遠，相見每不數。", "所思聞清談，何意發狂藥。"]'),
('8aa9997e-46e6-479e-80bc-cc57fbdd250e','呈程可久','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','微風送落日，餘霞雜停雲。',276,'全唐诗/poet.song.164000.json','["微風送落日，餘霞雜停雲。", "陟彼山之巔，誰識我與君。", "彭蠡咫尺見，匡廬毫髮分。", "波瀾似吳淞，岡巘殊勝雲。", "是間豈無詩，愧我初不文。", "圖畫亦足寫，摩詰居離羣。", "裴回竟何得，指點徒加勤。", "回憩僧所廬，幽闃令人欣。", "談鋒壯鏖戰，茗椀頻策勳。", "交游數伯厚，文字從右軍。", "我是漫瞠若，莫能窺厥垠。", "少焉復來過，凜然落衣帉。", "江山恍疑非，林空月紛紜。", "旁有博士湖，姓名未前聞。", "何年隠君子，高棲辭世氛。", "得非羊裘漁，當是植杖耘。", "至今宴息地，離離幽草薰。", "人生七十稀，過眼俱蝱蟁。", "適意何必多，悠悠幾朝曛。", "君明履霜畦，我正坐水濆。", "會合且不常，使我生憂慬。", "何當十日款，誦說心爲醺。", "庶如逢豫章，其藁一以焚。"]'),
('57d7412e-2374-403a-aa2c-61abc3741522','呈壽岡先生','趙蕃','宋','宋诗','song-poetry','','[]','我行上蕭灘，慘澹無與適。',168,'全唐诗/poet.song.164000.json','["我行上蕭灘，慘澹無與適。", "肩輿問何詣，揚雄一區宅。", "地雖占城隅，野澹遶修碧。", "主人誰何輩，蓋代文章伯。", "喜我過其廬，倒屣相應接。", "似聞杜陵翁，一飯無俗客。", "如何重留我，更道雞黍窄。", "談間雖文字，往往先名節。", "我語固多狂，公亦不我折。", "爲言古今人，耽詩信癡絕。", "身名兩棄置，死若墮霜葉。", "公言蓋有激，我亦因啟發。", "莫將夢中事，重對癡人說。", "此語竟云何，梵志翻著襪。"]'),
('bf3a1294-ac0c-4afc-ac64-6006fbe98355','次韻元衡送別','趙蕃','宋','宋诗','song-poetry','','[]','老馬千里志，老鶴萬里心。',156,'全唐诗/poet.song.164000.json','["老馬千里志，老鶴萬里心。", "武夫用清廟，珍材卧中林。", "進寸輒退尺，枉尺寧直尋。", "桃李本無言，山水乃有音。", "靡不競盛麗，疇能聽幽深。", "平生文字遊，幾作南北襟。", "清宵寄明月，遠望傷遥岑。", "悠悠歸計晚，卒卒年事侵。", "狗監薦相如，將軍知杜欽。", "彼哉竟何處，已矣真難任。", "乖離歎每昔，邂逅期豈今。", "贈別枉古調，和之徒苦吟。", "我何一錢直，君自抵千金。"]'),
('a9a450cc-252c-4e29-b647-f69d9bde2a6f','留別成父弟以貧賤親戚離爲韻五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','秋日苦易暗，秋宵苦難晨。',48,'全唐诗/poet.song.164000.json','["秋日苦易暗，秋宵苦難晨。", "蟲號雞不已，我亦長吟呻。", "哀哉念何深，出處累一貧。", "在家庸可忍，行旅計愁人。"]'),
('ec65b373-5bdc-47a8-874c-70c5934973c0','留別成父弟以貧賤親戚離爲韻五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','今年歲大熟，穀價率以賤。',48,'全唐诗/poet.song.164000.json','["今年歲大熟，穀價率以賤。", "富家積囷倉，貧自無飽飯。", "悲哉五斗圖，去矣千里遠。", "四民士爲先，今乃媿工販。"]'),
('3dbd61ad-7b33-4ee7-975b-546b1924e088','留別成父弟以貧賤親戚離爲韻五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','木落山有骨，水落河有津。',48,'全唐诗/poet.song.164000.json','["木落山有骨，水落河有津。", "扁舟所常經，大半迹已陳。", "身非鴻鵠舉，心乃鷗鷺親。", "勝處自屬我，塵事勿敗人。"]'),
('173e9437-1497-4124-a74d-109d3ee9ece8','留別成父弟以貧賤親戚離爲韻五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','我家如陶舍，幼稚有盈室。',48,'全唐诗/poet.song.164000.json','["我家如陶舍，幼稚有盈室。", "汝家亦十口，持去何可得。", "嗟我寡兄弟，至此得無戚。", "雖爾敢或忘，呴濡期沫濕。"]'),
('ce497742-8502-4e10-943d-658eb85ee101','留別成父弟以貧賤親戚離爲韻五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','人事苦好乖，咫尺當語離。',48,'全唐诗/poet.song.164000.json','["人事苦好乖，咫尺當語離。", "及乎中年後，畏與親友辭。", "陶謝得道者，其言且如斯。", "况我乃畸人，嗚呼得無悲。"]'),
('4f8c9664-6468-4b9b-a758-a76375bbfff9','咏古','趙蕃','宋','宋诗','song-poetry','','[]','淵明欲弦歌，爲酒利公田。',60,'全唐诗/poet.song.164000.json','["淵明欲弦歌，爲酒利公田。", "到縣十餘日，歸意已拳然。", "一稔且莫待，遥遥問歸船。", "是事可質信，考之歸來篇。", "種秔與種秫，夢語落何邊。"]'),
('deeda122-4940-4f5a-824c-923892217f04','和陶淵明乞食詩一首','趙蕃','宋','宋诗','song-poetry','','[]','我生墮貧中，欲避將安之。',84,'全唐诗/poet.song.164000.json','["我生墮貧中，欲避將安之。", "去年未是貧，假貸猶有辭。", "親朋戒今年，相與謝往來。", "朝昏曷以度，半菽藜羹杯。", "大笑不知悔，且和淵明詩。", "兒曹相與語，我幸乏此才。", "聊爲一飽謀，餓死無自貽。"]'),
('dc0a1be1-8572-4bce-9e44-d2835578abaa','和陶淵明己酉歲九日詩一首','趙蕃','宋','宋诗','song-poetry','','[]','山中無曆日，不知冬已交。',96,'全唐诗/poet.song.164000.json','["山中無曆日，不知冬已交。", "起行視林園，草木如半凋。", "黄花獨何爲，亭亭有餘高。", "俯不媿轉蓬，仰何羨凌霄。", "當其雜衆芳，開落真謾勞。", "豈若稍退步，坐閲枯與焦。", "建中方死蘇，元嘉迺終陶。", "二老蓋巋然，所歷匪一朝。"]'),
('3ce1dea3-ae33-40f7-8ce3-3ca1fe876de5','重九纔四日爾風雨如此病卧殊亡聊小兒輩取酒飲予且索作詩强和淵明九日閒居一首','趙蕃','宋','宋诗','song-poetry','','[]','久不觀陶詩，彷彿如前生。',108,'全唐诗/poet.song.164000.json','["久不觀陶詩，彷彿如前生。", "忽此迫重九，意是渠所名。", "我方卧病中，齋居忘昏明。", "不知簷雨落，但覺奔濤聲。", "兩兒絕可憐，弱者纔五齡。", "深憫乃翁憊，取酒前爲傾。", "歲月已如許，我衰難復榮。", "但願此可安，閭里無異情。", "何必議徙居，終焉計將成。"]'),
('431e5628-fcfa-4cbd-9fae-24151a3a7797','九日用靖節己酉歲韻','趙蕃','宋','宋诗','song-poetry','','[]','宿雨曉未止，紛紛雲氣交。',96,'全唐诗/poet.song.164000.json','["宿雨曉未止，紛紛雲氣交。", "秋令迫凄厲，草木無多凋。", "去年當茲晨，採菊踰山高。", "晚上寶公塔，徘徊意干霄。", "今年此幽居，粗免出入勞。", "茅簷縱偪仄，亦類蝸廬焦。", "舊醅更可漉，幽憤斯能陶。", "莫問無窮事，人生如露朝。"]'),
('9d81adf3-058e-4899-bab7-b7404659ce3b','人愛九日多以靖節之故僕以邠老七字爲可以益其愛者且連日不雨即風尤覺此句妙處賦詩八韻','趙蕃','宋','宋诗','song-poetry','','[]','東籬滿把菊，柯山一句詩。',96,'全唐诗/poet.song.164000.json','["東籬滿把菊，柯山一句詩。", "四時皆有節，九日獨如斯。", "潘子夙所尚，陶翁何敢師。", "是故逢此日，愛慕仍凄悲。", "所願學淵明，歸去了不疑。", "松菊儻猶存，田園隨事爲。", "亦願如邠老，白首邱壑期。", "人窮與詩長，得失其在茲。"]'),
('be6a2b7b-20f0-45d2-983a-33842970c772','拜嚴方范祠','趙蕃','宋','宋诗','song-poetry','','[]','東都重風節，先生實啟之。',108,'全唐诗/poet.song.164000.json','["東都重風節，先生實啟之。", "有士蓋如此，不拯家國危。", "迺知大厦傾，未易一木支。", "我讀黨錮傳，涕流每交頤。", "往來桐江船，必拜嚴子祠。", "俯誦宛陵句，仰觀文正碑。", "禹稷與顔回，千載同其師。", "數公固天人，可望不可追。", "但願如玄英，隠居名能詩。"]'),
('510724dc-bfdf-4f50-9a7b-eb1ddda9dfce','讀阮嗣宗傳見其醉六十日免求昏之言與醒忘作勸進辭據案便書何乃異同耶作阮嗣宗詩','趙蕃','宋','宋诗','song-poetry','','[]','善觀阮嗣宗，醒醉俱托狂。',60,'全唐诗/poet.song.164000.json','["善觀阮嗣宗，醒醉俱托狂。", "廣武歎已絕，蘇門嘯何長。", "昏既以醉免，辭寧不終忘。", "又疑殺青上，闕文今或亡。", "不然竹林遊，何獨棄山王。"]'),
('b2ad56ae-119b-4823-bb1d-bac2513cdec1','論詩寄碩父五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','詩人例多窮，我窮亦何因。',48,'全唐诗/poet.song.164000.json','["詩人例多窮，我窮亦何因。", "頻年走道路，一饑累其身。", "簞瓢豈非福，天理元自均。", "俯仰苟不媿，此心猶昔人。"]'),
('d06eff32-3341-4e9a-b62a-4c7de6412fc6','論詩寄碩父五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我詩元不佳，病後日益退。',48,'全唐诗/poet.song.164000.json','["我詩元不佳，病後日益退。", "年來窮到骨，未可專詩罪。", "故人周與施，愛我不我費。", "歲晚短書稀，相望千里外。"]'),
('388b2409-d100-4bb7-a179-9de186d2693f','論詩寄碩父五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','學詩如學道，先須養其氣。',48,'全唐诗/poet.song.164000.json','["學詩如學道，先須養其氣。", "植苗無它術，務在除荒穢。", "滔滔江漢流，源從濫觴至。", "要作千里行，無爲半途滯。"]'),
('38c19c8f-40ce-4818-b5fb-9510a0919167','論詩寄碩父五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','東萊老先生，曾作江西派。',48,'全唐诗/poet.song.164000.json','["東萊老先生，曾作江西派。", "平生論活法，到底無窒礙。", "微言雖可想，恨不床下拜。", "欲收一日功，要出文字外。"]'),
('d1ac8a7e-ede1-4c39-948a-ecd0f1ff75d4','論詩寄碩父五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','溧陽罕賢才，兩沈好兄弟。',48,'全唐诗/poet.song.164000.json','["溧陽罕賢才，兩沈好兄弟。", "讀書不求功，其涯未可既。", "古人豈難到，顧我力行爾。", "茲道果何如，在此不在彼。"]'),
('689d883a-7d3b-4382-b213-88f1213fffb6','雜詠  其一','趙蕃','宋','宋诗','song-poetry','','[]','蘭生雜蓬藋，匪願爲世採。',48,'全唐诗/poet.song.164000.json','["蘭生雜蓬藋，匪願爲世採。", "一朝落城市，未免論金賣。", "金輕孰見多，棄不待其艾。", "抔土儻與期，含熏歲猶再。"]'),
('83865280-7899-4e65-8687-2195d95b5cbd','雜詠  其二','趙蕃','宋','宋诗','song-poetry','','[]','鳥雀雖微物，頗知庇其身。',48,'全唐诗/poet.song.164000.json','["鳥雀雖微物，頗知庇其身。", "育雛並庭宇，用意蓋即人。", "即人亦何爲，吞噬防暮晨。", "巢空儻不救，豈曰近乎仁。"]'),
('1a6234b9-0204-451e-8862-8e7f08e25c19','雜詠  其三','趙蕃','宋','宋诗','song-poetry','','[]','婦有居冢亞，冢富亞則貧。',120,'全唐诗/poet.song.164000.json','["婦有居冢亞，冢富亞則貧。", "貧知敬尊章，富不親補紉。", "尊章愛貧婦，富婦讒生鬭。", "讒巧僞若真，兩婦俱遭詬。", "貧婦自修飭，富乃計之得。", "日復鬭其間，衆謂貧當出。", "尊章頼深慈，不納富婦詞。", "貧婦亦勿疑，但瘽前所爲。", "纔言有時辨，富婦何施面。", "貧婦貧無歸，尊章願終眷。"]'),
('66c96938-1cda-436b-adf3-90d7c1648e0c','令逸作歲寒知松柏題詩因作','趙蕃','宋','宋诗','song-poetry','','[]','不有歲寒時，若爲松柏知。',72,'全唐诗/poet.song.164000.json','["不有歲寒時，若爲松柏知。", "南方故多暖，此物寧能奇。", "漫道同生植，何云盛衰齊。", "不臣真浪說，難用空增悲。", "匠石今孰是，明堂那覺遲。", "玄都種桃者，一笑已前期。"]'),
('e8b57582-562d-4a10-814f-d163eb7113ce','嚴山  其一','趙蕃','宋','宋诗','song-poetry','','[]','嚴山多嵯峨，婺水爭平遠。',48,'全唐诗/poet.song.164000.json','["嚴山多嵯峨，婺水爭平遠。", "山如古屏張，水似橫軸展。", "世絕郭熙畫，我無摩詰詩。", "熟視眼中景，偃蹇不得追。"]'),
('991f66cb-d1b8-4199-af0d-8f7bef1f9f11','嚴山  其二','趙蕃','宋','宋诗','song-poetry','','[]','春風吹桃花，適與流水會。',48,'全唐诗/poet.song.164000.json','["春風吹桃花，適與流水會。", "流水固無心，桃花亦何意。", "如何武陵人，便至神仙家。", "神仙不可見，回首空煙霞。"]'),
('7f8d8656-2ba1-429f-8120-99a58ef22773','范湘監務許惠其父盤溪居士詩先往數語焉','趙蕃','宋','宋诗','song-poetry','','[]','國朝幾名家，在蜀蘇與范。',144,'全唐诗/poet.song.164000.json','["國朝幾名家，在蜀蘇與范。", "斯文何與人，竟作南荒竄。", "盤溪諸子行，少小便精悍。", "早從宜州遊，句法悟骨換。", "官稱薄如紙，名蓋越千萬。", "我爲餘杭役，識子非楚産。", "姓名問即識，一笑冰已泮。", "長哦迺翁詩，亹亹無間斷。", "使我傾耳聽，妙處驚輒歎。", "前輩今遠矣，俗眼易作玩。", "大軸許見遺，此賜安敢慢。", "行囊政爾空，得此吾無患。"]'),
('7b6806aa-c166-495f-a0c4-52c9212b94cb','二十七日作','趙蕃','宋','宋诗','song-poetry','','[]','卜居面勢隘，附山枕林麓。',96,'全唐诗/poet.song.164000.json','["卜居面勢隘，附山枕林麓。", "曠瞻既無地，何以慰羈束。", "昏昏半月雨，候應黄梅熟。", "晨興更凉冷，轉午增蒸溽。", "山蟬苦見聒，聲亂非絲竹。", "病夫不耐事，頗復傷煩促。", "緬懷江湖舊，歷歷夢能續。", "誰與具扁舟，我被立可襆。"]'),
('b6f31c28-aa52-405e-8478-b374a1c6081e','桃花臺下望龜峰作','趙蕃','宋','宋诗','song-poetry','','[]','吾州四名禪，獨未歷龜玉。',120,'全唐诗/poet.song.164000.json','["吾州四名禪，獨未歷龜玉。", "足後懶不鞭，幾同毀於櫝。", "繫舟桃花下，龜峰正相峙。", "决意欲造前，已行卒成止。", "嘗觀是山圖，未究所得名。", "道人相指似，咸曰因賦形。", "方今聖人治，圖書當瑞出。", "胡不負之去，而此久屹立。", "老我無藉在，放意師莊蒙。", "不願智以用，懷哉曳塗中。"]'),
('7079f4ae-6098-40c3-9e7a-50a72ef9161f','期斯遠不至登谿亭有懷併屬雲臺劉先生三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','落日照谿谷，寒光摇樹林。',60,'全唐诗/poet.song.164000.json','["落日照谿谷，寒光摇樹林。", "宿鳥投密枝，歸雲釋遥岑。", "餘輝尚燠背，纖月忽在襟。", "可人期不來，何以寫我心。", "近者且若此，悠悠望西南。"]'),
('b23f50eb-668b-45e8-b590-7ee38cfb1f7f','期斯遠不至登谿亭有懷併屬雲臺劉先生三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','西南定何方，路遠惟迢迢。',60,'全唐诗/poet.song.164000.json','["西南定何方，路遠惟迢迢。", "白鷺带演迆，青居鬰岧嶢。", "下有隠君子，內盛外不驕。", "芳春覺蘭馨，窮冬知木喬。", "無爲事獨往，車乘方翹翹。"]'),
('ec34ad02-fa40-4bd4-a17d-ec10f2d71e64','期斯遠不至登谿亭有懷併屬雲臺劉先生三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','戚戚重戚戚，有抱不自釋。',60,'全唐诗/poet.song.164000.json','["戚戚重戚戚，有抱不自釋。", "問余何所憂，學道不早力。", "悠悠復悠悠，頭禿頷須白。", "先對有遺言，朝聞死可夕。", "矢詩道其懷，庶獲師友益。"]'),
('10fb4649-fae8-430a-bdce-88a2d2cc7500','二月二日阻風呈同行','趙蕃','宋','宋诗','song-poetry','','[]','平居說江湖，似若苦饑渴。',132,'全唐诗/poet.song.164000.json','["平居說江湖，似若苦饑渴。", "及今落吾手，謂可娛朝夕。", "胡爲連日行，迺復形歎息。", "使風不終朝，阻風有併日。", "欲行波濤恐，欲住餓餒迫。", "吾舟僅如芥，吾命真若髮。", "吾罪不足云，吾家復何說。", "不唯風浩蕩，更直雨騷屑。", "鷄啼三家幽，鳥度萬里闊。", "遥聞君山青，舊詠高樓月。", "何當俱醉倒，夢去山南北。"]'),
('7413f4fd-333e-4640-9908-14455c6ac7fd','與彥博審知同爲問梅之行到溪南僕與審知俱以畏風罷興止小酌于僧房以有寒疾不可以風分韻作詩得有寒可字三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','驚飆振林梢，落日掛馬首。',48,'全唐诗/poet.song.164000.json','["驚飆振林梢，落日掛馬首。", "世方功名圖，我自饑寒走。", "蕭條政長路，驩喜逢故友。", "酒酌戒毋多，詩聲媿新有。"]'),
('90e1d89e-07b4-4cc4-a08b-27414c81887c','與彥博審知同爲問梅之行到溪南僕與審知俱以畏風罷興止小酌于僧房以有寒疾不可以風分韻作詩得有寒可字三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','非爲十日留，重此一歲闌。',48,'全唐诗/poet.song.164000.json','["非爲十日留，重此一歲闌。", "歲去易悲感，日來盛陰寒。", "今晨已春意，欲出反浩歎。", "梅事足可惜，病軀良獨難。"]'),
('a44552ec-9e62-4364-acf0-82104225032e','與彥博審知同爲問梅之行到溪南僕與審知俱以畏風罷興止小酌于僧房以有寒疾不可以風分韻作詩得有寒可字三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','山梅且翩翩，溪柳向婀娜。',48,'全唐诗/poet.song.164000.json','["山梅且翩翩，溪柳向婀娜。", "羣行欲何詣，僧屋惟所可。", "連朝謾蘄爾，作意終敗我。", "此事且復然，吾生信多坷。"]'),
('f6ae56b9-39aa-4d72-b93c-937b5ac0dc92','五月十有八夜與審知同宿塔山次審知韻','趙蕃','宋','宋诗','song-poetry','','[]','初期半山來，已止輒復上。',120,'全唐诗/poet.song.164000.json','["初期半山來，已止輒復上。", "山遊更同君，兼取魚熊掌。", "向來觀極南，屢作此山想。", "那知有今日，談笑得縱賞。", "謝公彼何人，詩聲擅霄壤。", "得非山川行，於以助其長。", "逐人易浮沈，與物多俯仰。", "政當恨未立，安曰悟已往。", "蕭蕭煙雲變，浩浩風雨響。", "世豈乏此觀，身由居蒼莽。"]'),
('f6e75949-7ebd-494d-aad0-c2c9d35144a2','再次韻','趙蕃','宋','宋诗','song-poetry','','[]','偶來無一關，何必化身上。',120,'全唐诗/poet.song.164000.json','["偶來無一關，何必化身上。", "下視膠擾中，脫去如覆掌。", "我生本山人，說山非妄想。", "賦詩亦漫興，不要世稱賞。", "與君志同趣，匪但居同壤。", "惟慚學不進，莫稱年事長。", "今人豈無賢，敢謂吾安仰。", "不爾簡與編，言行富前往。", "相期山中讀，勿待秋風響。", "而我累饑驅，畏途方莽莽。"]'),
('772b6733-ef3b-4c50-9a08-73d94d12d4b9','雨宿永源寺','趙蕃','宋','宋诗','song-poetry','','[]','六月有此雨，是爲豐年徵。',36,'全唐诗/poet.song.164000.json','["六月有此雨，是爲豐年徵。", "我眠虛堂上，肅肅若有冰。", "預愁前溪水，明發度凌兢。"]'),
('ae6dd227-1d45-432f-8a22-bf24f767e5b4','十二日登列岫亭有設空幄者去之薦福酌淺沙泉登大楚之秋屏閣而歸賦詩一首','趙蕃','宋','宋诗','song-poetry','','[]','軒亭著難穩，名字又惡同。',276,'全唐诗/poet.song.164000.json','["軒亭著難穩，名字又惡同。", "譬猶死得謚，美惡百代公。", "維洪之厭原，茲爲衆山雄。", "何許千萬間，可以屏障充。", "不於春夏時，刻畫仍遺冬。", "豈非即其西，故取摇落中。", "所得正且盡，評自曾南豐。", "是令登賦士，談說口不容。", "我留豫章城，十日雨且風。", "重尋湖上宅，再叩仙佛宮。", "未行北沙門，憂心實忡忡。", "落日擬進棹，殷勤謝篙工。", "我遊有未盡，汝去何匆匆。", "肩輿天寧寺，高下一逕通。", "其誰列翠幕，正爾遮青松。", "欲住不得久，傍觀南平鐘。", "清澄淺沙泉，一酌醒我胸。", "秋屏適跬步，直上如凌空。", "回觀列岫亭，有見真附庸。", "玄暉彈丸句，固足名壤穹。", "後人竟攘取，榜識千家逢。", "况茲如許山，詎止窗戶供。", "脊記題葆真，疑未經此翁。"]'),
('1452daf5-08af-43f1-ae95-f22584276667','孟秋八日夜伯壽仲理過予同訪俊乂步月入城南書院繇東渚上讀書堂過蒙軒憩卷雲欲訪月榭而月未到坐濯清者久之乃歸賦詩十四韻以記','趙蕃','宋','宋诗','song-poetry','','[]','昨夕城南來，鬰鬰張園窺。',168,'全唐诗/poet.song.164000.json','["昨夕城南來，鬰鬰張園窺。", "坡頭步犖确，牆下循委蛇。", "今夕復何夕，二妙爰集茲。", "重爲南坡行，因作張園之。", "無風幽自凉，有月光仍滋。", "菱荇與草樹，陸離間參差。", "卷雲一舉趾，濯清久支頤。", "空無十丈蓮，湛此數頃池。", "堤柳有倒影，畫手不可施。", "愛之不能已，遂許他夕期。", "昔人安在哉，萬里鯨魚騎。", "神游儻來歟，恍惚不可知。", "林園想巾履，編簡遺書詩。", "懷人渺無盡，樂處翻成悲。"]'),
('ca94e1cb-47d3-41c4-ab57-bb3f67449c80','克齋','趙蕃','宋','宋诗','song-poetry','','[]','百川恣奔騰，底柱乃屹立。',48,'全唐诗/poet.song.164000.json','["百川恣奔騰，底柱乃屹立。", "萬物蓋可流，疇能轉金石。", "世紛崢嶸來，何啻一敵國。", "油然反吾齋，夢覺春冰釋。"]'),
('f702c2a9-b9b0-4dcc-896f-c12bbbcaa6a2','題鄭氏北墅','趙蕃','宋','宋诗','song-poetry','','[]','籃輿度浮梁，朝嵐尚濛濛。',132,'全唐诗/poet.song.164000.json','["籃輿度浮梁，朝嵐尚濛濛。", "十有九日雨，得晴類投空。", "遊巖既願適，訪隠亦好從。", "道傍得野舍，一逕幽且通。", "主人誰與者，其祖鄭七松。", "流風被雲仍，真有隠者風。", "問年七十餘，曳履不扶筇。", "我年僅其半，而已衰龍鍾。", "豈其養生效，殆自起死功。", "若人種藝法，橐駝安取同。", "木老德亦熟，聞之蘇長公。"]'),
('fc5674af-b9d5-4091-906e-aec06f5c09ea','題彥真天開圖畫','趙蕃','宋','宋诗','song-poetry','','[]','湘山不爲高，湘水未爲遠。',84,'全唐诗/poet.song.164000.json','["湘山不爲高，湘水未爲遠。", "湘城幾何家，湘景無不輓。", "滕侯宅雖早，郭圃市之晚。", "紆餘直陂阤，突兀對偃蹇。", "登臨適正晝，亭榭愜深穩。", "詩材浩無窮，畫手羞用本。", "雖然倏變化，正以發關鍵。"]'),
('c1638908-68e0-4f37-95d4-7180035f76c7','餘干游昌國寺','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u897f\u6e56"]','於越之爲游，束髮迨中年。',108,'全唐诗/poet.song.164000.json','["於越之爲游，束髮迨中年。", "契闊固多矣，夢寐如喚焉。", "邇來數經過，所休必思禪。", "凭欄上清音，解包留煮泉。", "摩挲壁間詩，幾人獲流傳。", "歐吟廬山高，坡詠西湖全。", "惜哉此奇勝，乃不遭兩賢。", "何當覓扁舟，窮老依雲煙。", "脫屣塵垢外，岸巾鷗鷺前。"]'),
('246ce45f-df78-4157-aa10-0de0c751a59d','學佛者祖遷自南陵來謁莫萬安題詩于知津閣適同莫過而見之用韻以贈','趙蕃','宋','宋诗','song-poetry','','[]','嘗聞學苦空，世事應廢閣。',48,'全唐诗/poet.song.164000.json','["嘗聞學苦空，世事應廢閣。", "頗疑休己輩，顧以詩流落。", "爾今定何業，更慕揚州鶴。", "願長歲寒柯，勿矜春濯濯。"]'),
('2982af6d-7a9e-4cd1-86b9-55a4221349d6','獨過知津閣二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昔正月五，淵明遊斜川。',48,'全唐诗/poet.song.164000.json','["憶昔正月五，淵明遊斜川。", "我亦屏百事，來茲並欄干。", "雖無與俱人，鷗鷺翻以翩。", "吾生後淵明，此心兩悠然。"]'),
('add736b7-c204-463e-9659-e134ba7b7aa9','獨過知津閣二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','憶昔孟東野，作尉悲龍鍾。',48,'全唐诗/poet.song.164000.json','["憶昔孟東野，作尉悲龍鍾。", "有詩即景賦，大吏怒不容。", "我癡坐移官，避事得養慵。", "寄語鷗鷺輩，勿驚足音跫。"]'),
('2462bb20-c97e-45ec-bee2-2f0411e1efd5','題沅陵縣治廓軒','趙蕃','宋','宋诗','song-poetry','','[]','昔我過此屋，四壁蔽莫窺。',144,'全唐诗/poet.song.164000.json','["昔我過此屋，四壁蔽莫窺。", "屋外何所有，榛草連污池。", "今我重來過，壁去簷竹垂。", "榛草既除屏，洿池出漣漪。", "簷前復何有，江上山參差。", "山窮望不窮，所恨眼力遺。", "主人要命名，名汎境不隨。", "昔闇今則廓，曰廓咸謂宜。", "慨茲一室爾，繫在治不治。", "除昏與致明，可不念已爲。", "游焉且息焉，舍斯復何斯。", "豈惟君是規，我亦因得師。"]'),
('b2fc2a4a-b663-470e-b097-d1e997dc6421','胖軒','趙蕃','宋','宋诗','song-poetry','','[]','陶翁避暑者，容膝取易安。',48,'全唐诗/poet.song.164000.json','["陶翁避暑者，容膝取易安。", "賈生憂世患，晚乃悟達觀。", "出處等蘧廬，可作異致看。", "胸中極空洞，流止亦鯢盤。"]'),
('b0e41019-8fbf-4fe2-ad3e-42e5cab364cc','與潘文叔遊衡岳四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','欲行雨如蓰，既出雲若涌。',48,'全唐诗/poet.song.164000.json','["欲行雨如蓰，既出雲若涌。", "山高一身微，風動萬國洶。", "豈唯林木悲，亦爲毛髮悚。", "衆謂當亟回，吾行便賈勇。"]'),
('e91ecbc0-87fb-4539-b1f4-1d885b4ce863','與潘文叔遊衡岳四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','遠看雲吐吞，近見日出沒。',48,'全唐诗/poet.song.164000.json','["遠看雲吐吞，近見日出沒。", "解駮謂須臾，迷漫翻倏忽。", "山靈似知我，老興不得發。", "縱使盡高深，安能造剞劂。"]'),
('d55867c3-d9fa-4d57-a5f8-8c9c1492e2ec','與潘文叔遊衡岳四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','寥寥兩石門，此地忽在眼。',48,'全唐诗/poet.song.164000.json','["寥寥兩石門，此地忽在眼。", "臨欄塞雲霧，入戶欠編簡。", "規模自我友，恨不同叩款。", "仙佛匪吾徒，茲焉聊可館。"]'),
('612397c0-19d0-4db7-8d67-a8511c4860b1','與潘文叔遊衡岳四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','常聞祝融峰，今日上封寺。',48,'全唐诗/poet.song.164000.json','["常聞祝融峰，今日上封寺。", "雖孤登望眼，要逐幽遐志。", "蓋渠目力及，皆我脚力自。", "是可將無同，吾言亦聊戲。"]'),
('03f30440-8a0b-4d67-a390-d2cb41e62134','次韻衡州先生游花光因泛舟過向園示坐客之作','趙蕃','宋','宋诗','song-poetry','','[]','使君有佳招，宿雨曉更驚。',144,'全唐诗/poet.song.164000.json','["使君有佳招，宿雨曉更驚。", "晨起候天色，對岸煙嵐生。", "使君匪遨遊，因行問農甿。", "農甿趨急務，歡然慰中情。", "天公亦喜事，爲辦終日晴。", "喚酒屢酌客，往往顔半赬。", "興乘不暇止，遂作浮舟行。", "園荒久關閉，誰復相逢迎。", "但餘古梅花，點綴莓苔輕。", "想其種蒔時，老大繇孩嬰。", "中筵出高唱，妙絕五言城。", "勇起欲强和，媿此淫哇聲。"]'),
('a43f9d3e-970f-4d3e-b5b1-62641506da3a','衡山道中懷清江舊遊寄長沙諸公','趙蕃','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昔我官白下，屢到清江上。',180,'全唐诗/poet.song.164000.json','["昔我官白下，屢到清江上。", "清江衆君子，我友或我丈。", "至今過其邦，眷戀若鄉黨。", "幾思結廬居，風流共來往。", "柰何懷玉山，挽我不我放。", "去年五溪歸，泊家長沙國。", "長沙今洙泗，不但談賈屈。", "梁吳兄弟游，兩周新舊識。", "咸能不我鄙，更復成我益。", "其餘或一見，往往情如昔。", "自疑長沙人，宛類清江時。", "官期縱卒卒，行計猶遲遲。", "出門即風雪，悵此將安之。", "然薪旋燒酒，借筆追索詩。", "詩成何所屬，興落古湘西。"]'),
('47311f48-cc8b-40ed-8d47-5c41f512176b','發潭州','趙蕃','宋','宋诗','song-poetry','','[]','人言天宇澄，政好行遠道。',120,'全唐诗/poet.song.164000.json','["人言天宇澄，政好行遠道。", "秋陽既已後，朔風尚茲早。", "那知羈旅臣，寧有佳懷抱。", "鬻田就遠宦，廩薄不得飽。", "故鄉雖難歸，萬里生且老。", "及今翻滯留，悠邈不能到。", "客中更作客，此意將誰告。", "妻兒重相別，更語各善保。", "蛩鳴幽砌苔，馬齕荒原草。", "深羨田中人，春禾復囷藁。"]'),
('1d497feb-b1b7-4666-82cb-039b7433001a','頃在杭叔驥以離湖日見懷詩相遺舟中無事取而次韻兼呈同舟到衢當示叔驥及其兄法曹','趙蕃','宋','宋诗','song-poetry','','[]','江南千萬山，何許爲吾栖。',180,'全唐诗/poet.song.164000.json','["江南千萬山，何許爲吾栖。", "深林與豐草，本自麋鹿宜。", "長安冠盖場，誰識杜拾遺。", "日赴鄭老飯，未救方朔饑。", "如我何如人，飄然亦天涯。", "買舟今日歸，已恨作計遲。", "山川舊曾經，所至皆依依。", "共載得王蔡，何樂其如之。", "但恨詩豪人，先我浮春溪。", "眼中清絕處，收拾隨以西。", "遂令我筆端，失去溫潤姿。", "衢州法曹君，句成亦多奇。", "會當一快讀，遣此別後思。", "人生離合間，可喜更可悲。", "但泛石室酒，萬事端能齊。"]'),
('670623e7-9423-4291-b880-29800a9dd46e','溧水道中回寄子肅玉汝并屬李晦庵八首  其一','趙蕃','宋','宋诗','song-poetry','','[]','出門復入門，去來何悠悠。',36,'全唐诗/poet.song.164000.json','["出門復入門，去來何悠悠。", "故人別有見，見乃不重留。", "居人寧念此，行者可勝不。"]'),
('a6958329-e6d4-4992-8c93-9400942007bf','溧水道中回寄子肅玉汝并屬李晦庵八首  其二','趙蕃','宋','宋诗','song-poetry','','[]','今年非閏年，是月已臘月。',36,'全唐诗/poet.song.164000.json','["今年非閏年，是月已臘月。", "北風勿渠嗔，汝自衣百結。", "永夜只愁陰，清晨吹作雪。"]'),
('52cbad42-abc7-4b4d-9f59-72d4805232a1','溧水道中回寄子肅玉汝并屬李晦庵八首  其三','趙蕃','宋','宋诗','song-poetry','','[]','僧房四立壁，淅瀝夜吹風。',36,'全唐诗/poet.song.164000.json','["僧房四立壁，淅瀝夜吹風。", "破衲作深擁，其勢乃若空。", "晨鐘不能待，宿火撥通紅。"]'),
('9ec25c16-62b0-4f47-b4b9-f94045c007f7','溧水道中回寄子肅玉汝并屬李晦庵八首  其四','趙蕃','宋','宋诗','song-poetry','','[]','悲風吹籃輿，渺渺如孤舟。',36,'全唐诗/poet.song.164000.json','["悲風吹籃輿，渺渺如孤舟。", "我亦作坐睡，兀兀隨輕鷗。", "鷗翻夢亦覺，未絕叩舷謳。"]'),
('25a950cd-2ed7-4717-b871-f9bc0a2ccba9','溧水道中回寄子肅玉汝并屬李晦庵八首  其五','趙蕃','宋','宋诗','song-poetry','','[]','抱關故悠悠，掛壁仍駸駸。',36,'全唐诗/poet.song.164000.json','["抱關故悠悠，掛壁仍駸駸。", "况此十日病，酒止詩廢吟。", "別來定安否，千萬關我心。"]'),
('ac17b57a-2b9c-49d7-99a0-1a47c3e94e4f','溧水道中回寄子肅玉汝并屬李晦庵八首  其六','趙蕃','宋','宋诗','song-poetry','','[]','借宅亦種竹，知子未忘此。',36,'全唐诗/poet.song.164000.json','["借宅亦種竹，知子未忘此。", "竹間有餘暇，塵事勿到耳。", "行年且半百，太息我與爾。"]'),
('5173e543-66a8-462c-acd2-258bd78c4250','溧水道中回寄子肅玉汝并屬李晦庵八首  其七','趙蕃','宋','宋诗','song-poetry','','[]','懷綬新括州，乘驄前御史。',36,'全唐诗/poet.song.164000.json','["懷綬新括州，乘驄前御史。", "一州與天下，先後寧同軌。", "縱云山水佳，何與於瘡痏。"]'),
('3f453263-bb5d-4f71-9ba6-2fd38cb0a574','溧水道中回寄子肅玉汝并屬李晦庵八首  其八','趙蕃','宋','宋诗','song-poetry','','[]','李孫兩詞伯，我爾乃學子。',36,'全唐诗/poet.song.164000.json','["李孫兩詞伯，我爾乃學子。", "輩行雖不同，趣操要相似。", "歲寒松柏知，春風謝桃李。"]'),
('99ccbdc2-c07c-4ead-9522-3cba5a4987da','自溧陽達上塘官河舟屢行矣不能盡名其所經偶書小韻','趙蕃','宋','宋诗','song-poetry','','[]','平生溧陽船，白首凡幾遭。',120,'全唐诗/poet.song.164000.json','["平生溧陽船，白首凡幾遭。", "宜其登覽地，靡復應接勞。", "吳流亂如带，吳岫冗若毛。", "吳人闕共載，吳語聞空嘈。", "雖云面目熟，竟爾名字逃。", "冬常置雨雪，春復衝波濤。", "茲行又累日，逆風苦悲號。", "曾微咫尺帆，頗費千萬篙。", "一以付累句，再焉茲薄醪。", "詩書陶靖節，相馬九方皋。"]'),
('6001d9d6-64dc-4376-b19e-97beb5b26e63','貴溪出陸','趙蕃','宋','宋诗','song-poetry','','[]','捨舟覓籃輿，意欲避搜句。',60,'全唐诗/poet.song.164000.json','["捨舟覓籃輿，意欲避搜句。", "那知花草香，不減江山助。", "霏霏霧將歛，兀兀村又度。", "長卿故倦游，征夫問前路。", "歸歟亦何爲，時哉正農務。"]'),
('039177cc-0387-417d-8a35-8794eca2ff2b','二十三日雨中發贛州','趙蕃','宋','宋诗','song-poetry','','[]','江流何湯湯，萬里勢方注。',108,'全唐诗/poet.song.164000.json','["江流何湯湯，萬里勢方注。", "僮奴勸乘舟，期至纔旦莫。", "我聞是江石，屹立甚可怖。", "水乾或能避，水漲多與忤。", "卒行偶相攖，取死將誰訴。", "况我坎坷人，快意天所怒。", "遲速均一歸，可犯馮河懼。", "吾寧事崎嶇，依舊來時路。", "梅月况何常，無庸慮朝雨。"]'),
('836f8a29-b69d-41b5-8b03-b9659de367af','再宿合龍山','趙蕃','宋','宋诗','song-poetry','','[]','山僧雖居山，山豈山僧有。',192,'全唐诗/poet.song.164000.json','["山僧雖居山，山豈山僧有。", "政如多藏家，黄金爲誰守。", "我雖不居山，隨至輒有取。", "未嗤無田人，飯薄亦昏晝。", "生平所經歷，勝處十八九。", "要當考於詩，未易談諸口。", "合龍近始至，游訪茲亦偶。", "愛其四回合，中乃開戶牖。", "欣然遂留宿，日早未及酉。", "壁間右丞句，歲月蔽塵垢。", "摩挲追和之，武夫繼瓊玖。", "及今再來過，如客還舊畝。", "往泉但涓涓，今作雷音吼。", "往筍尚戢戢，今已長過母。", "長夏當更佳，我住不得久。", "遶竹聽泉鳴，悠然屢搔首。"]'),
('3632bde9-ba48-4fa7-ade8-40ac53d9364b','桃川山中用陳蘇舊韻示周遊','趙蕃','宋','宋诗','song-poetry','','[]','仙人之爲仙，終古莫盡世。',192,'全唐诗/poet.song.164000.json','["仙人之爲仙，終古莫盡世。", "頗笑區中人，沄沄逐川逝。", "念將與之游，端恐吾道廢。", "如爲千里行，數步輒一憩。", "不如返吾鄉，耕鑿仍樹藝。", "及私具伏臘，輸王應租稅。", "人惟顔徒睎，學匪桀犬吠。", "桃源定何許，說自淵明製。", "今日復何日，身乃中山詣。", "嗟哉彼嬴秦，其虐甚幽厲。", "不知喪無日，萬欲從始歲。", "商山被褐者，疢疾由德慧。", "徐福尚海山，此地只楚界。", "胡爲略不聞，政坐耳目蔽。", "神仙非吾學，可以置度外。", "山高水深深，好事幽尋契。"]'),
('efe64e9c-1369-4d6c-bca2-26e63129682e','與成父弟自嚴礲同入城晚宿黄巖','趙蕃','宋','宋诗','song-poetry','','[]','昔人重離合，感慨思功名。',156,'全唐诗/poet.song.164000.json','["昔人重離合，感慨思功名。", "我今迫貧賤，乃作分袂驚。", "徘徊未能別，崎嶇復同行。", "捫蘿到黄巖，倚杖日已傾。", "摩挲磴道古，開拓窗戶明。", "道人慣看客，撥火治短檠。", "村醪偶提携，霜柑亦包并。", "病來不喜飲，一再瀉濁清。", "道塗今日勞，林壑他年盟。", "蘇州對牀卧，不下五言城。", "自經長少公，增重手足情。", "細聽松竹響，疑是風雨鳴。", "披衣更起坐，月出山四更。"]'),
('b33b6e40-985f-4c42-a703-e244ebf6af1c','過愛直驛次張安國韻','趙蕃','宋','宋诗','song-poetry','','[]','亭然一何奇，枯者亦靡側。',72,'全唐诗/poet.song.164000.json','["亭然一何奇，枯者亦靡側。", "雖經歲祀多，未覺霜霰迫。", "余行再此驛，爾故無變色。", "慨念題詩人，深爲九泉客。", "泥深兀羸馬，苔老迷舊刻。", "愛爾故蒼蒼，余今變爲白。"]'),
('5e33b012-6a48-4f74-8ede-d217d4688c05','承契兄昨過我於永豐山間今又相遇於鄱陽以暇日同遊薦福寺會軒蓋鼎來避之天慶觀作詩一首','趙蕃','宋','宋诗','song-poetry','','[]','君爲日邊行，過我迂道里。',96,'全唐诗/poet.song.164000.json','["君爲日邊行，過我迂道里。", "我有江上役，值君亦行李。", "誰云動參商，邂逅乃如此。", "似非人力爲，定是天所使。", "古云昔道場，門枕東湖水。", "相從及休日，趨去不停軌。", "參禪固未暇，作詩實先議。", "要問戴叔倫，當年卜居意。"]'),
('9edfa1d5-505d-49a2-a3c8-68034b7504d4','發衡州後懷使君劉先生','趙蕃','宋','宋诗','song-poetry','','[]','四年別師門，十日留函丈。',48,'全唐诗/poet.song.164000.json','["四年別師門，十日留函丈。", "所問與所知，安得回賜放。", "孰爲驅之去，茲行定焉往。", "倦馬苦陂陀，白鷗思渺莽。"]'),
('9ada071b-bf80-4566-a49a-8e69b3d77a29','閏七月二十日侍知府寺簿先生爲石鼓山向園之遊','趙蕃','宋','宋诗','song-poetry','','[]','晦翁守南康，政成有餘暇。',192,'全唐诗/poet.song.164000.json','["晦翁守南康，政成有餘暇。", "駕言山之中，於日非聊假。", "紫霄作重陽，白鹿見圖畫。", "聞之幾向風，恨不款段跨。", "今年五溪歸，邇日三湘役。", "先生喜其至，舍以江亭闊。", "頻能枉高軒，人駭非重客。", "那知先生意，於此自爲德。", "茲日復何日，休沐著甲令。", "先生重過之，俱款石皷勝。", "西溪命題字，東巖俾開徑。", "既除古莓苔，又索賢名姓。", "已焉興未休，棹舟放中流。", "西風未却暑，一雨方回秋。", "僧坊遠莫至，隠墅近得留。", "寧同峴山輩，不異舞雩遊。"]'),
('a255ced3-c264-41cb-9b5e-cd951f9f29e4','蕃方爲紀遊之詩未就知府寺簿先生寵示佳句敢輒次韻','趙蕃','宋','宋诗','song-poetry','','[]','茲因謀道來，不爲看山新。',144,'全唐诗/poet.song.164000.json','["茲因謀道來，不爲看山新。", "看山雖云新，圖畫猶昔人。", "虛亭十日留，欲出凡幾巡。", "隔江樹差差，俯檻波粼粼。", "終藉席間語，乃滌胸中塵。", "况茲籃輿行，攀崖陟嶙峋。", "是知竹使符，不異邱壑身。", "世人何不察，百僞嫌一真。", "而我孤拙者，崎嶇聿其轃。", "話言聽矻矻，書札勝頻頻。", "先生今徐州，愚非歐陽陳。", "庶因唱酬詩，牽聯詔無泯。"]'),
('8d42d683-d555-4e0f-9188-17a0c5a786a9','仙巖道間','趙蕃','宋','宋诗','song-poetry','','[]','茲巖如許深，中乃一物無。',168,'全唐诗/poet.song.164000.json','["茲巖如許深，中乃一物無。", "非仙莫能幻，故即巖之呼。", "何代有禪衲，孑焉寄褐蒲。", "名字不可考，種松今欲枯。", "我來值雪後，陰崖盡成晡。", "茶罷攝衣起，巾車問前途。", "前岡雲氣敷，後嶺兩脚暗。", "宵安禮賢枕，蚤赴天心飯。", "奔馳亦云極，憇息寧卹蹔。", "自猶厭登車，况乃躬負擔。", "行年甫三十，道里遍千萬。", "懷哉坐一饑，使我歷諸患。", "長卿病故多，次山仕真漫。", "盍整舊詩書，歸歟老山澗。"]'),
('b54b77f8-3d9e-40a9-b04f-ab21ec6c3863','題新樂鋪鋪在灘頭','趙蕃','宋','宋诗','song-poetry','','[]','朝煙山濛濛，暮靄山羃羃。',48,'全唐诗/poet.song.164000.json','["朝煙山濛濛，暮靄山羃羃。", "窮日作山行，而不見山色。", "投昏宿此舍，乞曉動前轍。", "歸夢遶家山，灘頭有輕檝。"]'),
('fb043773-ab2f-4111-a4c3-d9eb7685f3fc','夜泊劉口雨連明有懷成父','趙蕃','宋','宋诗','song-poetry','','[]','山中風雨夕，招要對床期。',48,'全唐诗/poet.song.164000.json','["山中風雨夕，招要對床期。", "今夕風亦雨，牢落孤舟維。", "蓬窗與竹窗，蕭瑟雨在茲。", "不寐欲至曙，何繇夢見之。"]'),
('17445c4a-2bd5-4bac-8931-97f7c11ec4b4','重九前一日東流道中','趙蕃','宋','宋诗','song-poetry','','[]','明日乃重九，今晨更天涯。',48,'全唐诗/poet.song.164000.json','["明日乃重九，今晨更天涯。", "馬嘶原上草，菊放崖邊花。", "吾家白雲合，歸路青嶂賒。", "去去無復道，行行空自嗟。"]'),
('27316403-5db2-40dc-b59d-6b73639e6465','意釣','趙蕃','宋','宋诗','song-poetry','','[]','仲舒區中賢，談治苦吃吃。',96,'全唐诗/poet.song.164000.json','["仲舒區中賢，談治苦吃吃。", "但知羨川魚，不慮網罟密。", "仁哉東坡公，遊戲亦此術。", "究其廣大心，意釣真玩物。", "我欲竊其語，作廬以自逸。", "東西南北人，有志特未必。", "相會有溪竹，竹下亭可立。", "亭成乞以名，四海一明月。"]'),
('acd625db-c76c-4810-adf0-c1a60a822a6f','半江遇風濤其勢危甚晚示同舟','趙蕃','宋','宋诗','song-poetry','','[]','言歸固多欣，值險輒大怖。',120,'全唐诗/poet.song.164000.json','["言歸固多欣，值險輒大怖。", "方趨順風捷，忽與犇濤遇。", "得非蛟龍爭，無乃雷霆怒。", "我舟僅如掌，我命且如縷。", "何止失人色，殆欲成狼顧。", "神明力扶持，生死費調護。", "平生素多艱，安坐乃其處。", "便哦歸來辭，勿草遠遊賦。", "同行信同憂，相唁勞相諭。", "急反浪頭魂，還尋酒中趣。"]'),
('a1bfcc35-2c15-47be-ad80-82fa0601be24','十二月一日使風','趙蕃','宋','宋诗','song-poetry','','["\u592a\u6e56"]','中宵不得休，常州已鷄鳴。',96,'全唐诗/poet.song.164000.json','["中宵不得休，常州已鷄鳴。", "欲知五更寒，掃霜四聞聲。", "出門風暴起，掛席遂前征。", "官河溝瀆耳，洶洶若未平。", "想見太湖中，白浪山嶽傾。", "紆直雖有殊，高枕幸不驚。", "舟師尚若悔，吾身未宜輕。", "既無性命憂，從使嫌怨并。"]'),
('d6f8c864-ffdd-41f1-ab8e-57b330424dd6','嚴州道間得順風俗云七里瀧篙師云風便纔七里無風乃七十里爾','趙蕃','宋','宋诗','song-poetry','','[]','桐江多犇湍，牽挽厭勞止。',132,'全唐诗/poet.song.164000.json','["桐江多犇湍，牽挽厭勞止。", "舊云七里瀧，實乃七十里。", "篙師爲予言，風便輒易爾。", "迴思前日驚，留滯固可喜。", "溪神果何心，憐我倦行李。", "有風西南來，不徐亦不駛。", "布帆保無恙，爲賜何其侈。", "眼中峰巒過，天外鷗鳥起。", "畫圖欠傳貌，詩語費驅使。", "生平登臨心，於此得自已。", "勿歎囊橐空，收將遺妻子。"]'),
('77eff7ad-ad7b-4253-898e-5cd4a7a5170b','永豐令括蒼章君尉上蔡謝君以淳熙改元二月晦日勸農於負郭祖印院事已率蕃爲汎舟之役','趙蕃','宋','宋诗','song-poetry','','[]','前村後村桃李空，牡丹酴醿當春風。',224,'全唐诗/poet.song.164000.json','["前村後村桃李空，牡丹酴醿當春風。", "令君無暇問許事，親率僚吏行劭農。", "清晨小隊東郊出，宿雨初開泥尚濕。", "白頭扶杖稚子旁，不待符移自相集。", "令君盛服臨致言，國因肆赦新改元。", "雍熙淳化太宗年，治道度越唐漢前。", "爾曹何幸生此世，身不知兵無橫稅。", "去秋小歉未足云，詔書屢下憂勤意。", "吏令奉行敢不躬，爾無自惰愆爾功。", "吾言諄諄爾其聽，酒肉更戴君恩豐。", "我時佇立觀盛舉，徑欲傭田買牛具。", "不然枵腹亦以寬，年登賤糴夫何慮。", "少焉有白官盍休，携我山陰上小舟。", "謂我聊此半日留，與民同樂非宴遊。"]'),
('602cfd7d-13c1-4fc7-b2cb-980402918cb7','四月十二日以夏潦暴甚艤舟辰之鐵槍崖下偶得浮木於水中宛然如山因其形似名曰卧嶺立峰喜而賦詩當寄交友之能詩者求著語焉','趙蕃','宋','宋诗','song-poetry','','[]','昔讀梅蘇木山詩，未信人間有此奇。',224,'全唐诗/poet.song.164000.json','["昔讀梅蘇木山詩，未信人間有此奇。", "雖云尤物不必有，時一玩之何病爲。", "吾行東南千萬里，仙遊不已遂臻此。", "奇奇怪怪日在眼，浩浩湯湯夜盈耳。", "舊評峽江似嚴陵，此行佳處亦可朋。", "又聞八桂好山水，亦應與此相雲仍。", "畫師好手不可遇，詩中有畫無其具。", "江神好事不我尤，乞與一山酬願素。", "不知何年遭仆落，浪激波衝幾飄泊。", "岸高壁立自嶄巖，泓淺坳深非斧鑿。", "老夫得之喜莫極，欲加名字相刻畫。", "卧之成嶺立成峰，天成故爾非人力。", "多言譊譊欲何如，要覓新詩爲寫摹。", "余名敢與昔人並，用寄我友梅蘇徒。"]'),
('27038e0a-8d5b-4f7c-920d-8b7f7fc430fc','八月二十四日同審知登塔山用審知前載九日留題之韻作二首時彥博歸及常山  其一','趙蕃','宋','宋诗','song-poetry','','[]','郊原莽莽吹黄埃，餘暑已去若復來。',128,'全唐诗/poet.song.164000.json','["郊原莽莽吹黄埃，餘暑已去若復來。", "昨宵一雨爲蘇洗，曉興坐覺飛崔嵬。", "平生詩盟有徐孺，筆力可挽狂瀾回。", "要明兩眼費雙脚，作計似我何疏哉。", "茲遊只欠王子在，見說歸書一紙開。", "追隨正復聽君樂，流浪如我空增哀。", "吾邦此山頗高絕，泛菊况堪臨季月。", "要當相與一杯酒，只恐因之又成別。"]'),
('e2eea2f8-ac2c-47cc-87c1-006f33e7374e','八月二十四日同審知登塔山用審知前載九日留題之韻作二首時彥博歸及常山  其二','趙蕃','宋','宋诗','song-poetry','','[]','出門生憎觸風埃，故邀幽人山中來。',128,'全唐诗/poet.song.164000.json','["出門生憎觸風埃，故邀幽人山中來。", "小休危亭带曲折，未盡高塔當崔嵬。", "目營所到豈有極，脚力尚壯不擬回。", "舊遊久闊空信耳，高處一上何佳哉。", "是山百年定誰主，一丘新壤手所開。", "淵明自祭豈非達，杜牧作誌夫何哀。", "如君風流固曠絕，與我論交忘歲月。", "異時訪我入此山，扣牛共唱生生別。"]'),
('6c820585-68ba-46ea-a2ef-75eeb45b8b15','明日同數公復登山忽聞履聲乃審知也携和詩三篇來復用韻作一首','趙蕃','宋','宋诗','song-poetry','','[]','松間謖謖衝浮埃，跫然誰能爲余來。',128,'全唐诗/poet.song.164000.json','["松間謖謖衝浮埃，跫然誰能爲余來。", "憑高所歷故已下，得君更覺爭崔嵬。", "茲山不到近十載，頻日能來已再回。", "人生萬事每如此，而欲取必真愚哉。", "袖銜文書辱持似，快讀不待紙尾開。", "金聲詎須擲地出，隠隠自雜山風哀。", "吾曹用意果癡絕，非爾何以娛歲月。", "明當舉似子王子，不但慰歸仍賦別。"]'),
('56c3cbbd-c841-4a8d-9490-4ab341e5736c','貴溪隔岸有二巖僕舊遊也聞子暢受秋租於彼以詩寄之','趙蕃','宋','宋诗','song-poetry','','[]','黄巖嶄絕人人居，徐巖蟠鬰處士廬。',144,'全唐诗/poet.song.164000.json','["黄巖嶄絕人人居，徐巖蟠鬰處士廬。", "扁舟半載泊南岸，折梅看雪頻携壺。", "黄巖夾道松百株，風來迎送齊笙竽。", "壇崩殿古黄冠癯，懸巖石刻墨可模。", "徐巖觸目多荒蕪，啼嘯往往紛鼪鼯。", "廢基斷砌或有無，名字不復知誰渠。", "聞君奉檄方受租，播糠瞇目莫與娛。", "作詩爲君道何如，尋幽速遣從騎驅。", "賦成孰寄當念吾，不用寒溫枉素書。"]'),
('e8d23f1d-680b-4a22-913f-389b3e1aff83','次韻斯遠同宿歲寒西軒六韻','趙蕃','宋','宋诗','song-poetry','','[]','思君無計憂能舒，見君還愧腹每虛。',96,'全唐诗/poet.song.164000.json','["思君無計憂能舒，見君還愧腹每虛。", "知君於此未見止，而我但覺有不如。", "他人招呼厭來集，爲我淹留成屢屈。", "豈惟高義篤交情，政頼微言起衰疾。", "南山三剎此最高，平生幾許乎逍遥。", "異時我去君獨遨，期當寄我山中謠。"]'),
('0eec34ae-e7e4-4c1c-9dfa-e9e9df791784','謁孺子祠後由南昌還艤舟之地','趙蕃','宋','宋诗','song-poetry','','[]','南昌假傳欲上書，孺子乃復辭聘車。',64,'全唐诗/poet.song.164000.json','["南昌假傳欲上書，孺子乃復辭聘車。", "東都已顛不可救，莽篡未露猶枝梧。", "福爲市卒終潜吳，穉乃懸榻太守居。", "吁哉迹異心不殊，出處語默如是夫。"]'),
('bbf73c56-56d1-4467-9208-98320f30d60f','呈齊之二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','舍舟步到南山寺，恍然忽記當年事。',67,'全唐诗/poet.song.164000.json','["舍舟步到南山寺，恍然忽記當年事。", "李侯見我顔色溫，席間款語真有味。", "翰林風月久蕪沒，莫歎青衫百僚底。", "君不見少陵一生窮到死，亦有詩能驅瘧鬼。"]'),
('6fe379e4-d6a9-4be1-a216-73944cf40229','呈齊之二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','夜聞袁宏誦詩聲，空山寂寞魚龍驚。',64,'全唐诗/poet.song.164000.json','["夜聞袁宏誦詩聲，空山寂寞魚龍驚。", "丈夫有才不貧賤，倦遊何乃困長卿。", "平生讀書得力處，公卿褐夫安重輕。", "鴻鵠一飛定千里，俯首莫與燕雀爭。"]'),
('df6dd16e-6ce2-4beb-abd5-3ce74246eabf','主山湖圍二渡','趙蕃','宋','宋诗','song-poetry','','[]','主山渡頭成久立，長年傲客呼從疾。',64,'全唐诗/poet.song.164000.json','["主山渡頭成久立，長年傲客呼從疾。", "撐舟來前僅如掌，泝波却下幾百尺。", "湖圍橋壞新有船，衆壑犇流會一川。", "嗟我胡爲數此險，爭似飯餘牛背眠。"]'),
('c015557c-8936-4653-a8f7-57412992334f','約明叔過買江天閣','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','前年爲君記江閣，醉裏狂言不知怍。',96,'全唐诗/poet.song.164000.json','["前年爲君記江閣，醉裏狂言不知怍。", "豈惟大負退之慙，要似揚雄真悔作。", "君家此閣端何然，萬里長江咫尺山。", "江流湛湛山平遠，合付畫手非詩傳。", "畫工縱得空諸境，閣中之人妙難領。", "世人紛紛夔蚿蛇，是公了了形神影。"]'),
('054e6f09-e045-4cb9-a628-7424d72e3dcb','白鷺洲詞寄曾裘甫','趙蕃','宋','宋诗','song-poetry','','[]','白鷺洲前烟草微，黄鶴樓外烟雲飛。',64,'全唐诗/poet.song.164000.json','["白鷺洲前烟草微，黄鶴樓外烟雲飛。", "縹縹黄鶴政高舉，漾漾白鷺孤無依。", "鶴舉直上登寥廓，鷺立汀洲方俯啄。", "卒然驚墮野人罝，豈不欲飛遭急縛。"]'),
('11047970-7c1c-4b05-b685-0efc22904554','示兒','趙蕃','宋','宋诗','song-poetry','','[]','我昔讀書夜達晨，膏燭且盡繼以薪。',64,'全唐诗/poet.song.164000.json','["我昔讀書夜達晨，膏燭且盡繼以薪。", "年來漸知得力處，簞瓢陋巷忘其貧。", "爾曹有身須自立，幸逃薪水供朝夕。", "不於文學自勤苦，長大始悔終何益。"]'),
('dcd795f0-28c2-4f52-a431-f1938ed7bb5b','十八日記夢','趙蕃','宋','宋诗','song-poetry','','[]','冥冥落月子規哭，幽人夢成續復續。',194,'全唐诗/poet.song.164000.json','["冥冥落月子規哭，幽人夢成續復續。", "茅簷壞砌到何許，酴醿架倒留紫竹。", "紫竹新抽雨又滋，淚粉娟娟凝翠玉。", "夢中自省非宿遊，又意簷村舊林谷。", "阿連對牀呼得醒，亦說夢作看花行。", "看花夢向江南去，江石犖确屐有聲。", "行逢古屋鬰崢嶸，仙家釋氏俱莫名。", "看花非揚亦非洛，但見滿眼灼灼朝霞明。", "夢中又意東莊路，普圓寺下芙蓉樹。", "主人亦道舊相識，乃復不逢戶外屨。", "嗟我與君無自疑，夜之所夢晝所爲。", "扁舟若具可徑歸，知長不必詢筮龜。"]'),
('9e78e17c-03bd-440f-8042-a78f5712c161','別韓尚書','趙蕃','宋','宋诗','song-poetry','','[]','南山之作險以壯，南溪之作閒以放。',192,'全唐诗/poet.song.164000.json','["南山之作險以壯，南溪之作閒以放。", "流風莫和况當家，南澗先生堪頡頏。", "吾州自昔寡所傳，一自南渡居羣賢。", "邇來寂寞誰嗣焉，先生築屋南山邊。", "先生事業本廊廟，履聲夙已明光到。", "闔廬固非避寒暑，大厦萬間均覆幬。", "我家爲庶爲清門，早因昭德容攀援。", "自期松柏歲寒後，不入桃李春風園。", "鄉者屢見不一見，何但懷刺亦行卷。", "胡爲於此不繼來，衣食遑遑遊苦倦。", "扁舟去矣江復湖，可能不一趨庭隅。", "吹噓上天不敢望，贈言於此能無乎。"]'),
('d0659a52-0c4e-4b9b-aac0-4604796a7c0f','送徐季益赴婺州陳尚書之招并屬寄謝郡守韓侍郎','趙蕃','宋','宋诗','song-poetry','','[]','禪月臺邊草樹蒼，下臨溪流碧泱泱。',160,'全唐诗/poet.song.164000.json','["禪月臺邊草樹蒼，下臨溪流碧泱泱。", "君卜居之歲且長，徑路不忍夷其荒。", "我時巾幅上君堂，勞君煮茶炷爐香。", "與談世故如有亡，掉頭誦詩聲遶梁。", "別來書劄闕寄將，忽然貽我細作行。", "似言欲從懷玉旁，迤邐遠趣金華裝。", "金華尚書漢豫章，招禮孺子固所當。", "出處有道君素詳，此行甚重無或傷。", "况君袖手久退藏，九十半百胡可忘。", "儻謁地主詢吾鄉，爲致登臨憶侍郎。"]'),
('766d1077-8539-4580-8cc5-bc43174ac88f','寄新喻丞章季亨','趙蕃','宋','宋诗','song-poetry','','[]','憶昨寄聲因鮑子，闕然已復四終星。',64,'全唐诗/poet.song.164000.json','["憶昨寄聲因鮑子，闕然已復四終星。", "向來相期臺閣者，薄宦乃淹松竹廳。", "頗願近詩見新述，舊好尚意能忘形。", "臨風三歎不知罷，梅花落盡蘭未馨。"]'),
('77e90f32-537e-4176-8da3-df0abbce358b','送王亢宗赴劍浦丞','趙蕃','宋','宋诗','song-poetry','','[]','青松自是山林物，移植階除傲難屈。',128,'全唐诗/poet.song.164000.json','["青松自是山林物，移植階除傲難屈。", "雜居箠楚塵埃地，譬似高人累簪紱。", "孰能哦詠於其下，古今僅有一斯立。", "昌黎老翁爲之記，遂使崔名等金石。", "王郎家世本愛竹，舊說不可無一日。", "要將我竹配渠松，聊復從容寄卑秩。", "春風咫尺龍蛇動，除地求栽政宜疾。", "爲銘耘業定誰歟，是公筆力韓之敵。"]'),
('97c58fd6-c1ab-425e-b503-08c4916a86b4','送程提幹','趙蕃','宋','宋诗','song-poetry','','[]','尚書曾剖上饒符，我姊亦歸高郵掾。',64,'全唐诗/poet.song.164000.json','["尚書曾剖上饒符，我姊亦歸高郵掾。", "與公既親亦有故，此地經行幾相見。", "十年幕府持旌麾，日月計之無乃遲。", "治世急才寧定制，徯公把節慰民思。"]'),
('7f273fce-26d4-4cce-85ec-a35214303bb7','送丁懷忠朝佐赴象州教授二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','西山南浦昔相逢，桂林象郡今相送。',64,'全唐诗/poet.song.164000.json','["西山南浦昔相逢，桂林象郡今相送。", "長才妙略世所知，諸公貴人胡不用。", "文風廣被固可喜，志士遠適豈其理。", "上書報罷君勿悲，廣西政復多事宜。"]'),
('537eb4ee-1ec2-403d-a2db-d3bb2c4a3b07','送丁懷忠朝佐赴象州教授二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我今方從湖外歸，君行重向湖外去。',64,'全唐诗/poet.song.164000.json','["我今方從湖外歸，君行重向湖外去。", "湖南山水故佳絕，我獨茫茫畏長路。", "君行更過五嶺南，象郡我亦聞人談。", "縱令爲郡真爾好，願勿久留歸要早。"]'),
('f2f18d21-721b-4524-8126-3121a0516f14','留別子肅','趙蕃','宋','宋诗','song-poetry','','[]','欲雪不雪雲雨愁，將行未行心口謀。',160,'全唐诗/poet.song.164000.json','["欲雪不雪雲雨愁，將行未行心口謀。", "問胡不去良有由，故人伏枕關我憂。", "自心初識十年遊，不作世人新白頭。", "抱關非爲辭挾搜，乃知自欲吾志求。", "適來遂作兼旬留，昔者公侯今日瘳。", "河山空能泣楚囚，不如窗几問不休。", "公如大道鳴驊騮，我乃蹇足歷澗溝。", "彌明故足悲侯劉，淙淙詎識東之流。", "懷哉黄堰公先疇，章泉吾亦營菟裘。", "莫言相望風馬牛，葦間會有延緣舟。"]'),
('b1c5ea40-80b9-4135-bbfb-6a962d39290c','次韻呈審知','趙蕃','宋','宋诗','song-poetry','','[]','誰云徐郎瘦如竹，撐腸書若相如粟。',128,'全唐诗/poet.song.164000.json','["誰云徐郎瘦如竹，撐腸書若相如粟。", "渠儂高處背時俗，而獨許我遊與辱。", "舊來詩已有老氣，邇日更覺加圓熟。", "我生取友固不苟，乃復得君真厭足。", "清朝求士正側席，可使白駒詠空谷。", "期君布衣應徵書，未見却從東觀讀。", "我今作官竟何事，亟拜未應徒鼎肉。", "與民憂樂安得同，所念因人終碌碌。"]'),
('4a7ffee0-267d-46f8-bf75-48dc82e47cb9','再次韻呈審知','趙蕃','宋','宋诗','song-poetry','','[]','秋風泠然動高竹，起並朝簷溫體粟。',128,'全唐诗/poet.song.164000.json','["秋風泠然動高竹，起並朝簷溫體粟。", "忽驚剝啄意誰何，乃是和詩重拜辱。", "再三開闔手不置，不惟詩好字亦熟。", "我雖年事濫催忝，於此論功真未足。", "重憐別來不我舍，連日追隨訪林谷。", "和詩未厭數還往，別後要期常誦讀。", "知音已死或絕絃，聞韶解忘三月肉。", "但得我輩識錚錚，徒使世人譏碌碌。"]'),
('9a348f92-97cb-4fc8-be4a-586e0a23aeec','審知以詩送行借韻留別','趙蕃','宋','宋诗','song-poetry','','[]','十年保我章泉竹，木枕布衾供易粟。',128,'全唐诗/poet.song.164000.json','["十年保我章泉竹，木枕布衾供易粟。", "家貧縱爾不自給，且不知榮安取辱。", "今年誰令起作官，此路向來非所熟。", "示詩往往道離索，又說是邦山水足。", "風流文物夙有人，九州共識黄山谷。", "細哦海內流傳句，足緩司空城旦讀。", "少時已無鞍馬志，老矣豈堪消髀肉。", "但令詩與故人期，此外聲名甘碌碌。"]'),
('75bc2285-9aaa-4ac0-bf85-f6d63a7b2bd5','季奕枉詩送行借審知韻奉別并呈伯元','趙蕃','宋','宋诗','song-poetry','','[]','往年敵來如破竹，九州泛若浮海粟。',128,'全唐诗/poet.song.164000.json','["往年敵來如破竹，九州泛若浮海粟。", "鄭公仗節守馮翊，毅然可殺不可辱。", "飄流南浮適茲里，平生行事耳目熟。", "幾回下馬過其墳，溪水洄洄抱山足。", "季孫甚才耻爲吏，哦詩欲效雲臺谷。", "四篇贈我勞我行，入手爲之三過讀。", "君家涇縣亦工此，知者尚稀凡眼肉。", "會看入洛似機雲，不應如我但碌碌。"]'),
('14ba77b6-550e-4d00-8f0d-6c4919a93d48','孝顯追送至沙溪書所見以別','趙蕃','宋','宋诗','song-poetry','','[]','白雲英英行空山，白鷺矯矯去復還。',112,'全唐诗/poet.song.164000.json','["白雲英英行空山，白鷺矯矯去復還。", "雨聲驟來却小住，樹色全綠或半殷。", "誰家有屋茅三間，舂聲未斷橫炊烟。", "刈禾雖阻得治圃，造物所惠無一偏。", "我亦願此坐無田，千里顧上西江船。", "經年擾子曾未厭，更煩車馬相追牽。", "客中無酒可醉子，聊書所見爲別言。"]'),
('b2e600f6-3958-4e57-b33b-03065e9e2812','成父來自玉山審知有送行詩且以見及次韻','趙蕃','宋','宋诗','song-poetry','','[]','思君一夕或三起，詩卷曷從來眼裏。',128,'全唐诗/poet.song.164000.json','["思君一夕或三起，詩卷曷從來眼裏。", "驟疑笑語接秋窗，不悟江山隔吾里。", "近來海內詩好誰，賤目可憐空貴耳。", "謫仙既作東山稱，杜陵亦貴衡陽紙。", "吾人得窮固其分，幽谷安能爭市倚。", "何當與子棄茲世，卜居在在佳山水。", "不同淵明田下潠，即效龜蒙耕甫里。", "文成不作封禪詞，相我于耜并舉趾。"]'),
('db5439ff-d7af-4e81-adc2-f31159d645bd','次韻徐運使送行','趙蕃','宋','宋诗','song-poetry','','[]','歸耕負郭家無牛，手持釣竿何適投。',104,'全唐诗/poet.song.164000.json','["歸耕負郭家無牛，手持釣竿何適投。", "長年慘慘集百憂，土牛未肯隨獼猴。", "秋風別家月未鈎，彈鋏永歎客五侯。", "吳江楓落曾四愁，行行重到江東州。", "誰能著意憐轉流，新詩忽俾吟掉頭。", "念將小駐蹇莫留，冰霜豈不思推輈，山川回首空相繆。"]'),
('bb787088-6ae5-4516-82c0-c5f65d1f0f7b','再次韻審知索彥博送行之文','趙蕃','宋','宋诗','song-poetry','','[]','江清可釣思持竹，地廣可耕思種粟。',134,'全唐诗/poet.song.164000.json','["江清可釣思持竹，地廣可耕思種粟。", "胡爲作計久低回，而乃覓官親賤辱。", "南州徐孺晚與遊，江東文度昔所熟。", "堂堂荆州止獲一人半，我邦有此二士差亦足。", "五君流詠轉竹林，蘭亭何意慕金谷。", "徐詩到眼以數過，王筆入手曾未讀。", "但能贈我以規不以頌，不用崇酒仍載肉。", "嗟哉他人豈無言，交友不高徒碌碌。"]'),
('900dde8c-a3ed-45e0-bd18-be4e7ab36a72','寄劉叔驥兼索遠齋伯瑞仲文叔魚叔驥和叔太和送行詩','趙蕃','宋','宋诗','song-poetry','','[]','苕溪往來非不款，何山道場况非遠。',128,'全唐诗/poet.song.164000.json','["苕溪往來非不款，何山道場况非遠。", "如何著脚竟無緣，孤我平生看山眼。", "劉郎生長在溪山，吸光飲綠歲月閑。", "不惟人作晉宋樣，更覺詩參簡遠間。", "向來稍得相酬唱，別後闕然難屢枉。", "况今結束事西浮，那可無詩道遐想。", "遠齋視我猶其子，伯仲視我乃其季。", "儻能俱寄絕妙辭，更約髯參并表弟。"]'),
('c7bf300a-d56c-44b4-8bb8-4049b40967d9','寄楊溥子','趙蕃','宋','宋诗','song-poetry','','[]','昔聞許劭月旦評，人生倚以分重輕。',160,'全唐诗/poet.song.164000.json','["昔聞許劭月旦評，人生倚以分重輕。", "當時初非徇虛名，往往夷考其學行。", "今人誰復持此柄，鄉評亦復無公論。", "故當信目不信耳，毀譽不用從人問。", "我行溧陽得楊子，何止國士天下士。", "大科異等非謾狂，筆頭真有三萬字。", "十篇琅琅金玉音，一唱三歎感我心。", "子昂感遇不啻過，阮籍詠懷何念深。", "匡章通國稱不孝，夫子與遊仍禮貌。", "雖然前聖亦有云，善與不善分惡好。"]'),
('b5860f76-792c-4d16-95db-f7e26fa33ce0','文顯和答旦字韻詩再用前韻寄文顯','趙蕃','宋','宋诗','song-poetry','','[]','憶昔追隨昏復旦，負郭雖賒足忘倦。',99,'全唐诗/poet.song.164000.json','["憶昔追隨昏復旦，負郭雖賒足忘倦。", "別之未覺夢魂疏，但恨有時音信斷。", "世間變化何不有，深谷寧須問高岸。", "我今瘦骨立如山，君亦童頭不能亂。", "君不見簞瓢自樂保清名，富貴失時多遠竄。", "千年青史固茫茫，精意所關唯此段。"]'),
('a3701bde-13c0-434b-b245-2b15a98edb2f','達觀僧紹本年九十能記東坡建中靖國題詩之事且云清都道士者坡同遊此寺坡題詩後道士臨之而滅其迹爲賦詩記此','趙蕃','宋','宋诗','song-poetry','','[]','老僧長生元祐年，龐眉皓首高頰顴。',64,'全唐诗/poet.song.164000.json','["老僧長生元祐年，龐眉皓首高頰顴。", "紛然送迎過雲烟，解記南歸玉局仙。", "清都道士同蹁躚，詩成忽俾如蛻蟬。", "嗟哉用心故可憐，那知海內爭流傳。"]'),
('dbe1da1c-e688-4931-8e51-767e8f0e89b0','鑑山主以天聖宣賜行道者五百金裝羅漢青𤮀香爐爲示復用韻','趙蕃','宋','宋诗','song-poetry','','[]','高林杲杲日欲出，却視諸山雲自入。',96,'全唐诗/poet.song.164000.json','["高林杲杲日欲出，却視諸山雲自入。", "道人導我啟圓龕，五百金仙爭突兀。", "耀州燒甆樸不巧，獅子座中蓮葉繞。", "亂餘得此鎮山靈，莫恨當時賜田少。", "世人變滅隨空雲，至人來往繇念根。", "長眉下生會有辰，摩挱笑視默與論。"]'),
('0df91002-ec04-4b66-9906-d92692466a86','寄婺州喻良能叔奇','趙蕃','宋','宋诗','song-poetry','','[]','我家入婺四十里，有竹參天山崛起。',320,'全唐诗/poet.song.164000.json','["我家入婺四十里，有竹參天山崛起。", "尋常一過故人飯，長是驅車不停軌。", "去年偶爲逃暑留，禪房小憇清溪頭。", "君當適閩駐行李，遣騎問我安與不。", "我聞君來固驚喜，君亦怪我窮不死。", "殷勤竟辱懷刺先，我乃踉蹡成倒屣。", "相看問我今何如，爲言斑鬢甘泥塗。", "君時新有阿兄戚，語及往事猶長吁。", "君歸匆匆莫可挽，劇談未了風吹斷。", "贈君不直一錢詩，何以報之錦繡段。", "明朝過君君且行，我思重別難爲情。", "勞君下馬更握手，再三謂我頻寄聲。", "別來僅可熟羊胛，含薰待春蘭已發。", "擬將採掇慰離居，路遠何繇置君側。", "如君人才誰與儔，直諒豈下西京劉。", "校讎祕府自能事，何乃傳經瀕海州。", "吾君急賢每旰食，詔書取士到微仄。", "君今未免滯周南，諸公貴人曷逃責。", "願君覓句勿自哀，清尊無事日日開。", "未有白地光明錦，用作人間負販材。"]'),
('30701da3-228f-4e76-9a72-54bc2fa3d0da','到家寄季承二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','相逢到別二十日，披覽溪山駐行役。',96,'全唐诗/poet.song.164000.json','["相逢到別二十日，披覽溪山駐行役。", "凄凉浩蕩兩生境，意不求詩詩自得。", "臨分不作珍重語，顧欲倡酬詩卷覓。", "問君得此君何用，云比相如家四壁。", "杜陵囊帛解救寒，陸生越橐千金直。", "人言君侯真太癡，君癡不癡君自識。"]'),
('6ab02067-c974-46f2-b1ae-77503d8fdea7','到家寄季承二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','向來已念修途苦，還家作况初無愈。',96,'全唐诗/poet.song.164000.json','["向來已念修途苦，還家作况初無愈。", "嬌兒失乳索飯啼，病妻服藥思鹿脯。", "關心藥裹詩自廢，無復吟哦繼朝暮。", "與君定交且十年，相從未有如君許。", "信知此藥莫可常，後會驚心念風雨。", "報儂安否比何如，莫以素書慵不具。"]'),
('8b53a1a1-7e3f-4259-8b1e-5be8e39dd3db','寄子暢文顯兼問僉判丈起居','趙蕃','宋','宋诗','song-poetry','','[]','昨憶長歌與君屬，嗟爾明月悲黄菊。',128,'全唐诗/poet.song.164000.json','["昨憶長歌與君屬，嗟爾明月悲黄菊。", "問君得歸今幾日，我迺還家期未卜。", "人生會合不可常，何止有類參與商。", "月明固可共清影，菊開安得同幽香。", "安輿歷想來自越，賀以羊酒生暖熱。", "小人繆忝通家子，不獲親陪上壽列。", "羨君斑衣有餘歡，憐我縕袍無乃單。", "何當卒歲從周子，陋巷簞瓢忘餒寒。"]'),
('ec940575-07a2-43aa-ab6f-e2c2c34ffb8e','以歸來後與斯遠倡酬詩卷寄辛卿','趙蕃','宋','宋诗','song-poetry','','[]','人家餽歲何所爲，紛紛酒肉相携持。',128,'全唐诗/poet.song.164000.json','["人家餽歲何所爲，紛紛酒肉相携持。", "我曹餽歲復何有，酬倡之詩十餘首。", "緘封寄藁玄英方，從人笑癡我自狂。", "狂餘更欲誰送似，咫尺知音稼軒是。", "公乎比復何所作，想亦高吟動清酌。", "賓朋雜遝孰爲佳，咸推楊范工詞華。", "我曹所樂雖小技，歷古更今不能廢。", "歲云暮矣勿歎窮，梅花爛漫行春風。"]'),
('bd35cc84-413a-4c69-91c1-3f2c5ec68a6d','寄莫萬安','趙蕃','宋','宋诗','song-poetry','','[]','天生尤物爲民瘵，荔枝奔騰自南海。',128,'全唐诗/poet.song.164000.json','["天生尤物爲民瘵，荔枝奔騰自南海。", "後來始說閩部採，亦有風人刺丁蔡。", "嗟哉萬安十室邑，橘比江陵梨號蜜。", "嘗聞舊日事苞苴，千數私家公百十。", "莫侯爲令知其然，罷獻初從使者先。", "其餘詬病置不問，貧友或乞捐餐錢。", "憶昨追隨秋政熱，不但近公如玉雪。", "別來已忽露爲霜，當念相如多病渴。"]'),
('95c2f55d-bea1-42ca-8ce2-365dbf092bd7','送周守二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昔我移官皇恐灘，緘詩送公因阿連。',320,'全唐诗/poet.song.164000.json','["昔我移官皇恐灘，緘詩送公因阿連。", "轉頭梅事兩飄忽，我亦解秩當返轅。", "豈期邂逅客歸舍，逢公政成朝日邊。", "可無一語道離闊，顧待別後空闌干。", "我聞袁人道路言，往者頗病吏道煩。", "袁人徯公以爲治，如赤子待父母安。", "問公治袁竟何如，寬不至弛嚴不殘。", "不惟民絕催科瘢，吏亦不急惠文冠。", "太平官府見今日，珥筆舊俗略不存。", "簿書期會足閒暇，江山風月忘遊般。", "作堂圃中視所尚，我所尊者房李韓。", "東西日月雙跳丸，後人思公面孱顔。", "人言循吏治無迹，有如春風被田園。", "試看一一發生意，從千百數何繇論。", "淳熙聖人歎才難，得人之路無不殫。", "而於守令最注意，往往六察并郎官。", "少公邇日與幾政，仲氏力請得皖灊。", "公雖遲登玉笋班，持節其惠寡與鰥。", "未知除書落何地，我家懷玉江東山。", "勿言形迹暫云遠，在處孰非千萬間。"]'),
('2c5e35d0-fa88-40c4-b9c6-16df823df2a7','送周守二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','雨珠雨玉非襦粟，雨雨懸知勝珠玉。',64,'全唐诗/poet.song.164000.json','["雨珠雨玉非襦粟，雨雨懸知勝珠玉。", "去年病禱祗如楚，今歲應祈如撒菽。", "黄雲割盡綠浪摇，可實饑腸慰枵腹。", "微官但爲斗食謀，再拜題詩謝賢牧。"]'),
('879f645c-2a63-4b95-8053-fe0fc04076ab','早過桃川不能謁一菴走筆寄之','趙蕃','宋','宋诗','song-poetry','','[]','山蒼蒼，水茫茫，落月未落歸故鄉。',64,'全唐诗/poet.song.164000.json','["山蒼蒼，水茫茫，落月未落歸故鄉。", "扁舟欲繫忽已遠，隠居不見遥相望。", "思君山中煮白石，歎我道上炊黄粱。", "開書視古常太息，今人高處亦難及。"]'),
('f7c2641c-0262-467a-8a63-6ed47f5c7002','泊舟桃花臺入妙香院','趙蕃','宋','宋诗','song-poetry','','[]','携家本避長城戍，孫子相仍住桃塢。',128,'全唐诗/poet.song.164000.json','["携家本避長城戍，孫子相仍住桃塢。", "雖云秦暴賦可逃，後乃開通晉南渡。", "當時未有神仙傳，創自淵明詩五言。", "祇今圖畫遍四海，樓臺樹木空蒼然。", "玄都亦說桃千樹，夢得飄零因怨句。", "未應只屬羽人家，亦有因茲悟初祖。", "我州那得桃花臺，臺下清溪轉石哀。", "仙耶釋耶不可見，每一過之空繫纜。"]'),
('d2c8f84e-b7bb-40bc-8d9e-e24a000d6de3','晨起聞杜鵑','趙蕃','宋','宋诗','song-poetry','','[]','水聲嘈雜蛙聲小，客子披衣坐侵曉。',64,'全唐诗/poet.song.164000.json','["水聲嘈雜蛙聲小，客子披衣坐侵曉。", "平生嗜懶每貪眠，行李催人未渠了。", "不勝倦歎歌方苦，更聽林間杜鵑語。", "杜鵑我豈不知歸，淵明政爲饑驅去。"]'),
('377f50ed-6312-433b-9a8d-fc4c97971ba2','初六日絕湖','趙蕃','宋','宋诗','song-poetry','','[]','政爾喧豗浪如屋，忽焉熨帖紋如縠。',64,'全唐诗/poet.song.164000.json','["政爾喧豗浪如屋，忽焉熨帖紋如縠。", "大船雙櫓鳴鸛鵝，小艇孤橈亂鳬鶩。", "金沙粲粲列宿明，君山宛宛修眉綠。", "囊無東絹畫無工，爲寫南征圖十幅。"]'),
('c7f09cc4-7279-428a-86ac-055233eb1aa8','南風行十八日早作','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吾聞黄帝張樂洞庭野，始意莊生言故假。',132,'全唐诗/poet.song.164000.json','["吾聞黄帝張樂洞庭野，始意莊生言故假。", "又聞湘靈鼓瑟進玄螭，亦意屈子夸厥辭。", "屬行洞庭四月半，南風三日吹不斷。", "黄昏猶是天陸離，午夜忽成雲片段。", "病夫數起不知睡，數起側聽仍熟視。", "恍疑帝樂尚鏗鍧，又謂湘絃發幽閟。", "乃知二子元非虛，吾聞自用耳目拘。", "須臾月落天向曉，依舊南風波浩渺。"]'),
('9f3e9fa4-8911-4f14-905d-94960975a7f0','遊山谷寺贈住山欽老欽嗣愚丘詩','趙蕃','宋','宋诗','song-poetry','','[]','少小已誦山谷文，老大始遊山谷寺。',64,'全唐诗/poet.song.164000.json','["少小已誦山谷文，老大始遊山谷寺。", "按詩尋境盡可得，落筆不容追一字。", "舊聞是老詩有宗，韓門更許愚丘雄。", "風流前輩日已遠，此道此山俱屬公。"]'),
('a37c7f0b-b93f-4e13-b62c-1e39b926e8f1','除夕萬安寄成父并示兒女','趙蕃','宋','宋诗','song-poetry','','[]','去年除夕遥憐汝，今歲酒觴期對舉。',96,'全唐诗/poet.song.164000.json','["去年除夕遥憐汝，今歲酒觴期對舉。", "誰知人事苦好乖，百里相望竟成阻。", "去年雖深兄弟思，兒女抱負有母慈。", "今年已作生死隔，慟哭無地天使之。", "哀哉一官竟何直，南北由人長役役。", "屬兒無恨弟勿嗟，來歲田廬當畢集。"]'),
('c9cd20ac-6508-40ce-a8a5-212cfa5d8c41','初六日阻風新淦二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昨日北風猶可行，今日北風不可撐。',64,'全唐诗/poet.song.164000.json','["昨日北風猶可行，今日北風不可撐。", "雖無人止公無渡，憑河而死聖不與。", "况我生平憂患多，平陸往往愁風波。", "近連章貢遠鄱蠡，如此千濤萬浪何。"]'),
('ca294e53-7591-4b9c-8fd3-249762ee546c','初六日阻風新淦二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','北風不但江流白，天色往往吹作陰。',64,'全唐诗/poet.song.164000.json','["北風不但江流白，天色往往吹作陰。", "漫云一水六十里，中有青山千萬尋。", "人言下水必犇駛，而獨於此成滯淫。", "鵁鶄屬玉爾自得，短詠長歌吾亦任。"]'),
('295ecb49-4922-4cd5-9dd5-8daa49c29da8','投宿聖仙寮','趙蕃','宋','宋诗','song-poetry','','[]','已慚叩戶驚莊夢，更喜置牀鄰畢甕。',64,'全唐诗/poet.song.164000.json','["已慚叩戶驚莊夢，更喜置牀鄰畢甕。", "新醅未熟不可嘗，舊酒雖漓聊入用。", "道人深居怕賓客，老子頻年慣行役。", "細聽木杪風向息，起視月沈天正黑。"]'),
('e33a5a73-033d-466b-b280-ff2b7a21a078','宿合龍山達觀寺用張澂達明壁間韻','趙蕃','宋','宋诗','song-poetry','','[]','遊山到處不擬出，幾向官程問山入。',96,'全唐诗/poet.song.164000.json','["遊山到處不擬出，幾向官程問山入。", "旁人笑我底悠悠，我亦應緣聊兀兀。", "平生作詩忌大巧，到此真成腸胃繞。", "試將閣筆罷楮生，又病囊中此山少。", "入山已破山中雲，出山定復松崖根。", "合龍端爲此得名，達觀妙旨又莫論。"]'),
('c55b85b9-810a-4952-98cb-62a429d3db33','博山道中','趙蕃','宋','宋诗','song-poetry','','[]','春陰春晴往復佳，園花落去逢山花。',64,'全唐诗/poet.song.164000.json','["春陰春晴往復佳，園花落去逢山花。", "城中小駐欲十日，坐覺老眼孤芳華。", "中團寺前慣休歇，故向博山尋曲折。", "眼中奇處要使傳，倚頼筆端真有舌。"]'),
('7e8d9694-5123-48bf-ba0f-5325b91febc2','芙蓉道間二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','芙蓉山上芙蓉尖，向人咫尺分毫纖。',64,'全唐诗/poet.song.164000.json','["芙蓉山上芙蓉尖，向人咫尺分毫纖。", "或如冠劍或鳥獸，令我左右煩窺覘。", "平生退之南山句，爲渠持騁筆力嚴。", "那知刻畫果辦此，造物至是無留殲。"]'),
('593ba89a-b156-4eaa-a54a-761111d0f420','芙蓉道間二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','芙蓉山下芙蓉渡，歷盡崔嵬何物路。',64,'全唐诗/poet.song.164000.json','["芙蓉山下芙蓉渡，歷盡崔嵬何物路。", "更觀溪水突人來，令我詩情雜欣懼。", "輿夫重說松原山，如此積雨應生湍。", "從來潢潦無根源，水收石露須臾間。"]'),
('be1109b4-53d2-4899-a1ff-c56048a32ee6','辰陽待嶽祠之命舟發武陵回寄從遊諸公','趙蕃','宋','宋诗','song-poetry','','[]','叔父風流元祐支，清貧遠自相國時。',208,'全唐诗/poet.song.164000.json','["叔父風流元祐支，清貧遠自相國時。", "舊聞河朔人偉奇，元衡筆力猶可窺。", "佳哉伯玉賢塤箎，小阮亦與竹林期。", "兆民雖云非舊知，知之正自梅花詩。", "伯壽憔悴儒冠衣，十年不調長苦饑。", "經明行修後所歸，非吾光遠其誰推。", "洪文學問方築基，基成可保無傾欹。", "嗟我誤落東南陲，疏者迺親親異宜。", "念我流轉終年疲，去章已上歸俟之。", "或持酒肴或贈辭，亦或眷眷江之湄。", "數面成親還語離，前日之樂今日悲。", "秋風颯颯衣披披，山長水遠屬玉飛。", "高城望斷日已西，望不可見令人思。"]'),
('1017867c-4e7d-4f1a-ac7a-375fef207e59','明叔有語贈贛丞曾幼度次韻簡明叔并寄幼度爲明叔賦買江天詩','趙蕃','宋','宋诗','song-poetry','','[]','詩成要落天地間，太虛明月相往還。',192,'全唐诗/poet.song.164000.json','["詩成要落天地間，太虛明月相往還。", "聲名或覺四海隘，身乃憔悴窮閉關。", "詩中妙理超生死，何但不以彼易此。", "我來白下豈徒然，簿書鳬鶩非吾事。", "陳君一見投紵衣，刺天翼並青冥垂。", "楚人不悞玉在璞，山川終用騂之犁。", "曾侯願識今已後，因君示我詩到手。", "不惟我輩獨識真，異饌珍羞甘衆口。", "幾思插翅飛墮前，漫看璧月缺復圓。", "符移催來定不遠，挐音不見聞擔肩。", "世人千金買嬋娟，我視棄去如浮烟。", "萬言杯水世所捐，顧欲頼以無窮傳。"]'),
('4db7f267-077f-44b7-81c5-d22dec4b2d8c','次韻徐季純見貽','趙蕃','宋','宋诗','song-poetry','','[]','尺渾孰愈千丈清，幽居何以爭城傾。',160,'全唐诗/poet.song.164000.json','["尺渾孰愈千丈清，幽居何以爭城傾。", "翺翔蓬蒿豈不適，乃欲萬里勞蜚鳴。", "文章縱云有定價，瓦釜亦或能鏗鍧。", "知音固當屬善聽，我初未鼓一再行。", "鄭人之璞周死鼠，昧者自謂懷連城。", "我于翰墨雖早嗜，四十五十今何情。", "元無小異君孰取，矻矻便欲揚其名。", "得非念我西南征，倦遊久意思傭耕。", "少年不飲老更醒，而衆紛紛多絕纓。", "屬君勿用揚其名，臃腫拳曲能全生。"]'),
('1f6ef199-6cce-40e5-855b-a1f6932d4bbf','畢叔文携坡帖及與季真給事倡酬詩卷見訪於邢大聲家相與觀之明日次韻淳熙癸卯正月二十有一日也','趙蕃','宋','宋诗','song-poetry','','[]','精金美玉當難朽，白衣蒼狗終何有。',192,'全唐诗/poet.song.164000.json','["精金美玉當難朽，白衣蒼狗終何有。", "胡爲徑欲老東坡，應坐生時宿南斗。", "何時斯文日再中，共推元祐超羣公。", "衮衣已易深衣古，醴酒寧思客酒濃。", "當年政化方隨日，詔訪賢良設科十。", "玉堂發策肆雄深，四海旁招無遁逸。", "緬惟貞觀圖凌烟，功臣劍佩空蹌然。", "未如武德藏書府，至今名字星日懸。", "君之曾祖我高祖，想象聞風謂千古。", "書藏東里罔或存，集喜西臺刊未覩。", "相逢已足慰悲凉，墨妙更許窺家藏。", "趣奇造異兩邢子，置酒共親燈燭光。"]'),
('42c08c3c-78e5-4ec8-9e4d-9a39ba7e659b','次韻斯遠同彥章見過之作','趙蕃','宋','宋诗','song-poetry','','[]','昔人結交談耳餘，一朝變起肝腦塗。',160,'全唐诗/poet.song.164000.json','["昔人結交談耳餘，一朝變起肝腦塗。", "吾曹結交自有道，嗜好又况子與余。", "每憶見君吾里初，中間去君落江湖。", "歸來忽忽夏復夏，相過凡幾窮朝晡。", "君家仲容亦吾徒，向來亦恨天一隅。", "我今借屋得近市，渠乃屏迹田間廬。", "吾曹與物自多忤，頌詩讀書猶論古。", "君才端可供王羞，而我不足供鼎俎。", "胡爲愛我不棄我，匪但追隨仍晤語。", "南山有約不可渝，可堪舊雨連今雨。"]'),
('cafc8e0a-2979-4382-af10-eec0e1c5c78d','次韻徐審知寄贈古句','趙蕃','宋','宋诗','song-poetry','','[]','倦遊歷落三載中，重來觸事多不同。',256,'全唐诗/poet.song.164000.json','["倦遊歷落三載中，重來觸事多不同。", "舊交雲散隔山嶽，在者一二莫我從。", "新知喜獲徐孺子，年少已有諸老風。", "譬之寶劍雖尚伏，清夜往往舒長虹。", "惟君家學故有宗，念我早日嘗登龍。", "周旋何止道疇昔，玷缺便擬相彌縫。", "分携轉眄且十日，夢寐嘗若見德容。", "要裁短章寄離闊，抒思苦窮無由豐。", "新詩忽來墮我側，句法沈穩字亦工。", "寂寥此道幾欲息，玄文縱在人非雄。", "吾君嗜好乃如此，誰爲冀北真羣空。", "我今百不一稱意，顧頼交友忘終窮。", "茲焉得君益足賀，自起酌酒澆塊胸。", "滔滔原從濫觴至，君其勿憚尋尺庸。", "異時相見定刮目，敢作吳下舊阿蒙。", "因君我亦事穮蔉，瘠鹵要使成千鍾。"]'),
('7f7e34de-3de5-42a1-9622-8d6932401f84','呈審知','趙蕃','宋','宋诗','song-poetry','','[]','去年別君重九日，君時痁作卧一室。',224,'全唐诗/poet.song.164000.json','["去年別君重九日，君時痁作卧一室。", "許我爲我一入山，人事好乖言竟食。", "一官我落江之西，每附書來必以詩。", "宣心寫妙無不盡，知君不累寒與饑。", "念君見君何由得，江西水深波浪闊。", "無何奄忽室人喪，繫舟復在南山側。", "君來見我顔色好，不但文章能合道。", "信知木潤山有輝，盎背晬然眸子瞭。", "向來之所未見書，向我誦讀如貫珠。", "有時舉問不知對，汗爲浹背口輒呿。", "嗟我忝惟十年長，學業無功時既往。", "羨渠松柏拱把姿，絕勝樗櫟高尋丈。", "一官羈我端何爲，投劾歸來亦未遲。", "豈惟問字當載酒，儻復借書仍一癡。"]'),
('ec611e45-23a1-46a6-8963-2cff1504143c','呈葉懷寧陳參軍章簿公','趙蕃','宋','宋诗','song-poetry','','[]','潜山皖山烟雨昏，山城索莫少所親。',96,'全唐诗/poet.song.164000.json','["潜山皖山烟雨昏，山城索莫少所親。", "令君邀我入山去，復道山流方四奔。", "側聞剝啄來叩門，疑匪索我云見存。", "已焉一見即傾倒，乃與諸劉相弟昆。", "因君又來驚坐陳，吾嘗同寮義世敦。", "不惟邂逅索詩卷，更復追隨携酒尊。"]'),
('1b774d59-02ba-45d5-a9ca-43857467d392','呈任邕州詔子言','趙蕃','宋','宋诗','song-poetry','','[]','清江江上賢大夫，我所識者向楊胡。',128,'全唐诗/poet.song.164000.json','["清江江上賢大夫，我所識者向楊胡。", "盤園近說在城郭，使君政剖邕州符。", "笑談雖阻親顔色，新詩往往流傳得。", "豈知舟楫復江湖，飄飄又墮清江側。", "向來一識苦無因，茲日何緣得造門。", "要題詩句道所以，行色蒼茫難具陳。", "盤園已成十年陰，使君二毛殊未侵。", "平生慷慨功名事，切勿戀此成遐心。"]'),
('d852f48a-ecb5-41b3-8077-cf5588d21b29','用前韻呈碩父昆仲','趙蕃','宋','宋诗','song-poetry','','[]','嗟我失脚墮棘榛，寸步有若千里行。',144,'全唐诗/poet.song.164000.json','["嗟我失脚墮棘榛，寸步有若千里行。", "窮山自縛數椽屋，便認懷玉爲里門。", "扁舟泛從吳楚轉，遠遊欲賦慚無文。", "他鄉喜見兩表弟，把臂勞苦仍如勤。", "夜窗款坐屢續燈，有酒更倒樽如岑。", "祗今一笑莫輕失，轉首便恐成後今。", "要知後會渺何許，慷慨忍對臨風襟。", "故家如子未多有，立身行己須自欽。", "不惟門戶在所寄，異日亦足張吾軍。"]'),
('7411c253-c995-426d-ad6e-6ce3578d9069','曾季明經過相見聞壽岡先生掛冠之報且承動靜因其歸賦古句寄呈用坡谷贈王慶源韻','趙蕃','宋','宋诗','song-poetry','','[]','夫子文章何所如，高處直命騷爲奴。',160,'全唐诗/poet.song.164000.json','["夫子文章何所如，高處直命騷爲奴。", "世人共誦詞人賦，不道雕蟲羞壯夫。", "兒時聞公薌林社，既見則喜已白鬚。", "公亦與我自言志，笑謂此客向來無。", "昨傳得官隸王都，且復將試齊相壺。", "岐江嚴湍浪饒舌，愛公願公吾道扶。", "今知謝事歸懸車，食可無肉寒須襦。", "再三問公近起居，復道今腴非昔癯。", "君今好去相與娛，馬牛寧得加我呼。", "絕代幽居在空谷，市門三五方當壚。"]'),
('e17575c0-b6c4-41e7-a395-a85f7e79208d','戲呈喻叔奇丈','趙蕃','宋','宋诗','song-poetry','','[]','平生喻工部，許我詩盟與。',124,'全唐诗/poet.song.164000.json','["平生喻工部，許我詩盟與。", "邇來每見每匆匆，倚頼深春間歸路。", "問我自行何所去，告以吳門當小住。", "問公公有故人否，爲我略營薪水助。", "欣然惠我書一紙，爲我殷勤談所以。", "我云素書難送汝，併復因之陳骩骳。", "公言於我則厚矣，楓落吳江自爲累。", "幸逃烏有一先生，猶勝東城老居士。"]'),
('e4bb27e4-deec-470c-bdf0-d75cd40ba00e','坐間呈曾幼度兼屬陳明叔','趙蕃','宋','宋诗','song-poetry','','[]','三年幾度江天閣，我爾相看兩牢落。',96,'全唐诗/poet.song.164000.json','["三年幾度江天閣，我爾相看兩牢落。", "江山好處欲題詩，下筆逡巡媿吾弱。", "詩中最愛曾贛丞，恨渠不來俱此登。", "今最驅車叩吾門，寒漫未了先覓君。", "乃知吾人同臭味，識面聞風總相契。", "一杯聊爾勞江山，向來鬰鬰今開顔。"]'),
('eca34447-2d56-4209-9fa0-040e8f077de7','留清江蒙簡兄壽玉徐兄思叔皆以文卷寵教愧未有以謝又承壽玉枉示古句仍用鄙韻謹次韻併呈二兄','趙蕃','宋','宋诗','song-poetry','','[]','客亭何以祛暑溽，一時頓有此兩玉。',128,'全唐诗/poet.song.164000.json','["客亭何以祛暑溽，一時頓有此兩玉。", "逃虛不用聽跫然，醫俗寧須更栽竹。", "平生韋布困藍縷，敢並奇文森綺縠。", "愛而忘醜反譽我，惠以大篇仍短幅。", "頗思浹日相就談，應對先生媿空腹。", "奈何別棹復催去，一日十日寒且暴。", "兩君如此尚場屋，吞舟詎可尋常瀆。", "悵子薄官亦碌碌，政坐家貧耕不足。"]'),
('0f676e3d-266b-417c-abca-232492d68254','二日晚得少空偶閲杜集無何墜火焚者數葉謹成古句致愧惜之意呈明叔仲威','趙蕃','宋','宋诗','song-poetry','','[]','去年鼠齧涪翁文，今年火攻少陵詩。',160,'全唐诗/poet.song.164000.json','["去年鼠齧涪翁文，今年火攻少陵詩。", "雖云成毀有定數，天意於此可逆知。", "我之所嗜何足計，上有先墨顔之姿。", "况渠詩本貫忠義，在處神物宜護持。", "向來一字且莫補，脫此千百何繇追。", "我詩不工空自欺，天意豈欲警戒之。", "不然身當貧到骨，俱應蓄此瑰瑋詞。", "又疑風來勸勤讀，邂逅俾之遭禍奇。", "平生學易未有得，損益二卦須湛思。", "詩成書以示我友，不惟自訟仍求規。"]'),
('c5f633ae-b429-4d8c-8c8a-c282fcc2f277','莫萬安生日','趙蕃','宋','宋诗','song-poetry','','[]','員多闕少銓曹病，陛下用人多擇令。',160,'全唐诗/poet.song.164000.json','["員多闕少銓曹病，陛下用人多擇令。", "公今秩滿代未除，召節盍來人側聽。", "我知天意從民欲，要煖袴襦飽餐粥。", "遂令局促滯騰驤，百里孰如天下福。", "我官白下未識公，謠俗往往聞其風。", "坐移不作趨走怕，政喜官曹退食同。", "我嘗從容聽公說，勞心撫字催科拙。", "昔人如此號循良，歎息今時異途轍。", "雖然自有公論在，民之所言上其採。", "舉觴不但祝長年，始立新秋甘雨霈。"]'),
('7e6ac5fb-b1a0-42c0-8b3b-5313b5ee8e56','送趙一叔江西漕赴召代成父作二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昨公持使節西，迎公曾渡石田溪。',64,'全唐诗/poet.song.164000.json','["憶昨公持使節西，迎公曾渡石田溪。", "今公復因召節至，送公亦渡石田水。", "公今西來又東去，送迎車馬紛無數。", "我雖憔悴不如人，倚頼故情蘄一顧。"]'),
('6f05e4ae-0fd1-4857-ab4f-0d67e83df31b','送趙一叔江西漕赴召代成父作二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','阿兄今得太和官，買舟同載初不難。',64,'全唐诗/poet.song.164000.json','["阿兄今得太和官，買舟同載初不難。", "公持使節豫章郡，蘄以過公道窘寒。", "公今召節趨日邊，我雖失望猶欣然。", "西江恩波千萬里，活此枯魚當易爾。"]'),
('b3fd2c81-d960-48e1-ad3e-73cb02b73474','正月二十四日雨霰交作','趙蕃','宋','宋诗','song-poetry','','[]','杏花燒空紅欲然，柳色亦復青可憐。',96,'全唐诗/poet.song.164000.json','["杏花燒空紅欲然，柳色亦復青可憐。", "胡爲雨霰忽交作，已洗破衾還被綿。", "去冬梅時雪復雪，未省好看冰玉潔。", "祇今縱有已殘枝，零落教人已愁絕。", "故知好雨當趣耕，快雨仍須作快晴。", "放渠花柳十分事，我欲浩蕩郊原行。"]'),
('5c7fed5e-8ee6-4b0b-98bb-df2a1008e662','二月十日夜雨起書曾移忠禾譜後','趙蕃','宋','宋诗','song-poetry','','[]','去年秋旱冬尤劇，一雪不能濡土瘠。',288,'全唐诗/poet.song.164000.json','["去年秋旱冬尤劇，一雪不能濡土瘠。", "立春日雨雖應時，到今闕然又幾日。", "遊人但欣春物榮，農夫痛心田未耕。", "我因于役偶適野，駭見蓬勃煙埃生。", "我今一官非勸農，爲民閔雨常顒顒。", "如聞春寒雨之候，病骨不憚添衣重。", "朝來數點初蔌蔌，勢壓黄昏成霢霂。", "雖云潤物要無聲，未救田疇龜背暴。", "眼前市糴雖云賤，復道輸租錢乏見。", "從來穀賤必傷農，政亦何能堪此旱。", "天公用意何難爲，三日爲霖事可知。", "區區折腰困日糴，苦憶村舂宿雨時。", "屠龍先生曾夫子，著書斤斤良有以。", "往曾持獻儒林蘇，爲歌秧馬附書尾。", "髯孫知我此書愛，遺我殷勤意何在。", "世人菽麥或未分，而翁有意除稊稗。", "我今一官故不堪，此書歸田爲指南。", "便當教兒罷群讀，讀此寧憂飯不足。"]'),
('13e977ff-aea1-4e5a-84a1-43f2e12e568f','二月十二日偶題','趙蕃','宋','宋诗','song-poetry','','[]','空庭無人風自掃，風定時聞有啼鳥。',64,'全唐诗/poet.song.164000.json','["空庭無人風自掃，風定時聞有啼鳥。", "簿書幸免苦束縛，文字何妨恣探討。", "菊湯瀹茗雜鼠蓂，瓦鑪欲作風泠泠。", "睡魔於此不得靈，簷間卧對山橫青。"]'),
('1e527eb8-5c07-45e1-9ebe-40b4a9274ac6','二月十七日','趙蕃','宋','宋诗','song-poetry','','[]','入春不雨憂在田，數朝乃復相屬連。',96,'全唐诗/poet.song.164000.json','["入春不雨憂在田，數朝乃復相屬連。", "今晨得晴絕可喜，病體素羸猶著綿。", "杏花始開忽已落，桃李安能問今昨。", "獨餘楊柳故青青，乃似仍叔之子弱。", "春今二月已强半，匆匆何方爲羈絆。", "雨雖未厭愁奈何，又聽僕僕林鳩喚。"]'),
('7a0be6f1-cc63-4eb5-84c7-bf4378256ff1','社後一日風雨中作','趙蕃','宋','宋诗','song-poetry','','[]','南山北山雨未分，東村西村雞叫羣。',64,'全唐诗/poet.song.164000.json','["南山北山雨未分，東村西村雞叫羣。", "病夫深居百不聞，香爐茗椀頻策勳。", "浮生蹤跡空中雲，斯須變化歸無垠。", "春風九十又足云，眼中紅白徒紛紛。"]'),
('e7df1be9-5de1-48f2-adc1-5acba4630729','張王臣載酒約同過梁和仲既以風雨大作舉杯相屬而止偶成四韻呈和仲','趙蕃','宋','宋诗','song-poetry','','[]','祇疑寒食無風雨，不料今晨頓如許。',64,'全唐诗/poet.song.164000.json','["祇疑寒食無風雨，不料今晨頓如許。", "縱然風雨敢怨尤，留得佳人駐南浦。", "佳人雖駐亦何爲，杯酒竟成孤晤語。", "巴陵他日記同曾，君歎淹留我羈旅。"]'),
('1bfafd01-c6e4-4244-8468-cb811a758ec7','三月十八日','趙蕃','宋','宋诗','song-poetry','','[]','巴陵一月雨不休，豈惟人病天亦愁。',128,'全唐诗/poet.song.164000.json','["巴陵一月雨不休，豈惟人病天亦愁。", "蠶饑麥腐穀種壞，農夫田婦呼天求。", "巴邑有客方倦游，杭湖欲歸思具舟。", "冥冥政爾羨歸雁，拍拍安得從輕鷗。", "遠書數月絕不得，爾窮故與吾髣髴。", "或云此雨祇此域，又道淋淫遍江國。", "夜來痛飲不知極，終日破牀成兀兀。", "感斯風雨憶江東，詩就鳥栖窗紙黑。"]'),
('4a76a292-c6e3-452e-a12e-683ffcfe5c6e','二十一日雨','趙蕃','宋','宋诗','song-poetry','','[]','疾風吹倒庭前樹，更有飛來雨如注。',128,'全唐诗/poet.song.164000.json','["疾風吹倒庭前樹，更有飛來雨如注。", "終朝畏暑自脫巾，亟起收書不能屨。", "前山雲重如潑墨，坐想溪流高數尺。", "是間無乃隔分龍，點滴纔堪清几席。", "前時小旱已作憂，三日爲霖遂不休。", "早禾盡實晚禾秀，造物於此功無留。", "祇今望霓尤所急，百里之行半九十。", "民乃犇走奉神祠，神盍經營足民食。"]'),
('3fed18a1-ad9e-4ba6-b7df-141774e9b211','寄懷','趙蕃','宋','宋诗','song-poetry','','[]','風聲雨滴相騷屑，深山深處應凝雪。',64,'全唐诗/poet.song.164000.json','["風聲雨滴相騷屑，深山深處應凝雪。", "豐年未慮米如珠，病骨自安衣百結。", "鄰翁墐戶行徑斷，怪我讀書聲屋徹。", "茲時意緒政復佳，欲往尋梅間何闊。"]'),
('7cf60fb1-c3c7-476d-8616-abfca6ed58df','田家即事','趙蕃','宋','宋诗','song-poetry','','[]','東村鞭牛耕未已，西村車水愁秧死。',64,'全唐诗/poet.song.164000.json','["東村鞭牛耕未已，西村車水愁秧死。", "可憐番人長苦辛，旱乾水溢年年事。", "旱乾水溢天之爲，天意如回一彈指。", "所愁郡縣無良吏，不得辛勤住田里。"]'),
('795070e0-f6a4-44bd-9fd0-5e8d201e9bae','長安行','趙蕃','宋','宋诗','song-poetry','','[]','東街女兒誰家子，有名籍籍長安市。',96,'全唐诗/poet.song.164000.json','["東街女兒誰家子，有名籍籍長安市。", "不知身失不自回，顧侈金珠炫羅綺。", "西街貧女夫何如，年長不見行媒車。", "有時視倡獨歎息，從之不可翻躊躇。", "傷哉彼倡不自醜，顧嘲貧女爲牛後。", "此時貧女將何言，嫁與不嫁懸諸天。"]'),
('1b2bf53c-e74d-4085-99e7-220d4f9fd387','清水道上望隔山桃花盛開','趙蕃','宋','宋诗','song-poetry','','[]','青山深處桃花紅，應有幽人住此中。',64,'全唐诗/poet.song.164000.json','["青山深處桃花紅，應有幽人住此中。", "又疑山深人迹絕，封泥彈核如芙蓉。", "樹成花開亦既實，實落山中還自植。", "年年歲歲長芳株，人人錯認神仙宅。"]'),
('60347673-4c7b-4c7b-9348-e31b24f28239','偶得牡丹之白者賦之','趙蕃','宋','宋诗','song-poetry','','[]','梅花當冬吐冰雪，古今已復稱高潔。',96,'全唐诗/poet.song.164000.json','["梅花當冬吐冰雪，古今已復稱高潔。", "春風草木爭寵光，爾乃白乎無得涅。", "屈原放逐楚江濱，山高水疾誰與鄰。", "商山山中四老人，漢且終辭肯事秦。", "白山茶有涪翁賦，蓮自遠公仍白傅。", "數公已矣不可作，風雨明朝埋玉樹。"]'),
('7e95a466-239b-46bd-adc7-ec5028db3256','見負梅趨都城者甚夥作賣花行','趙蕃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔人種田不種花，有花只數西湖家。',66,'全唐诗/poet.song.164000.json','["昔人種田不種花，有花只數西湖家。", "祇今西湖屬官去，賣花迺亦遍戶戶。", "種田年年水旱傷，種花歲歲天時禳。", "安得家家棄花只糴米，塵甑炊香勝旖旎。"]'),
('f9c28f65-aa0f-4cb9-b293-6198552b9458','對菊成詠','趙蕃','宋','宋诗','song-poetry','','[]','城陰何有唯蓬翳，爲乏人工欠除薙。',64,'全唐诗/poet.song.164000.json','["城陰何有唯蓬翳，爲乏人工欠除薙。", "連朝陰雨早始晴，照眼黄花驚嘒嘒。", "結根失所少陵悲，晚何用好退之詩。", "那知是物有奇操，要並歲寒松柏知。"]'),
('e392327c-47e0-4274-ac1e-232f1895bf83','風雨兼旬繼之以雪作惜梅歎','趙蕃','宋','宋诗','song-poetry','','[]','至寶橫道驚路人，明珠白璧天不珍。',66,'全唐诗/poet.song.164000.json','["至寶橫道驚路人，明珠白璧天不珍。", "風饕雪虐雨更打，委珠碎璧同泥塵。", "天生人材怨不以，天亦何心及於爾。", "不然明珠白璧當愛惜，忍使飄零至于此。"]'),
('2e1cc37f-2c06-4b82-b9bb-219865a25bbd','有懷故居梅花','趙蕃','宋','宋诗','song-poetry','','[]','梅花照耀山下村，舊居不返傷我魂。',128,'全唐诗/poet.song.164000.json','["梅花照耀山下村，舊居不返傷我魂。", "破苔履迹誰復掃，定要風雨參成昏。", "祇今環堵聊自存，亦有獨樹背竹園。", "驟看疑是雲母薄，細睇迺識玉體溫。", "裴回竟使不忍去，步遶直欲窮晡暾。", "是中有句鬰莫吐，如禪未悟參多門。", "須臾月上花且落，四顧無人相與言。", "經年取酒藉地飲，飲醉更覺山林尊。"]'),
('872e5202-3114-4948-b94d-64cfff5c8e0b','次韻斯遠折梅之作','趙蕃','宋','宋诗','song-poetry','','[]','春歸寂寞誰與傳，梅開年後并臘前。',160,'全唐诗/poet.song.164000.json','["春歸寂寞誰與傳，梅開年後并臘前。", "江南此物處處有，不論水際仍山顛。", "爲之著句道所以，點檢敗篋曾年年。", "七言五字古復律，非獨愛渠還自憐。", "見君新就之長篇，有如潢潦投清漣。", "俗間比擬不足道，老大更爭兒女妍。", "山行蠟屐要上下，水泛艇子思延緣。", "豈惟病思待一洗，直恐高致成輕捐。", "定逢縞衣露皎潔，仍聽翠羽啁清圓。", "賦成從使筆併禿，飲雋更須瓶屢眠。"]'),
('1d1d140f-fc8f-4bb9-8c4b-0bc1611545d9','對隔壍梅贈斯遠','趙蕃','宋','宋诗','song-poetry','','[]','梅開壍邊勿渠陋，倚竹長年固成瘦。',64,'全唐诗/poet.song.164000.json','["梅開壍邊勿渠陋，倚竹長年固成瘦。", "風期喚得高人就，幾度行看仍落齅。", "是花佳處絕難摹，思雖宛轉終不如。", "我詩有媿渭南趙，君句自續東湖徐。"]'),
('2e11cd57-586e-4ff6-a213-700f9668abe2','憶山中梅送大聲瞻軍赴調','趙蕃','宋','宋诗','song-poetry','','[]','江南梅蕊臘前破，憶我林園疲坐卧。',64,'全唐诗/poet.song.164000.json','["江南梅蕊臘前破，憶我林園疲坐卧。", "君行正過玉溪邊，雪後應餘欲殘朶。", "君既不飲何以酬，詩成寄我無悠悠。", "得意歸來應不晚，雨肥紅綻綠陰稠。"]'),
('a85f8a05-0d1e-4c66-bead-2a1ed8a0a982','初五夜再過昨逢之梅乃酒家保也','趙蕃','宋','宋诗','song-poetry','','[]','前日日莫相逢初，今日日斜來看再。',48,'全唐诗/poet.song.164000.json','["前日日莫相逢初，今日日斜來看再。", "鬨然肯作時世粧，蕭然自有無人態。", "題詩欲報故人知，爲爾停驂一杯買。"]'),
('3b2ea9f5-aa39-4a5e-984c-232cf73dd098','初十日早起','趙蕃','宋','宋诗','song-poetry','','[]','北風動地木欲折，雨既不成當作雪。',96,'全唐诗/poet.song.164000.json','["北風動地木欲折，雨既不成當作雪。", "黄昏側聽到鷄鳴，纔有飄蕭興騷屑。", "雖然風力猶未止，雨耶雪耶知孰是。", "幾將被褐出門看，不待足前成辟易。", "遲明迺知雪未就，雨亦甚微風獨吼。", "晨炊未暇詢無有，亟令問訊鄰家酒。"]'),
('9eff15f8-c83a-42a4-b1fe-6383750a6f7d','聞鳩有感','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','可憐鳩拙安無棲，雨來逐婦晴呼歸。',64,'全唐诗/poet.song.164000.json','["可憐鳩拙安無棲，雨來逐婦晴呼歸。", "我行願晴不願雨，憂樂殆與鳩同機。", "長安通衢多顯位，長江大艑謀崇利。", "我圖非利亦非名，胡爲役役無寧歲。"]'),
('f2816a6f-6c73-4072-9f9d-59485a0fdc5f','田家歎','趙蕃','宋','宋诗','song-poetry','','[]','春欲耕時天不雨，小雪不能濡旱土。',128,'全唐诗/poet.song.164000.json','["春欲耕時天不雨，小雪不能濡旱土。", "辛勤僅得遍鉏耰，浸種可憐溝脈縷。", "忽然一雨催插秧，東阡西陌青相望。", "謂茲勞逸足報補，豈知亢旱愁秋陽。", "高田已分鹵莽取，下田庶幾十八九。", "柰何雨勢反作淫，令我痛心仍疾首。", "我曹饑餒無足悲，不死會值豐登時。", "所嗟官吏不相察，借租日日來符移。"]'),
('5dc38fb7-2381-4c76-b84b-45152aabf595','有懷江南作田家忙','趙蕃','宋','宋诗','song-poetry','','[]','南風吹動原頭草，秧老麥收蚕向了。',64,'全唐诗/poet.song.164000.json','["南風吹動原頭草，秧老麥收蚕向了。", "田家政用此時忙，不問兒童與翁媼。", "五溪之俗殊江南，刀耕火種不知蠶。", "勸農未有陶蘇句，俗陋不改奚多談。"]'),
('99835958-7f7b-434a-9d8a-49b44340a20f','田家行二首  其一','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雨聲颯颯斷復來，間作隠隠兼出雷。',64,'全唐诗/poet.song.164000.json','["雨聲颯颯斷復來，間作隠隠兼出雷。", "田家作苦樂不哀，拔秧插田政時哉。", "誰知有客洞庭上，船破篷疎蔽無障。", "何如雨笠與煙蓑，相逐田伴歌田歌。"]'),
('90964ef3-6788-4fe5-a1e8-33976daca1ab','田家行二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','江東聞田歌，湖北聽田鼓。',60,'全唐诗/poet.song.164000.json','["江東聞田歌，湖北聽田鼓。", "鼓聲于以相疾徐，歌調因之慰勞苦。", "東山絲竹仍携妓，風月鳴蛙勝鼓吹。", "何如田鼓與田歌，烏烏坎坎安而和。"]'),
('2601dc4e-a74d-419c-a7c3-193c65f52296','苦雨感歎而作','趙蕃','宋','宋诗','song-poetry','','[]','不肯官嶺海，頗畏瘴癘虞。',104,'全唐诗/poet.song.164000.json','["不肯官嶺海，頗畏瘴癘虞。", "誰知江西山盡處，亦有嵐霧畫若晡。", "五斗何所直，千金不保軀。", "司空城旦困刀筆，尺籍伍符愁鉞鈇。", "吁嗟此賊蠭蟻如，飛煙一炬斯無餘。", "奈何徵兵動州閭，紛然亦復勞轉輸。", "戍柵如櫛猶恐疎，江徼一朝成塞隅。"]'),
('bc1847ca-dfa1-45ca-8ea1-ec23777775f6','連雨即事','趙蕃','宋','宋诗','song-poetry','','[]','官居如穴還如巢，數間編竹仍結茅。',64,'全唐诗/poet.song.164000.json','["官居如穴還如巢，數間編竹仍結茅。", "淫霖更值七八月，凉冷不待秋冬交。", "豈惟寒近感蟋蟀，更爲役久悲蠨蛸。", "偶茲得句付排悶，嬾復多言强解嘲。"]'),
('a5888cd0-567d-434d-8887-23fa6ea0f3c1','長江','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江滾滾來無盡，順流逆挽紛成陣。',64,'全唐诗/poet.song.164000.json','["長江滾滾來無盡，順流逆挽紛成陣。", "誰令轉側入漕河，舟似鳧鷖亦難進。", "長江漕河唇齒間，去留異態空浩歎。", "孰能稍激長江水，顧使漕河舟亦起。"]'),
('e0707d4a-f48f-42da-adc0-da2e1268041c','晚自白沙投宿側水','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','白沙漫漫風肆威，白沙道上行人稀。',64,'全唐诗/poet.song.164000.json','["白沙漫漫風肆威，白沙道上行人稀。", "征衣攝葉馬力微，問胡不歸驅以饑。", "浮家洞庭書未來，腸九回兮朝莫思。", "莫投道店鷄已栖，一杯自慰無嫌醨。"]'),
('243397f9-2918-40cc-8c95-41f39def2e72','題劉炳先兄弟怡齋','趙蕃','宋','宋诗','song-poetry','','[]','晦庵貽我書滿紙，爲說君家好兄弟。',128,'全唐诗/poet.song.164000.json','["晦庵貽我書滿紙，爲說君家好兄弟。", "人言是公輕許可，我謂親仁乃渠事。", "客遊偶爾過君廬，中有誠齋榜怡字。", "斯人許可蓋不輕，何事齋名契於季。", "嗟余夙昔兩公遊，與君常恨風馬牛。", "何知一見辱傾蓋，四海兄弟寧待求。", "有弟有弟江南州，尺書斷絕安與不。", "因君使我增離憂，一夜夢逐滄波鷗。"]'),
('87ae3f26-7759-4159-a924-c8a2a319a772','三兄既見過喜而賦此','趙蕃','宋','宋诗','song-poetry','','[]','村居不記元夕期，田蠶鐙火俗異宜。',128,'全唐诗/poet.song.164000.json','["村居不記元夕期，田蠶鐙火俗異宜。", "但餘林月光陸離，所期不來空賦詩。", "明朝風作後日雪，祇道來期中已輟。", "今朝小霽泥未乾，或報門前有車轍。", "我窮政爾落荒山，跫然忽復解我顔。", "平生交舊固多矣，風味如此端亦慳。", "梅雖已謝蘭可掘，有酒縱漓醅可撥。", "爲子一醉莫深辭，更要好詩書歲月。"]'),
('b70b7026-5ef5-4113-b54f-b90989501c82','次韻畢叔文苦旱歎','趙蕃','宋','宋诗','song-poetry','','[]','爾何不歸乎故宇，却向殊方書閔雨。',176,'全唐诗/poet.song.164000.json','["爾何不歸乎故宇，却向殊方書閔雨。", "江東數月不得書，憶弟看雲在何許。", "舊傳重湖北之北，米賤真成等泥土。", "如何比歲公及私，衰竭不能堪再鼓。", "貧家一飯有併日，遠市朝炊或亭午。", "朱門但知粱可厭，我輩翻嫌字難煮。", "晚且禾秀早向實，舂簸不須逾處暑。", "胡爲旱勢復如此，坐致詩人形苦語。", "如聞巫覡有通靈，肸蠁似逢人問嫗。", "前朝一雨苦不難，况今靡神無不舉。", "會當勞以三日霖，綠浪黄雲看掀舞。"]'),
('93762a20-b054-428a-9857-2f6bac403532','呈李齊之文學','趙蕃','宋','宋诗','song-poetry','','[]','大机石頭雲自橫，釣魚臺下潮初平。',64,'全唐诗/poet.song.164000.json','["大机石頭雲自橫，釣魚臺下潮初平。", "側聞左蠡春水生，蛟龍改穴黿鼊爭。", "扁舟夜泊鄔江尾，空山月出中夜起。", "政須傑句彈壓此，乃祖詩成會泣鬼。"]'),
('33551de7-1363-44c3-8328-7c41119bbf6b','贈唐德輿通判','趙蕃','宋','宋诗','song-poetry','','[]','憶昔中原全盛日，猶推巴蜀多人物。',216,'全唐诗/poet.song.164000.json','["憶昔中原全盛日，猶推巴蜀多人物。", "况今王氣在東南，北望中原渺蕭瑟。", "先生隠居談典墳，博士乃有垂世文。", "內前之行傳未了，鈎黨已到白鷺羣。", "舍人父子自知己，紅藥翻殘棠屢憇。", "逮公四世傳以是，池上鳳毛宜翽翽。", "胡爲一再纔別乘，縱說翺翔豈其稱。", "雞羣牛皂匪殽雜，玉水珠淵自輝映。", "維公大父我曾祖，紹聖同年蒙主恩。", "我今流落不足論，附驥詎敢儕青雲。", "鄱陽別去今三歲，邂逅從公寧自意。", "幾思著句道所以，筆力甚孱無好思。", "今辰何以爲公壽，四世斯文端不朽，匪蜀眉山還有否。"]'),
('485c7a64-2917-4924-adfb-67a4ff98b46c','簡子崧時丞建德','趙蕃','宋','宋诗','song-poetry','','[]','石田渡口鉦鼓鳴，憶同居民送君行。',160,'全唐诗/poet.song.164000.json','["石田渡口鉦鼓鳴，憶同居民送君行。", "至今是邦數廉吏，君與韋陸俱其名。", "別來憶君已騰趠，故人無復思漁釣。", "豈知更作畿縣丞，未免流俗輕嘲傲。", "如君爲學未易論，淵源固自知所尊。", "使其策足上臺省，憸人吉士當以分。", "韜藏自是玉之美，奈何有道貧賤恥。", "漢宣且識東海蕭，吾君聰明豈不爾。", "願君强飯力自持，九十半百古語之。", "扁舟僅可頃刻住，便風催人當語離。"]'),
('ca68c77c-0f63-41b6-aedb-73a8c22fa0b1','懷昔','趙蕃','宋','宋诗','song-poetry','','[]','君不見昔日朗州刺史賢何多，考功右史名不磨。',141,'全唐诗/poet.song.164000.json','["君不見昔日朗州刺史賢何多，考功右史名不磨。", "當時豈亦爲名計，民自思之相與紀。", "如何後世異於是，我自爲我民爲爾。", "但憂潦浸務安居，不慮旱年當使水。", "一時掘鑿恐不深，今日車戽乃無地。", "常聞退之勇詞訟風伯，甫也亦欲鞭起雷公洗吳越。", "我知二子屬風雷，引喻政合離騷轍。", "雖然柳州蜡說義甚顯，神且逃難吏何免。"]'),
('8db0e5e8-9cc5-4c39-a6c4-fd87733c0596','周愚卿用荀卿氏之語以遇名齋從余求詩爲賦古意一首','趙蕃','宋','宋诗','song-poetry','','[]','世俗爭知競冶容，紛紛牆穴交相從。',67,'全唐诗/poet.song.164000.json','["世俗爭知競冶容，紛紛牆穴交相從。", "誰知亦有秉正色，奉養辛勤供織舂。", "過期不嫁心不悔，偃蹇數夫終德配。", "君不見蘭生林下久含章，得時可以充君佩。"]'),
('259a2843-ab70-4b40-a256-5177efd1d83f','遂初泉','趙蕃','宋','宋诗','song-poetry','','[]','荆溪溪水清無底，下有亂石白齒齒。',192,'全唐诗/poet.song.164000.json','["荆溪溪水清無底，下有亂石白齒齒。", "東坡先生所卜居，想像神遊應不死。", "後來高躅嗣者誰，東門孫氏賢塤箎。", "不惟文采風流是，釀酒喜客俱似之。", "憶昨爲官在吳里，三年徵逐一日爾。", "詩傳活法付乃兄，酒有名方屬吾弟。", "當時釀熟曾入唇，大孫絕嘆能逼人。", "世間名賢久難辨，顧恐石室來亂真。", "遂初自是渠家賦，大孫取以名其住。", "我今以是謚君酒，要使交情不忘故。", "嗟予老矣百不如，有竹萬箇中藏書。", "願從吾徒授此術，歸去傭田親種秫。"]'),
('f4fc5ea1-b2d4-4512-a4ed-d29ff7831776','次韻曾季永乞筍','趙蕃','宋','宋诗','song-poetry','','[]','鄙夫食肉書生菜，要是均爲口腹賣。',64,'全唐诗/poet.song.164000.json','["鄙夫食肉書生菜，要是均爲口腹賣。", "籜龍雖美亦菜流，我苦嗜之還自怪。", "君家作屋溪上篁，想見春風參短長。", "柰何反向寒廳乞，一束未能成報章。"]'),
('2ae83c7d-c36a-44d9-b209-602dc61b5710','九月晦日','趙蕃','宋','宋诗','song-poetry','','[]','經旬不飲仍廢詩，不唯多故病使之。',96,'全唐诗/poet.song.164000.json','["經旬不飲仍廢詩，不唯多故病使之。", "黄花潦倒烏桕赤，窮邊物色分付誰。", "空庭索索枯葉吹，氣象如我苶且羸。", "强思把筆與摹寫，安得豪壯生毛錐。", "秋冬之間穫稻時，日脚苦翳雨脚垂。", "鳩鳴遠樹蛙吠坎，宜我病骨疲支持。"]'),
('07033e5b-a7ef-4299-bb0b-d3b678f51666','同成父過章泉用前韻示之','趙蕃','宋','宋诗','song-poetry','','[]','頻年盡室依此竹，意謝侏儒奉囊粟。',130,'全唐诗/poet.song.164000.json','["頻年盡室依此竹，意謝侏儒奉囊粟。", "今當舍竹去作吏，竹爲嘿嘿如抱辱。", "嗟我作吏豈俗徒，雖非計然念則熟。", "如聞西江之水深無底，可以濯纓仍濯足。", "昔人一爲功名誤，置碑且慮變陵谷。", "那知立名自有道，未妨痛飲離騷讀。", "人生于世譬于味，馬肝不食寧非肉。", "弟當進德使有聞，兄亦自期無碌碌。"]'),
('aafd44af-9a04-470d-8828-dc552f8ce422','比見愚卿于廬陵出示楊謹仲詩卷中及其弟魯卿問其所在云携琴往嶽麓度夏今日見楊謹仲又云其弟卓卿近過此奉其母往游洪之西山迴途游閣皂乃歸爾余方困于道途有歎于其人作詩須到吉示愚卿及二君云','趙蕃','宋','宋诗','song-poetry','','[]','廬陵得交君弟兄，楊子詩中稱魯卿。',128,'全唐诗/poet.song.164000.json','["廬陵得交君弟兄，楊子詩中稱魯卿。", "問云携琴嶽麓行，歸期去日云秋清。", "今晨復見楊子面，爲言卓卿近相見。", "玉隆閣皂兩仙山，遊以娛親趁鮮健。", "我時聞之與楊子，嘖嘖歎息久不已。", "我方五斗困塵埃，渠亦棲遲一丘底。", "魯卿卓卿真愈人，枉道儒冠解誤身。", "異日名山倘行遍，卧圖好學宗少文。"]'),
('75b204f7-eaf6-408f-8db7-6e08bf9c5129','李大椿伯壽見示寶劍歌答之','趙蕃','宋','宋诗','song-poetry','','[]','李子久不調，慷慨多雄辭。',96,'全唐诗/poet.song.164000.json','["李子久不調，慷慨多雄辭。", "題爲寶劍篇，贈我何足知。", "我爲讀數過，因之重嗟咨。", "尚方願賜有朱雲，櫑具带劍有不疑。", "雲也安能斬張禹，曼倩脫或逢勝之。", "君才固有用，我病且復衰。", "誰能長佩矜陸離，但取短鋏歌歸來。"]'),
('633770f1-fc66-4160-908d-54e9939d5a76','新桂林戶曹甘叔異過余於津亭留以小飲論文縣僚有招之者遂敗此興既夕作詩呈之','趙蕃','宋','宋诗','song-poetry','','[]','平生所聞甘叔異，半日爲泊寶氣亭。',64,'全唐诗/poet.song.164000.json','["平生所聞甘叔異，半日爲泊寶氣亭。", "逢迎稍稍昏忘集，誦說矻矻文章聽。", "其誰呼渠紅裙飲，遣我負此雙玉瓶。", "臨流不寐待月上，漫見紫翠橫山屏。"]'),
('8bf0263a-c905-4bb6-a4e4-6eb0520d0213','讀去非有行集','趙蕃','宋','宋诗','song-poetry','','[]','山嵯峩，江洶湧，舟疾如飛得無恐。',64,'全唐诗/poet.song.164000.json','["山嵯峩，江洶湧，舟疾如飛得無恐。", "忽來何處有竹編，勢與江山欲爭勇。", "回思往日曾倡酬，我詩島嶼縈微流。", "鶴鳬長短天所付，追隨恐失邯鄲步。"]'),
('57ee0319-cdb5-461f-9c0c-04c31a92683f','寄題山居','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山居爲山何所如，非灊非皖非匡廬。',144,'全唐诗/poet.song.164000.json','["山居爲山何所如，非灊非皖非匡廬。", "問云非山何所居，屋中主人山中徒。", "當簷屹立幾丈餘，亦有竹樹相盤紆。", "朝聽鶴吟暮猿呼，那知門外臨通衢。", "或聞此語謂我誣，答以君意誠守株。", "人間有國名華胥，其往初不因舟車。", "神游倏忽已即塗，晨雞喚覺猶蘧蘧。", "山名無乃類此歟，胸中有山無地無。", "朱門蓬戶何別區，參前見處成工夫。"]'),
('3c35a8ad-7625-4f98-a131-9a2b9e581593','季承作詩敏捷而工因成長句','趙蕃','宋','宋诗','song-poetry','','[]','我詩縱疾無多工，君詩嚴甚仍匆匆。',64,'全唐诗/poet.song.164000.json','["我詩縱疾無多工，君詩嚴甚仍匆匆。", "君酬我唱輒媿我，野鶩欲睨天邊鴻。", "平生交游不乏此，快筆相追屬吾子。", "莫愁風雨留滯人，不爾歸裝孰慰貧。"]'),
('6c6d70e7-c260-4ce7-b98f-032a1c61f140','王彥博愚齋','趙蕃','宋','宋诗','song-poetry','','[]','王郎立志誰能儗，適遠寧爲中道止。',96,'全唐诗/poet.song.164000.json','["王郎立志誰能儗，適遠寧爲中道止。", "愚齋之名豈真愚，用心蓋欲師顔子。", "聖門之徒三千人，回獨好學學何事。", "簞瓢陋巷不自貧，看此力量如何爾。", "願君勿作歲月計，有爲要之亦若是。", "它年究竟所歸宿，莫負名齋本來意。"]'),
('fa286e50-8584-4573-b454-d5c21a8b6263','畢叔文借示郭峽州詩二軸志其所見','趙蕃','宋','宋诗','song-poetry','','[]','真行黄家元祐脚，隠帙奧篇窮秘閣。',64,'全唐诗/poet.song.164000.json','["真行黄家元祐脚，隠帙奧篇窮秘閣。", "計其胸中所餘地，數百猶能君輩著。", "中朝文物政須此，刺史郎官謾今昨。", "腦脂遮眼失乘黄，安得金篦令刮膜。"]'),
('6a0f66ab-22f5-4318-b379-9b3dafd96179','寄青原山常不輕','趙蕃','宋','宋诗','song-poetry','','[]','吾舅每談方外友，吃吃醉吟長在口。',64,'全唐诗/poet.song.164000.json','["吾舅每談方外友，吃吃醉吟長在口。", "李侯佳句往往有，示我不輕詩數首。", "江湖願見非一日，豈有聞名不相識。", "路頭且向鬰孤臺，却傍釣臺深處回。"]'),
('9d7cf025-beb2-4b26-9707-a670ae2d6985','戲明叔','趙蕃','宋','宋诗','song-poetry','','[]','晚食以當肉，故云巧於貧。',124,'全唐诗/poet.song.164000.json','["晚食以當肉，故云巧於貧。", "我云未若子陳子，掛箔爲圖能事新。", "剪刀不用求諸并，海圖波濤供補紉。", "我今非剪詎可坼，樹林樓閣相參陳。", "君知人窮定何因，政坐百巧逢天嗔。", "天之嗔人或可恕，君更白取遮四鄰。", "雖然我詩聊戲君，天生萬象孰主賓。", "渠如愛惜不我借，聽渠收卷藏箱巾。"]'),
('96137ea7-1b0c-43d8-8b1e-27210e1fa7b7','簡贈祖高上人','趙蕃','宋','宋诗','song-poetry','','[]','黄山別久阻再披，青山路遠終未窺。',64,'全唐诗/poet.song.164000.json','["黄山別久阻再披，青山路遠終未窺。", "忽逢隠靜高監寺，不但學禪仍學詩。", "禪機最上吾不會，詩筆少親今老退。", "青山卧冢謫仙才，功名孰愈凌歊臺。"]'),
('b1497fd1-c1e8-4203-a6cf-4b07481fc915','示表弟沈見可','趙蕃','宋','宋诗','song-poetry','','[]','裴公臺上送入日，道鄉臺上看出雲。',80,'全唐诗/poet.song.164000.json','["裴公臺上送入日，道鄉臺上看出雲。", "窮居偪仄不屢到，拄杖容與能平分。", "江湖鶴髮歎老我，道路繭足嗟夫君。", "畫手政自難隃度，詩裏還嫌異所聞。", "歸來客去雨亦作，此故未易輕談云。"]'),
('5296563f-a700-4ea2-b2e3-95afc2159e78','贈于革去非時爲武陵尉','趙蕃','宋','宋诗','song-poetry','','[]','憶昨聞君謂君老，及見知君得名早。',96,'全唐诗/poet.song.164000.json','["憶昨聞君謂君老，及見知君得名早。", "文章妙處殆夙成，不作揚雄少而好。", "西山南浦飫搜尋，武陵桃源蹔探討。", "諸公識面爭我出，學子聞風競門掃。", "嗟我無聞不足畏，何事相逢亦傾倒。", "論詩未易當韓豪，聊復悲吟似郊島。"]'),
('343d7bff-1793-4ffc-ae37-9244ee2afdf4','次韻元衡病酒伏枕','趙蕃','宋','宋诗','song-poetry','','[]','陰從元日到人日，四體不佳真若病。',80,'全唐诗/poet.song.164000.json','["陰從元日到人日，四體不佳真若病。", "每煩從事與料理，百戰不能圖一勝。", "幾思屏去不復親，茗椀薰爐事閒靜。", "鳴鳩聒聒殊未已，門外雨狂風亦橫。", "此時但覺濁醪賢，少日漫知黄卷聖。"]'),
('5bd9b0ff-86a6-42eb-88d7-1ee4d6e4f1b3','屢遺公擇書且寄以詩皆未得報成父弟書云公擇欲過予再寄','趙蕃','宋','宋诗','song-poetry','','[]','與君相從不知樂，別去懸知頓牢落。',128,'全唐诗/poet.song.164000.json','["與君相從不知樂，別去懸知頓牢落。", "一旬兩詩三附書，底事來音向人邈。", "知君去住良關意，養節忍窮非失計。", "如君豈得終布衣，會有高名耀斯世。", "我居正在千山底，落葉填門吹不起。", "薄醪縱有不敢醉，留待君來相料理。", "惠然過我今其時，籬下菊香驚早衰。", "南山石老有梅樹，要君分韻共哦詩。"]'),
('bb6cd07e-518d-42c3-88de-ab6b5669f193','公擇失期未至再督以詩','趙蕃','宋','宋诗','song-poetry','','[]','作詩有病誰與說，讀書有疑誰與决。',64,'全唐诗/poet.song.164000.json','["作詩有病誰與說，讀書有疑誰與决。", "思君祇在百里間，底事相望若胡越。", "阿連報君有來期，候君未至趣以詩。", "想因故人意戀戀，故作去魯行遲遲。"]'),
('d7cebfa4-e846-409e-8191-8d78752e4ca3','醉呈亦韓','趙蕃','宋','宋诗','song-poetry','','[]','人言唯酒可忘憂，我今醉迺生百感。',64,'全唐诗/poet.song.164000.json','["人言唯酒可忘憂，我今醉迺生百感。", "又言和氣如三春，我迺凄凉似秋慘。", "層冰積雪春接冬，安得陽烏出幽坎。", "紛然桃李吾不關，要與晴窗事鉛槧。"]'),
('497545df-922e-4532-9aaf-f313ab010401','呈審知并簡伯元','趙蕃','宋','宋诗','song-poetry','','[]','溪流渴雨今幾日，夜夜月明翻我室。',224,'全唐诗/poet.song.164000.json','["溪流渴雨今幾日，夜夜月明翻我室。", "江西回首安在哉，南北故憐無定食。", "君居未盡喬木西，舊識鄰牆解作詩。", "如聞過語必更僕，飯寒麈禿忘其饑。", "我思從之不可得，書疏空云間何闊。", "秋風吹我逐轉蓬，何自翩然墮君側。", "君詩比昔更大好，誰謂文章技非道。", "暗中摸索未易窺，衆裏卒逢分眊瞭。", "我昔少小嗜讀書，老類賈胡空識珠。", "潜珍懷寶衣藍縷，見之每輒驚成呿。", "鄭君况是余所長，君得結交真邁往。", "如我何取亦與遊，聽呼殷兄喚張丈。", "兩君抱才終有爲，豐年未厭甘雨遲。", "我無良田蒔嘉穀，取譬但可同蹲鴟。"]'),
('a03ba861-bbc7-4b69-85e9-34e0bba29c90','比作詩從成父索不老泉并簡子進昆仲今日成父送酒與子進子肅子儀詩俱來復次元韻','趙蕃','宋','宋诗','song-poetry','','[]','閑居顧合親杯勺，醉後無人怪疎略。',368,'全唐诗/poet.song.164000.json','["閑居顧合親杯勺，醉後無人怪疎略。", "所嗟故舊不可同，往往茅齋成獨酌。", "兒曹癡疾故我問，問我嗜此有何樂。", "那知是鄉疆場寬，南北東西無住著。", "自應祗覓睡昏昏，不肯留計綬若若。", "浮生倏忽幾許事，今是何必還須昨。", "粗能適意效陶阮，底用策勳追衛霍。", "比年多病苦羸劣，暇日關心惟裹藥。", "誓從歡伯重尋盟，身雖欲前心迺却。", "今晨風日亦佳哉，冬暖如春木陰薄。", "潜魚撥剌鳥緩鳴，得處與我端相各。", "應門走報白衣至，麾去謂爾寧善謔。", "山陰應接已不暇，安得此君仍大嚼。", "須臾負擔置我側，趺坐方穩爲驚作。", "問之遣向阿連家，季也不爽千金諾。", "竟徵西園昔人例，尚病無花來自洛。", "快令汲井洗觥觴，小摘畦蔬失穿屩。", "俱來數紙定誰氏，疑枉續帖摹秘閣。", "抽簪擊鉢一誦之，郊居賦謝東陽約。", "蒼然暮色且欲合，檐光小占明窗拓。", "一時頓有未足道，真是曹劉暗中索。", "預愁取將下雷電，破篋深藏更牢鑰。", "出門仰視天雨霜，良夜初沉雲四冪。"]'),
('ac63e418-dfee-45e0-a572-3b561dd48360','代書寄候毛伯明李叔器康叔臨張王臣','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','巴陵洞庭在何處，我昨移官向其所。',192,'全唐诗/poet.song.164000.json','["巴陵洞庭在何處，我昨移官向其所。", "士所得者毛李康，兼之舊識祁之張。", "毛公學問本伊洛，康李從之亦不惡。", "皆能脫去科舉累，相與探求聖賢事。", "張侯英爽固絕人，亦復降志相友親。", "誰云巴陵洞庭側，有此四士寧易得。", "別來書疏猶數通，辰溪隸與巴陵同。", "張侯再把蒸湘酒，別後不聞安與否。", "遥知歲晚巾屨從，當亦念我窮山中。", "嘗疑昔人重離別，生不相逢死何別。", "偶逢鄂渚行人去，嬾復作書題此句。", "巴陵渺渺若箇邊，何時重泛洞庭船。"]'),
('1ba2d499-1849-421f-b252-55d792cfe12e','次韻斯遠夜歸自溪南之作','趙蕃','宋','宋诗','song-poetry','','[]','憶昔曾聞南渡初，里人最賞白社徐。',96,'全唐诗/poet.song.164000.json','["憶昔曾聞南渡初，里人最賞白社徐。", "君如竹林有雋子，我類犬子睎相如。", "君子何翅一頭出，李杜齊名真是溢。", "唱酬縱許並流傳，安有隋珠混燕石。", "我今鬢髮衰且殘，君乃春秋富未闌。", "後人縱使加譏彈，韓也固豪郊自寒。"]'),
('f551ba98-8958-4c45-a8f0-7d797d438cab','明叔用大字韻作詩見寄復用韻作七言一首答之','趙蕃','宋','宋诗','song-poetry','','[]','人皆言君酒腸寬，我亦畏君詩膽大。',64,'全唐诗/poet.song.164000.json','["人皆言君酒腸寬，我亦畏君詩膽大。", "有時長吸百川空，放意獨掃千軍敗。", "不堪悠悠射馬耳，頗願渺渺騎鯨背。", "問君何如差樂否，願窄江湖低華泰。"]'),
('cf61f172-ab30-479c-a6cb-3acbf31faea9','叔文再用韻賦詩亦復用韻答叔文兼呈伯玉昆仲','趙蕃','宋','宋诗','song-poetry','','[]','杜陵心喜歸茅宇，無復長安歎今雨。',179,'全唐诗/poet.song.164000.json','["杜陵心喜歸茅宇，無復長安歎今雨。", "事雖聊向朱阮論，身蓋自與稷契許。", "胡爲流落不稱意，長鋏貂裘遍南土。", "我嘗細把遺詩讀，大半悲傷聞戰鼓。", "徒空至德至大歷，田車竟絕維庚午。", "區區清{酉栗}與肥羊，何似松根茯苓煮。", "是翁獨破念吾廬，太息明光誰避暑。", "詩窮如是僅得名，欲作詩人寧易語。", "要呼同志共討論，客裏那知酒家嫗。", "便從甕側覓茂世，誰復尊中似文舉。", "共將嶮韻搜崛奇，要逼蛟龍起飛舞。"]'),
('992e87fe-c36c-4a30-ad21-4afb99279799','王伯玉兄弟皆用叔文韻作詩見示答之','趙蕃','宋','宋诗','song-poetry','','[]','春芳凋兮瘖杜宇，留得鳴鳩呼渴雨。',176,'全唐诗/poet.song.164000.json','["春芳凋兮瘖杜宇，留得鳴鳩呼渴雨。", "誰能使我病斯愈，矻矻深思誦詩許。", "朝來剝啄有扣戶，亟起褰裾犯塵土。", "三王詩就俱送與，律應節疏如會鼓。", "我家與君同鄭圃，流落殊方繇丙午。", "豈惟交友歎雲翻，亦有弟兄悲豆煮。", "羨君聚首共文書，憐我離形屢寒暑。", "江南豐歉未可知，安得書來相告語。", "已過有力健如犢，莫待無鬚行似嫗。", "我歸當事力田科，君行寧後公車舉。", "會當過我南山南，門有修篁風屢舞。"]'),
('796d852a-347d-4764-bafa-02eaed0cd288','寄答晁百谷元歸','趙蕃','宋','宋诗','song-poetry','','[]','嗟我與君爲近親，向來未識但有聞。',128,'全唐诗/poet.song.164000.json','["嗟我與君爲近親，向來未識但有聞。", "維夏臨川省伯父，時君束書寄荒村。", "豈知邂逅宜春郡，皎如玉樹相輝映。", "品題舊熟大參文，諸公所作皆傳信。", "探懷贈我一紙詩，功名慷慨真男兒。", "我衰怕作此硬語，君言水漲方東之。", "外家自有文章種，國朝名家居伯仲。", "只今人物未厭多，屬君勉矣加研磨。"]'),
('b429106a-72b6-4762-b161-ecdf4a9e1d38','贈彈琴李睎尹','趙蕃','宋','宋诗','song-poetry','','[]','臨川郡古多奇迹，嚴黎已老裘父沒。',96,'全唐诗/poet.song.164000.json','["臨川郡古多奇迹，嚴黎已老裘父沒。", "江山縱是詩得摹，峩峩洋洋亦其物。", "謫仙幾世之雲仍，平生嗜渠如嗜文。", "光風霽月胸次有，渭北江東脚底頻。", "忽來過我今幾日，擬欲贈行空四壁。", "臨分謾與一篇詩，箏笛紛紛敢謂知。"]'),
('7a01b354-2b03-4f8e-a3e5-1d35b5ca4e3e','九日病中無酒無菊寄王信州老謝丈','趙蕃','宋','宋诗','song-poetry','','[]','有身那識禁酒國，何乃飄零墮其域。',128,'全唐诗/poet.song.164000.json','["有身那識禁酒國，何乃飄零墮其域。", "兒曹强欲覓市酤，頗畏飲灰仍飲濕。", "重令尋菊菊未芳，飛蓬野蔓交加長。", "是知此物貴晚節，無意與俗充杯觴。", "生平浪說愛重九，今年無菊還無酒。", "要携藜杖作登臨，病不如人空竚首。", "使君聞說同王弘，半道邀公絕送迎。", "要見一時賓與主，輿籃侍坐俱門生。"]'),
('bf9252e3-8cb1-41e9-b9cd-118bd2f3ae28','二十七日既浴於乾明庵負暄久之詩示住庵','趙蕃','宋','宋诗','song-poetry','','[]','天公於人元不負，書生何用深追咎。',288,'全唐诗/poet.song.164000.json','["天公於人元不負，書生何用深追咎。", "無衣還可卒歲無，我有大裘聽汝覆。", "吾家縛屋依山址，晏齋之前僅盈咫。", "霜飈卷席不畏渠，羲馭停車吾事已。", "有時携書喚兒曹，坐來和氣生髮毛。", "眼眵豈待金篦刮，背癢不借麻姑搔。", "今年誰令落湖尾，塞向墐戶殊未止。", "移床也擬傍晨光，蓬勃如煙紛欲瞇。", "今我懷抱不自聊，歸𬋖生薪翻縕袍。", "人間萬事固絕望，天賜一暖誰相要。", "茲晨歸悶忽念浴，試覓僧廬渡喬木。", "道人見客如昔遊，爲煮清泉注萬斛。", "須臾一洗垢且空，漸覺表裏俱沖融。", "清虛日來滓穢去，吾貌可瘠神當豐。", "起尋冠服風動腋，却向茅簷親野日。", "恍然墮我晏齋前，鳥語不聞山四寂。", "道人領客殊忘倦，茗盌薰爐共閒燕。", "爲言炙背頗樂否，此味可須天子獻。"]'),
('6299c190-c441-4599-a762-d199e7e1b08f','壬寅元日','趙蕃','宋','宋诗','song-poetry','','[]','壯歲頻羈宦，王春又履端。',48,'全唐诗/poet.song.164000.json','["壯歲頻羈宦，王春又履端。", "東占風料峭，北驗斗闌干。", "歷數堯年永，條章漢詔寬。", "殘生侶麋鹿，何路接鵷鸞。"]'),
('89090a52-0b6c-40c5-a136-3b30024e866d','人日感懷因寄玉山親舊并以示當塗溧陽諸表弟','趙蕃','宋','宋诗','song-poetry','','[]','唐人重人日，往往見于詩。',48,'全唐诗/poet.song.164000.json','["唐人重人日，往往見于詩。", "孰謂風流遠，聊須著語追。", "憑高縱無地，念遠得忘思。", "欲寄江東弟，斷腸梅滿枝。"]'),
('8035da71-098d-4abe-b2d5-da1436f0b7a1','寒食日呈慶伯','趙蕃','宋','宋诗','song-poetry','','[]','浩浩風兼雨，紛紛柳與花。',48,'全唐诗/poet.song.164000.json','["浩浩風兼雨，紛紛柳與花。", "不知春事減，但覺旅愁加。", "嗜酒誰明意，耽詩老不佳。", "無家對寒食，相與重成嗟。"]'),
('9c5a6358-0362-4e9b-a9cf-cc3df4c152e7','又呈慶伯','趙蕃','宋','宋诗','song-poetry','','[]','下里又寒食，寒居猶去年。',48,'全唐诗/poet.song.164000.json','["下里又寒食，寒居猶去年。", "蕭條花不見，牢落病仍纏。", "强起陪親友，題詩未究宣。", "方欣好天色，雲氣復油然。"]'),
('2c2c7921-ae29-4322-9f34-e10f9b49127f','詠牡丹','趙蕃','宋','宋诗','song-poetry','','[]','洛下誰移致，江南種得成。',48,'全唐诗/poet.song.164000.json','["洛下誰移致，江南種得成。", "高株非自接，徑尺信能盈。", "恨匪堅牢質，漫令城國傾。", "未宜貧舍有，風起莫多驚。"]'),
('3dca73ec-9a26-43b0-ba15-766e44c49431','三月二日同明叔過從禮觀牡丹','趙蕃','宋','宋诗','song-poetry','','[]','新晴喚我出，負郭看花來。',48,'全唐诗/poet.song.164000.json','["新晴喚我出，負郭看花來。", "窈窕欄檻入，咄嗟尊俎開。", "嫣然同午醉，老矣怕春催。", "身羨雙飛蝶，翩翩去却回。"]'),
('b70391c5-ff4e-4a48-80ec-17a14f5c892e','瓶梅','趙蕃','宋','宋诗','song-poetry','','[]','驟逢初粲粲，儼立更亭亭。',48,'全唐诗/poet.song.164000.json','["驟逢初粲粲，儼立更亭亭。", "汲井洗醉盡，倦譚揮麈停。", "搜詩未窮妙，能畫孰遺形。", "風日人間苦，飛僊不假翎。"]'),
('462e02cd-afa9-4cef-ae48-6c15b47e7077','再題','趙蕃','宋','宋诗','song-poetry','','[]','舊歲只五日，晚梅能幾枝。',48,'全唐诗/poet.song.164000.json','["舊歲只五日，晚梅能幾枝。", "婆娑一尊酒，陶冶數篇詩。", "窗靜游蜂寂，簷深立雀窺。", "書齋寂寞裏，藉爾對支頤。"]'),
('3112266a-e282-407a-b40e-1e9c383fae99','題堂前梅花','趙蕃','宋','宋诗','song-poetry','','[]','廢宅委塵埃，梅花亦自開。',48,'全唐诗/poet.song.164000.json','["廢宅委塵埃，梅花亦自開。", "九泉無起日，雙鬢有新摧。", "索莫生何理，飄零句易哀。", "若爲歸去晚，茅屋老蒼苔。"]'),
('093a31df-ad83-442f-9c37-6d9cb11244d5','客長沙邢園堂下梅花一萼先開有懷成父斯遠二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','老樹發青枝，晴多雨亦奇。',48,'全唐诗/poet.song.164000.json','["老樹發青枝，晴多雨亦奇。", "一花成獨破，病眼得先窺。", "又作殊方見，還成寄遠詩。", "不知閩與淛，何處念乖離。"]'),
('d2219985-5795-460a-8b0d-902fb91c7f76','客長沙邢園堂下梅花一萼先開有懷成父斯遠二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','亦到溪南否，還能念我不。',48,'全唐诗/poet.song.164000.json','["亦到溪南否，還能念我不。", "梅花今次第，客子政飄浮。", "師法真難得，微官盍罷休。", "饑寒還累我，寤寐只關憂。"]'),
('1bc0db32-e0cd-41db-95ed-94afc1c58f46','咏梅六首  其一','趙蕃','宋','宋诗','song-poetry','','[]','十月江南路，梅花次第開。',48,'全唐诗/poet.song.164000.json','["十月江南路，梅花次第開。", "殊方孤病眼，高興闕詩材。", "幾日風鳴屋，連宵雨浥埃。", "曾令四郊覓，未見一枝來。"]'),
('802e2bdd-cbbd-4b00-bbfe-456a7a6a08cc','咏梅六首  其二','趙蕃','宋','宋诗','song-poetry','','[]','臘前能幾日，年後不多時。',48,'全唐诗/poet.song.164000.json','["臘前能幾日，年後不多時。", "五嶺無千里，東亭共一陲。", "胡爲欺北客，未即見南枝。", "或謂冰霜候，還憂衣褐爲。"]'),
('1999c84c-f40f-4d11-96b5-387f648b73cd','咏梅六首  其三','趙蕃','宋','宋诗','song-poetry','','[]','老眼從昏翳，高情未脫遺。',48,'全唐诗/poet.song.164000.json','["老眼從昏翳，高情未脫遺。", "雖云謝能賦，政爾動相思。", "彼自無妍鄙，渠寧可磷緇。", "猶須藉名勝，相與厚襟期。"]'),
('d9d09c99-3ebe-44c7-918c-2cc86cb6a7e5','咏梅六首  其四','趙蕃','宋','宋诗','song-poetry','','[]','縱乏幽人宅，猶餘大樹祠。',48,'全唐诗/poet.song.164000.json','["縱乏幽人宅，猶餘大樹祠。", "带山仍带水，宜飲亦宜詩。", "勿待全開後，當乘半放時。", "昏昏廓陰霧，皎皎上朝曦。"]'),
('b25fc3ff-62b3-4e84-9f33-6d72c13fefc8','咏梅六首  其五','趙蕃','宋','宋诗','song-poetry','','[]','溪北溪南路，山前山後居。',48,'全唐诗/poet.song.164000.json','["溪北溪南路，山前山後居。", "興來隨杖屨，意到總林廬。", "觸目常懷爾，關心相憶余。", "雖然風月趣，千里故非疎。"]'),
('6b2edc21-1177-4f7e-b352-a04556a0f0fd','咏梅六首  其六','趙蕃','宋','宋诗','song-poetry','','[]','幾日寒如許，梅花好在不。',48,'全唐诗/poet.song.164000.json','["幾日寒如許，梅花好在不。", "汝雖甘寂寞，吾自念深幽。", "靜塢無車馬，清溪足鷺鷗。", "何當細扶杖，隨處小遲留。"]'),
('23871cfd-8208-4ba0-a853-8bfe7b72a3a6','十六日雨中憶梅花','趙蕃','宋','宋诗','song-poetry','','[]','莫問帆遲速，且看山晦明。',48,'全唐诗/poet.song.164000.json','["莫問帆遲速，且看山晦明。", "賦詩忘意索，圖畫得天成。", "白髮應無種，流行詎有程。", "清霜可期至，郢樹合爭榮。"]'),
('8780ee18-aec0-4a57-95f5-98c7abc10a5d','次韻何叔信書齋梅花','趙蕃','宋','宋诗','song-poetry','','[]','坐對窗中帙，起尋簷外花。',48,'全唐诗/poet.song.164000.json','["坐對窗中帙，起尋簷外花。", "因之觀物化，藉以發天葩。", "一笑故無恙，百年終匪他。", "端殊苦心士，志失鬢先華。"]'),
('1ce36a3f-3d20-4e02-982e-23948458eeb2','嚴先輩詩送紅梅次韻','趙蕃','宋','宋诗','song-poetry','','[]','盡道梅花白，能紅又一奇。',48,'全唐诗/poet.song.164000.json','["盡道梅花白，能紅又一奇。", "渾疑丹換骨，不是酒侵肌。", "看此敷腴色，思儂少壯時。", "盛年雖不再，猶擬歲寒知。"]'),
('4172cd68-fd81-4b36-ba2f-83290249669c','植梅一株于廳事之後招丞及明叔同觀倪嚴二先輩送酒陳簿送茶因以成集','趙蕃','宋','宋诗','song-poetry','','[]','有竹似吾家，無梅覺欠花。',48,'全唐诗/poet.song.164000.json','["有竹似吾家，無梅覺欠花。", "移將香索莫，來伴綠交加。", "好事適餽酒，詩情仍得茶。", "相過况非遠，勝處莫令賒。"]'),
('bf4db98f-a2a5-432e-bef4-c9b314199151','和何叔信別種蠟梅韻','趙蕃','宋','宋诗','song-poetry','','[]','不識梅當牖，唯知竹映牆。',48,'全唐诗/poet.song.164000.json','["不識梅當牖，唯知竹映牆。", "脫成元似蠟，染就却殊黄。", "自是風神秀，寧由肌骨香。", "木犀雖瑣碎，品色庶同方。"]'),
('342f8b6a-3635-4d02-a438-4e376acef0c2','師契約看白蓮','趙蕃','宋','宋诗','song-poetry','','[]','勿陋盆爲沼，能生徑尺蓮。',48,'全唐诗/poet.song.164000.json','["勿陋盆爲沼，能生徑尺蓮。", "乍開冰刻鏤，欲謝羽蹁躚。", "得意疑來鷺，凌波欲問仙。", "平生苕霅興，擬借葉爲船。"]'),
('b0634ad8-4151-498e-a62a-9c6a2fa20fdb','叢桂','趙蕃','宋','宋诗','song-poetry','','[]','漫道希爲貴，那知夥不奢。',48,'全唐诗/poet.song.164000.json','["漫道希爲貴，那知夥不奢。", "江南故多桂，秋仲舉敷花。", "往往因人好，蕭蕭得句佳。", "人誰不種菊，千載但陶家。"]'),
('6b8020fd-b8f0-40e9-b636-683e561fe362','元之去非來邢園折牡丹酴醿碧桃以去','趙蕃','宋','宋诗','song-poetry','','[]','花取三英粲，時高兩玉人。',48,'全唐诗/poet.song.164000.json','["花取三英粲，時高兩玉人。", "毋嫌應接費，要悟色香真。", "詩定一題紙，酒應多入脣。", "病夫方坐穩，幽獨恐傷神。"]'),
('92207190-5a4c-4a93-99bd-239853287023','理菊','趙蕃','宋','宋诗','song-poetry','','[]','携鉏乘夏雨，分菊待秋風。',48,'全唐诗/poet.song.164000.json','["携鉏乘夏雨，分菊待秋風。", "幽事常關我，閑居不負公。", "苔深連竹地，籬破接蘭叢。", "更約兒童輩，須勤灌溉功。"]'),
('80e581bf-39db-4ee3-b559-e3007b90ac4c','暇日過在伯辱對菊置酒已焉甚醉得四十字','趙蕃','宋','宋诗','song-poetry','','[]','雨後江猶漲，霜前菊正繁。',48,'全唐诗/poet.song.164000.json','["雨後江猶漲，霜前菊正繁。", "波光摇檻楯，花氣入楹軒。", "病不勝杯勺，情欣接話言。", "兀然成徑醉，涕唾老仍煩。"]'),
('484fb2bb-39e5-4317-a8a5-af7f5f190e69','窗前葵萱皆吐花成詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','僮能去蓬藋，手自植葵萱。',48,'全唐诗/poet.song.164000.json','["僮能去蓬藋，手自植葵萱。", "疊石就爲砌，啟窗因當軒。", "後先殊早晚，開歛共朝昏。", "長夏曷以度，幽花相與言。"]'),
('a3abe6d2-f65f-4338-a1af-3a9a24cf3c10','窗前葵萱皆吐花成詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','落去梅堪裹，乍開臺更重。',48,'全唐诗/poet.song.164000.json','["落去梅堪裹，乍開臺更重。", "老懷非我獨，幽質爲誰容。", "短髮簪猶惜，高軒詠可供。", "還愁早衰歇，無以慰疎慵。"]'),
('de0bd633-52a5-45ad-b3d6-64ce7b6473ca','詠智門佛殿前凌霄花與斯遠同作','趙蕃','宋','宋诗','song-poetry','','[]','桂栽初得地，藤附亦凌霄。',48,'全唐诗/poet.song.164000.json','["桂栽初得地，藤附亦凌霄。", "層葉圓如葆，高花豔若燒。", "故能開續續，殊愈落飄飄。", "有木方思種，從僧會乞苗。"]'),
('1ca9e879-7db0-4784-b838-6229238a924b','咏蕙','趙蕃','宋','宋诗','song-poetry','','[]','莫與蘭爭長，風期本自同。',48,'全唐诗/poet.song.164000.json','["莫與蘭爭長，風期本自同。", "俱高漢賦上，並錄楚詞中。", "斛種當書屋，籃移自佛宮。", "更餘千箇竹，相與慰詩窮。"]'),
('3120b4fd-02ac-4d0e-af57-6353b268359b','蘐草','趙蕃','宋','宋诗','song-poetry','','[]','伯兮當日意，蘐也直云忘。',48,'全唐诗/poet.song.164000.json','["伯兮當日意，蘐也直云忘。", "豈是名茲草，真將種北堂。", "能叢又能幹，非絳復非黄。", "開處陰當合，看時晝閲長。"]'),
('8de5e747-0db0-4a2c-972d-ba66eafc358a','楊花','趙蕃','宋','宋诗','song-poetry','','[]','雨樹蒙茸集，晴空散亂飛。',48,'全唐诗/poet.song.164000.json','["雨樹蒙茸集，晴空散亂飛。", "若爲能撲撲，何只詠依依。", "花裏渾迷蝶，風前屢點衣。", "未妨吹盡得，病起带寬圍。"]'),
('d043befe-027a-4273-8fd4-9c586c209adc','蛺蝶','趙蕃','宋','宋诗','song-poetry','','[]','不逐春風去，仍當夏日長。',48,'全唐诗/poet.song.164000.json','["不逐春風去，仍當夏日長。", "一雙還一隻，能白或能黄。", "戀戀不自已，翩翩空復狂。", "計功歸實用，終日媿蜂房。"]'),
('231e1cea-95c0-4a3f-b009-94238bdf69a7','偶得掃竹因培竹五字會仲威見過留與明叔同飯用此語成詩','趙蕃','宋','宋诗','song-poetry','','[]','掃竹因培竹，畏人非避人。',48,'全唐诗/poet.song.164000.json','["掃竹因培竹，畏人非避人。", "跫然聞響屐，莞爾正欹巾。", "坐子竟日久，飯吾三韭貧。", "能來不嫌屢，梅底要深巡。"]'),
('cab0d13c-74cb-4e8e-99eb-82ffaf0c97fd','斫病竹','趙蕃','宋','宋诗','song-poetry','','[]','採掘寧慳供，護持期有成。',48,'全唐诗/poet.song.164000.json','["採掘寧慳供，護持期有成。", "時今閲春夏，爾獨意枯榮。", "瑣碎日無影，蕭騷風罷聲。", "樵蘇勿懷辱，而我豈無情。"]'),
('7fa6fd9c-7b30-4532-ad20-4a4c0557ae2c','新竹','趙蕃','宋','宋诗','song-poetry','','[]','新竹不數輩，歲慳非地貧。',48,'全唐诗/poet.song.164000.json','["新竹不數輩，歲慳非地貧。", "破苔方挺出，突屋已長身。", "未害少爲貴，居同德有鄰。", "山中乏朋友，舍爾復誰親。"]'),
('5870f493-a9db-4fcb-b731-94a0a5c26ae3','題新竹示韋德卿','趙蕃','宋','宋诗','song-poetry','','[]','戢戢初成茁，駸駸漸可竿。',48,'全唐诗/poet.song.164000.json','["戢戢初成茁，駸駸漸可竿。", "朝幽粉淚漬，午靜籜聲乾。", "枝且勝棲羽，陰仍合翠寒。", "書齋有餘暇，可以過予看。"]'),
('3839926f-334d-47d0-9fa5-fdceaefa0064','竹逕','趙蕃','宋','宋诗','song-poetry','','[]','一日猶思種，長年可不栽。',48,'全唐诗/poet.song.164000.json','["一日猶思種，長年可不栽。", "初時叢足玩，歲久徑成開。", "明月雖妨約，清風得敘懷。", "未須緣客掃，頻肯爲詩來。"]'),
('a65286b6-c4f5-4d55-812d-7802ce3e95fb','種柏','趙蕃','宋','宋诗','song-poetry','','[]','插柳終慙桂，殷勤買柏栽。',48,'全唐诗/poet.song.164000.json','["插柳終慙桂，殷勤買柏栽。", "予如樗櫟者，汝自棟梁才。", "今日藩籬護，他年風雨哀。", "人生朝暮爾，此物到雲來。"]'),
('2a753a01-c31c-40b9-a40a-5114778282ca','堂下梅一枝開遲而花極小疑地勢使然感歎而作','趙蕃','宋','宋诗','song-poetry','','[]','梅發無衰盛，根生有瘠腴。',48,'全唐诗/poet.song.164000.json','["梅發無衰盛，根生有瘠腴。", "都緣托地薄，故使著花癯。", "渺小吾憐爾，伶仃爾念吾。", "詎須詩欠興，何用竹相娛。"]'),
('33b321d3-17ab-4d4c-82c5-e20f318c4879','梅未開書四十字','趙蕃','宋','宋诗','song-poetry','','[]','地與南荒接，梅花合早開。',48,'全唐诗/poet.song.164000.json','["地與南荒接，梅花合早開。", "如何長至後，不見一杖來。", "政爾緣霜早，多應待雨催。", "簷邊有獨樹，日遶故千回。"]'),
('7fae750c-20dc-4b36-800a-da11385a30c1','約老謝丈及諸友尋梅','趙蕃','宋','宋诗','song-poetry','','[]','聞道梅花發，山邊復水邊。',48,'全唐诗/poet.song.164000.json','["聞道梅花發，山邊復水邊。", "要穿居士屩，還傍野人船。", "盤礴須窮日，飄零憶去年。", "携壺雖我約，能賦屬公先。"]'),
('202df15c-60a4-432a-9e90-5785bd71857c','梅微開復題','趙蕃','宋','宋诗','song-poetry','','[]','晨起渾無事，巡簷立久時。',48,'全唐诗/poet.song.164000.json','["晨起渾無事，巡簷立久時。", "不驚新苦瘐，頻憶舊題詩。", "次第開全樹，攙先見一枝。", "故園春尚晚，折寄欲因誰。"]'),
('029375c3-8d86-43d0-bfdb-75dd4a0bd73a','陳嚴二先生和前詩見示次韻報之','趙蕃','宋','宋诗','song-poetry','','[]','梅蕊何曾見，詩筒已再開。',48,'全唐诗/poet.song.164000.json','["梅蕊何曾見，詩筒已再開。", "如憐今歲盡，喚起好春來。", "咫尺花當動，侵尋老故催。", "不知榮悴閲，更得幾何回。"]'),
('5b64666e-a018-47e6-af16-384a385e9da5','和答曹季永縣尉用前韻見貽','趙蕃','宋','宋诗','song-poetry','','[]','旱久疑成癘，梅枯未得開。',48,'全唐诗/poet.song.164000.json','["旱久疑成癘，梅枯未得開。", "悵然因有句，作者賸能來。", "風日寧渠貸，光陰覺我催。", "却愁看欲盡，憶著首頻回。"]'),
('1f7e1d56-cfd7-4a8a-873b-9f4768730f96','梅驟開旋有落者','趙蕃','宋','宋诗','song-poetry','','[]','强說歲寒姿，曾無旬浹期。',48,'全唐诗/poet.song.164000.json','["强說歲寒姿，曾無旬浹期。", "多緣風日苦，休道雪霜欺。", "烱烱方懷璧，依俯遽泣岐。", "飄零陌上土，收拾卷中詩。"]'),
('72783410-b0ac-405b-8f85-1b64f1533e56','梅且盡作四十字','趙蕃','宋','宋诗','song-poetry','','[]','江梅自癯瘠，挫抑豈多禁。',48,'全唐诗/poet.song.164000.json','["江梅自癯瘠，挫抑豈多禁。", "未臘憂風雪，先春病雨陰。", "開時能慰眼，落去更關心。", "何以寬愁寂，村醪得屢斟。"]'),
('30f5575e-a238-430c-96f7-cfdd187050f0','至節後猶未見梅疑旱使然','趙蕃','宋','宋诗','song-poetry','','[]','敗砌初無菊，空林合有梅。',48,'全唐诗/poet.song.164000.json','["敗砌初無菊，空林合有梅。", "如何長至後，不見一枝開。", "豈是春渝信，端緣旱作災。", "蔬畦與麥壠，滿目但黄埃。"]'),
('bc98f70e-98a4-43a3-855c-21e311bf3107','和斯遠西軒竹二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','軒闢因松倒，軒深爲竹成。',48,'全唐诗/poet.song.164000.json','["軒闢因松倒，軒深爲竹成。", "山靈回俗駕，鳥語助詩鳴。", "客子息肩地，諸公携酒行。", "白頭哀我獨，青眼爲渠橫。"]'),
('f7457e20-7e78-4a22-be49-ba1d33f2745c','和斯遠西軒竹二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','道上行人暍，林間釋子幽。',48,'全唐诗/poet.song.164000.json','["道上行人暍，林間釋子幽。", "去無相趣迫，聊得小夷猶。", "竹樹擁簷立，溪山隨檻流。", "自非能賦者，常是欲眠休。"]'),
('d4d27d8b-2099-4b5b-acea-0e20fe548001','同成父弟訪王亢宗遇周欽止同過圓通看竹二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','訪客因逢客，相携看竹來。',48,'全唐诗/poet.song.164000.json','["訪客因逢客，相携看竹來。", "徑從林下轉，門向水邊開。", "高顧防驚鳥，徐行恐破苔。", "故嫌溪淺落，妨我泛舟回。"]'),
('4e1e8b2f-8560-42b5-b5f9-d5d0ca960ab0','同成父弟訪王亢宗遇周欽止同過圓通看竹二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','鄰圃代曾經，僧園種得成。',48,'全唐诗/poet.song.164000.json','["鄰圃代曾經，僧園種得成。", "不關新雨過，自是絕塵生。", "疎直能明眼，幽深足敘情。", "何當共携被，重此聽秋聲。"]'),
('f871aa33-7014-45a3-9823-4a49320d1b60','飲袁州惠仰山茶','趙蕃','宋','宋诗','song-poetry','','[]','黄溪方輟供，頓有仰山來。',48,'全唐诗/poet.song.164000.json','["黄溪方輟供，頓有仰山來。", "久怕羊腸險，小聽松吹回。", "喜能澆渴肺，愁柰走饑雷。", "何日俱君謁，香凝燕寢開。"]'),
('729aee74-d148-461f-bd2a-e3ada05f2196','大琛沽酒','趙蕃','宋','宋诗','song-poetry','','[]','吾州大琛酒，名不謝孤洲。',48,'全唐诗/poet.song.164000.json','["吾州大琛酒，名不謝孤洲。", "女子亦知價，行人皆繫舟。", "西來灘過險，東上寺逢幽。", "未說千憂散，姑爲一醉謀。"]'),
('bb6c3d44-b92a-446e-9676-243176ed4c55','鄰居送梅子朱櫻','趙蕃','宋','宋诗','song-poetry','','[]','山居蔬果少，口腹每勞人。',48,'全唐诗/poet.song.164000.json','["山居蔬果少，口腹每勞人。", "梅子欣初食，櫻桃併及新。", "供鹽貧亦辦，薦酪遠無因。", "便可呼杯勺，數朝陰雨頻。"]'),
('9bb1d7e8-7f85-4020-bacb-0769e375f62f','螢火','趙蕃','宋','宋诗','song-poetry','','[]','渾忘生朽腐，直擬暮光輝。',48,'全唐诗/poet.song.164000.json','["渾忘生朽腐，直擬暮光輝。", "解燭書帷靜，能添列宿稀。", "當風方自表，带雨忽成微。", "變滅無多理，榮枯會一歸。"]'),
('889f8f80-95cf-4ff6-a8bc-8643104da452','贈墨二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','奚李風流遠，名家得自賢。',48,'全唐诗/poet.song.164000.json','["奚李風流遠，名家得自賢。", "粗能明款識，不暇別中邊。", "歲計一丸足，癡人連屋懸。", "此生能幾屐，茲士信超然。"]'),
('a1246d23-5b09-4925-acb2-221ae9ec05df','贈墨二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','斲我千年質，成茲數寸瑿。',48,'全唐诗/poet.song.164000.json','["斲我千年質，成茲數寸瑿。", "當從黑白辨，豈問姓名題。", "願效文章用，寧辭肌骨刲。", "先生無浪語，略爲究端倪。"]'),
('0a8b2e82-8df4-4399-bf69-b7f65242b076','贈硯','趙蕃','宋','宋诗','song-poetry','','[]','一種端溪石，下巖滋別源。',48,'全唐诗/poet.song.164000.json','["一種端溪石，下巖滋別源。", "千金騰有翼，尺璧走非跟。", "自顧婆娑質，適堪椎鈍根。", "終焉老茅屋，已矣獻金門。"]'),
('e5263973-5d90-414d-ab76-143b4b5bb53b','硯答','趙蕃','宋','宋诗','song-poetry','','[]','食硯固可笑，硯枯還有云。',48,'全唐诗/poet.song.164000.json','["食硯固可笑，硯枯還有云。", "先生信難說，吾事亦徒勤。", "歲久當消髀，研窮且斷筋。", "不如因墜地，瘞得退之文。"]'),
('d4adba0c-f68c-46a4-88a6-9f0e46e04c2e','讀子進浙行詩軸中有二詩見寄次韻報之  其一','趙蕃','宋','宋诗','song-poetry','','[]','近有平安使，新詩得盡傳。',48,'全唐诗/poet.song.164000.json','["近有平安使，新詩得盡傳。", "深懷行役苦，更憶弟昆賢。", "笠水鴟夷子，荆溪玉局僊。", "經行如有訪，小爲繫歸船。"]'),
('baabbcd6-d3ab-4a77-b27e-2cf2da830fb5','讀子進浙行詩軸中有二詩見寄次韻報之  其二','趙蕃','宋','宋诗','song-poetry','','[]','何夕佳風月，仍陪笑語清。',48,'全唐诗/poet.song.164000.json','["何夕佳風月，仍陪笑語清。", "依依數行李，了了盡平生。", "要使交游態，渾如手足情。", "居閒有此樂，那用占時名。"]'),
('b9fe3904-615b-4dc7-a6ac-e85bef82b1c7','秀奕以文編垂示簡之','趙蕃','宋','宋诗','song-poetry','','[]','每念新疎闊，還思舊倡酬。',48,'全唐诗/poet.song.164000.json','["每念新疎闊，還思舊倡酬。", "年齡故相並，文事孰能優。", "媿乏聞多益，難支問不休。", "黄陳有正派，舍是復何求。"]'),
('fb05fb93-4e57-422b-b097-cdccc63a4768','以近詩寄丘運使','趙蕃','宋','宋诗','song-poetry','','[]','古貨自難買，良工徒苦心。',48,'全唐诗/poet.song.164000.json','["古貨自難買，良工徒苦心。", "誰能明致力，于此是知音。", "門第成乖隔，江湖阻滯淫。", "寄書因有使，還得附微吟。"]'),
('b773cfee-7d08-418b-815e-1a155eff2b0b','呈林子方運使四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','去歲都城客，傳聞召節馳。',48,'全唐诗/poet.song.164000.json','["去歲都城客，傳聞召節馳。", "深期遂披覩，得以敘乖離。", "竟復參差是，空成悵望茲。", "外臺知不遠，匹馬敢言疲。"]'),
('af97a80c-6941-4642-afeb-7fdd50e4a239','呈林子方運使四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','憶自梧州別，懷茲下榻勤。',48,'全唐诗/poet.song.164000.json','["憶自梧州別，懷茲下榻勤。", "寸心長炯炯，尺素每云云。", "遠地必迂報，高情真薄雲。", "百年公幾見，五十我無聞。"]'),
('5bc1b2ae-52cb-4588-a46d-3bc0988cdbbf','呈林子方運使四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','一代推人物，諸生頼楷模。',48,'全唐诗/poet.song.164000.json','["一代推人物，諸生頼楷模。", "高風雖莫並，盛德本非孤。", "物望歸臺閣，官稱復轉輸。", "澄清雖雅志，獻納政時須。"]'),
('21210f38-a79a-4547-b3c8-8b5e42e92b01','呈林子方運使四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','白髮絲難理，青衫葉半枯。',48,'全唐诗/poet.song.164000.json','["白髮絲難理，青衫葉半枯。", "自憐謀斗食，敢作慟窮途。", "試問遥書札，何如邇坐隅。", "合江趨浩渺，分水忘崎嶇。"]'),
('e4239427-6890-4ffa-8819-8d4beff58207','投曾原伯運使二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','一自嘉禾見，于今歲幾多。',48,'全唐诗/poet.song.164000.json','["一自嘉禾見，于今歲幾多。", "飛騰公可那，流落我如何。", "舊說金能點，今成鏡失磨。", "未甘終痼疾，還復向醫和。"]'),
('e0c44350-219e-405d-be42-f17d06a17ae8','投曾原伯運使二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','遠地書郵絕，長年屬望勞。',48,'全唐诗/poet.song.164000.json','["遠地書郵絕，長年屬望勞。", "要期親帚柄，寧憚學舟操。", "媿守藩籬小，難窺牆仞高。", "秋風滿天地，不廢候蟲號。"]'),
('53e7df9e-58dd-4d8b-a7a6-1bc93232940b','以近詩寄尤運使','趙蕃','宋','宋诗','song-poetry','','[]','求識尤太史，泛舟維豫章。',48,'全唐诗/poet.song.164000.json','["求識尤太史，泛舟維豫章。", "秋天值摇落，行色況蒼茫。", "竟乏驚人句，莫升君子堂。", "學詩雖老矣，猶擬遍諸方。"]'),
('04611504-bf68-4c35-bc99-be3688d5fb21','呈丘運使三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','海內求名輩，如公得未多。',48,'全唐诗/poet.song.164000.json','["海內求名輩，如公得未多。", "風流正始士，藝達孔門科。", "願識亦已久，陳詩無見訶。", "蒿蓬雖培塿，松柏自嵯峨。"]'),
('cda484f2-bbd8-4d60-bd75-258ba39f0e1a','呈丘運使三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','奔逸聞千里，飛騰見九遷。',48,'全唐诗/poet.song.164000.json','["奔逸聞千里，飛騰見九遷。", "禁途才咫尺，玉節屢回旋。", "看即自天下，催歸夜席前。", "如憐落鳶外，爲遣反驅邊。"]'),
('b538cb53-8244-4b46-9c78-dd1f33ff56d9','呈丘運使三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','從士二千里，學詩三十年。',48,'全唐诗/poet.song.164000.json','["從士二千里，學詩三十年。", "坐窮寧爲此，將老豈其然。", "恥食陶奴米，羞言夷甫錢。", "相逢何用早，契合有忘年。"]'),
('02ecbc84-21b6-4f8c-bf55-7e9108ec108d','呈黄永新希二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','江夏無雙士，嘉禾百里君。',48,'全唐诗/poet.song.164000.json','["江夏無雙士，嘉禾百里君。", "信非今日吏，要與古人羣。", "閲世卧松柏，過前紛蚋蚊。", "薰蕕自我別，青白在渠分。"]'),
('737b4c34-b15b-4140-8ad4-1c0c20cd6b22','呈黄永新希二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','偶作空房寓，頻成假日從。',48,'全唐诗/poet.song.164000.json','["偶作空房寓，頻成假日從。", "平生壯詩膽，一見怯譚鋒。", "天地雖云礙，江湖詎不容。", "終南捷徑絕，衡嶽卧圖逢。"]'),
('e55389e7-6017-4d76-b6df-f7919ee4759c','呈張太平三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','游日甘泉舊，如公孰與先。',48,'全唐诗/poet.song.164000.json','["游日甘泉舊，如公孰與先。", "內雖資獻納，外乃藉蕃宣。", "今日江淮地，寧惟牧守權。", "功名端未晚，勉力繼青氈。"]'),
('502ddec3-4597-4425-9591-c8c7c82d9340','呈張太平三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','貴者多驕士，古然寧邇來。',48,'全唐诗/poet.song.164000.json','["貴者多驕士，古然寧邇來。", "惟公獨超俗，片善靡遺才。", "譽已滿臺閣，勤方散草萊。", "深知桃李徑，不爲看花栽。"]'),
('ecc92b13-ebd0-42bf-bd4b-1abf9369c143','呈張太平三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','門牆十五載，每見辱加親。',48,'全唐诗/poet.song.164000.json','["門牆十五載，每見辱加親。", "老至名不立，道乖家轉貧。", "世誰能我及，志欲向公申。", "賸欲搜詩獻，青山恐笑人。"]'),
('49df7a40-efcf-465a-ab2b-83e5a5832fa1','送劉通判二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','射策今晁董，摛詞昔左班。',48,'全唐诗/poet.song.164000.json','["射策今晁董，摛詞昔左班。", "題輿已最課，召節待遄頒。", "鵬背九萬里，龍媒十二閑。", "除書看臺閣，盛事聳荆蠻。"]'),
('4be5e91d-9170-44ce-9345-dc29107296f7','送劉通判二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','國祚重興後，人才應運生。',48,'全唐诗/poet.song.164000.json','["國祚重興後，人才應運生。", "端殊飛紫鷟，亦異夢長庚。", "大半廟堂用，若爲州縣更。", "垂弧賀今日，連茹徯茲行。"]'),
('d35508e3-ee5e-406f-b043-c9e03f395e34','寄趙信州一叔二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','蓬山辭上直，番國喚回舟。',48,'全唐诗/poet.song.165000.json','["蓬山辭上直，番國喚回舟。", "舊事超千佛，茲行奪萬牛。", "未除真學士，且列古諸侯。", "詔旨防敦迫，民言願借留。"]'),
('b261d4d5-4e03-4626-96a6-f039fa772b20','寄趙信州一叔二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','官梅親手種，山閣聽僧修。',48,'全唐诗/poet.song.165000.json','["官梅親手種，山閣聽僧修。", "授簡慙吾事，登高企勝流。", "葭莩元有託，桑梓近臨州。", "媿我資身拙，從公但食謀。"]'),
('c5d8e32d-e760-466f-b192-e060a030e7fc','呈葛撫州二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','人物與江山，風流適比肩。',48,'全唐诗/poet.song.165000.json','["人物與江山，風流適比肩。", "家聲自勾漏，出守更臨川。", "美政人人說，新詩句句傳。", "五言成漫興，一見豈無緣。"]'),
('41197a68-4f2a-4ae2-bb10-2ee0ebb5013f','呈葛撫州二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','試說臨川郡，江西第一州。',48,'全唐诗/poet.song.165000.json','["試說臨川郡，江西第一州。", "晏王今邑子，顔謝古諸侯。", "未覺流風遠，端知物望優。", "峴山猶得擬，湛輩肯容不。"]'),
('f4352291-5017-43d1-8632-1e6cc365395f','與李潭州椿壽翁五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','荷橐上甘泉，居多政府遷。',48,'全唐诗/poet.song.165000.json','["荷橐上甘泉，居多政府遷。", "胡爲抗章謝，而必退身全。", "自計雖良已，人賢詎舍旃。", "吾心故公爾，斯道合幡然。"]'),
('2e414413-e685-4f5c-a11c-a38cfab2389b','與李潭州椿壽翁五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','疏去良臣散，文興大老歸。',48,'全唐诗/poet.song.165000.json','["疏去良臣散，文興大老歸。", "能忘繆公側，何有步兵幾。", "暴虎無苛政，鳴岡覽德輝。", "輩雖參落落，業且相巍巍。"]'),
('bc5948d1-fbed-4ecb-a83e-1d035bf288b1','與李潭州椿壽翁五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','今代長沙帥，當年漢李膺。',48,'全唐诗/poet.song.165000.json','["今代長沙帥，當年漢李膺。", "登門故未易，爲御亦堪矜。", "嗜好雖章句，經營在斗升。", "青衫舊藍縷，白髮近鬅鬙。"]'),
('721e02b7-4a71-4953-8427-3a2c1aeacbe7','與李潭州椿壽翁五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','萬里沅湘路，千年賈屈文。',48,'全唐诗/poet.song.165000.json','["萬里沅湘路，千年賈屈文。", "迹同探禹穴，心每望堯雲。", "未說渺茫隠，長思矍鑠勳。", "不應迷出處，四十畏無聞。"]'),
('1935869c-a894-40d4-9948-b1fae081dc3f','與李潭州椿壽翁五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','日夜霜風急，東西客路昏。',48,'全唐诗/poet.song.165000.json','["日夜霜風急，東西客路昏。", "詩方學蠻語，病昔似文園。", "俯上轅門謁，愁干節制尊。", "頑疎寧自昧，剪拂望深恩。"]'),
('3a8490e4-80ad-487d-98cc-b29c88129cc0','呈李贛州四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昔重湖北，逢人問處州。',48,'全唐诗/poet.song.165000.json','["憶昔重湖北，逢人問處州。", "寄書寧盡達，覓使苦無由。", "風月無離闊，山川自阻修。", "那知遠遊櫂，又傍昔年洲。"]'),
('506c160b-0064-4a13-96df-01c784dbb812','呈李贛州四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','見自長臺數，于今十五年。',48,'全唐诗/poet.song.165000.json','["見自長臺數，于今十五年。", "雖云公偃薄，政坐我迍邅。", "苦志思重寫，愁腸不易煎。", "却憐難掩處，霜髮半蕭然。"]'),
('73046d54-82ef-45a2-a93a-e68f0e0dd7b2','呈李贛州四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','安否每難問，姓名今得通。',48,'全唐诗/poet.song.165000.json','["安否每難問，姓名今得通。", "久憂埋積雪，大喜得春風。", "與世故多識，如公能幾同。", "既欣還有感，愁對海棠叢。"]'),
('19a91693-0bd2-43e8-8b46-8dfa370dc46c','呈李贛州四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','學時元草草，賦就每匆匆。',48,'全唐诗/poet.song.165000.json','["學時元草草，賦就每匆匆。", "竟復無真好，空令坐枉窮。", "春風纔亂鳥，秋雨又鳴蛩。", "笑我胡爲者，真成浪自攻。"]'),
('0b546b53-5566-43aa-9e64-6cb6dec3f456','贈劉進父監廟四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','退士今安有，微官詎足旌。',48,'全唐诗/poet.song.165000.json','["退士今安有，微官詎足旌。", "茹蔬知味薄，不飲見神清。", "要是高其事，况堪詩有聲。", "淮南人物論，是亦一權衡。"]'),
('fda32a5a-f19c-4a4e-9dcc-d225aa72e40f','贈劉進父監廟四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','北客自無幾，老親寧重論。',48,'全唐诗/poet.song.165000.json','["北客自無幾，老親寧重論。", "客居誰肯記，郊寺辱深存。", "厚義真難得，高情獨見敦。", "寒燈仍薄粥，相與話黄昏。"]'),
('8659b151-fc28-4049-9717-858df6f31384','贈劉進父監廟四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','彼美南山石，槎牙更貫之。',48,'全唐诗/poet.song.165000.json','["彼美南山石，槎牙更貫之。", "道雖橫至寶，誰復賞奇姿。", "歎息已云屢，寫摹嘗有詩。", "吾曹從行者，名字亦俱垂。"]'),
('ac24c87e-66da-4a07-8707-4b9167589ab8','贈劉進父監廟四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','歲晚戒行路，問君何遠征。',48,'全唐诗/poet.song.165000.json','["歲晚戒行路，問君何遠征。", "風霜雖自苦，墳墓不勝情。", "南徙計豈得，北歸邊未平。", "非惟慕嚴父，抑亦念難兄。"]'),
('724d9f42-0855-495f-b818-daf7d7f4eafa','呈楊謹仲監廟三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','祇道無前輩，于今識後凋。',48,'全唐诗/poet.song.165000.json','["祇道無前輩，于今識後凋。", "形容猶矍鑠，鬢髮自飄蕭。", "早日破萬卷，暮齡甘一瓢。", "紛紛盈鄭衛，洗耳驟聞韶。"]'),
('8dc1c5cc-7cd6-4793-a51a-3bfbdc813677','呈楊謹仲監廟三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','劉孔何如士，歐蘇敢並行。',48,'全唐诗/poet.song.165000.json','["劉孔何如士，歐蘇敢並行。", "江山故好在，人士熟知名。", "道遇澄清使，爲言月旦評。", "經過纔一見，已似慰平生。"]'),
('74639770-7624-448f-8c67-14e1be249982','呈楊謹仲監廟三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','地占清江勝，居兼水竹幽。',48,'全唐诗/poet.song.165000.json','["地占清江勝，居兼水竹幽。", "衡門阻靜僻，高卧樂優游。", "深霧隠玄豹，滄波翻白鷗。", "弓旌不可挽，芻牧政旁搜。"]'),
('02d187a8-5492-4e98-8aed-5ecc3f853b42','十八日分謁升德廟過江作','趙蕃','宋','宋诗','song-poetry','','[]','命有叢祠事，晨興敢憚勤。',48,'全唐诗/poet.song.165000.json','["命有叢祠事，晨興敢憚勤。", "渚沙微隠艇，山木總藏雲。", "雨勢紛未已，詩材怳見分。", "中流更回首，片片媿鷗羣。"]'),
('31e1636c-5c5d-4404-8e9c-e9e86ba76191','寄峽州使君郭郎中三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','漢代郭林宗，詞場繼國風。',48,'全唐诗/poet.song.165000.json','["漢代郭林宗，詞場繼國風。", "郎官曾賜被，刺史蹔憑熊。", "爲客留工部，移官滯酒翁。", "淮陽豈爲薄，無恨不居中。"]'),
('f19baa23-8273-4785-a9a4-79f5baebef0c','寄峽州使君郭郎中三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','何處觀文獻，如公尚典刑。',48,'全唐诗/poet.song.165000.json','["何處觀文獻，如公尚典刑。", "詩先獲麟作，字本換鵝經。", "牛斗漫寶氣，虛危須德星。", "無爲偃薄計，不晚詔除聽。"]'),
('edae44b7-3b8e-4521-94a5-d11d7313848a','寄峽州使君郭郎中三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','契自西臺敘，親從昭德論。',48,'全唐诗/poet.song.165000.json','["契自西臺敘，親從昭德論。", "名聲蓋前輩，牢落媿清門。", "既見未知日，因風聊自存。", "祇愁千里面，識我故塵昏。"]'),
('6e632453-4b20-4acc-8ae2-2956f9c25fbf','馮守生日  其一','趙蕃','宋','宋诗','song-poetry','','[]','西漢馮君裔，康時萬石家。',48,'全唐诗/poet.song.165000.json','["西漢馮君裔，康時萬石家。", "治邊清鼓角，勸課足桑麻。", "誕日今年再，歡聲闔境譁。", "無言政長夏，亦可醉流霞。"]'),
('97036d38-c096-45a8-82c0-af56028c2a35','馮守生日  其二','趙蕃','宋','宋诗','song-poetry','','[]','報政期年外，裏言朝夕間。',48,'全唐诗/poet.song.165000.json','["報政期年外，裏言朝夕間。", "省郎何太晚，召節看遄頒。", "屢上薰風殿，行參玉筍班。", "故應憐末掾，牢落尚羣蠻。"]'),
('2b263bfe-01ef-46df-9d3c-e9d9dd738871','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其一','趙蕃','宋','宋诗','song-poetry','','[]','驟雨落還收，餘寒去却留。',48,'全唐诗/poet.song.165000.json','["驟雨落還收，餘寒去却留。", "飄零梅樹底，髣髴杏梢頭。", "酒有連朝病，詩從一笑求。", "平生湖海興，又復具扁舟。"]'),
('f0262130-73c3-4d61-a6f6-c0e29dc6c348','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其二','趙蕃','宋','宋诗','song-poetry','','[]','門戶憐非寄，聲名歎不羣。',48,'全唐诗/poet.song.165000.json','["門戶憐非寄，聲名歎不羣。", "倦遊俱楚子，舊識記番君。", "去覓江山助，行思風月分。", "詩成如枉寄，亦足張吾軍。"]'),
('53917676-fb69-45dd-a60c-74f5ddae88dd','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其三','趙蕃','宋','宋诗','song-poetry','','[]','問認書能數，飄流見愈親。',48,'全唐诗/poet.song.165000.json','["問認書能數，飄流見愈親。", "通家如弟數，受賜亦州民。", "渺莽重湖路，羈棲一病身。", "欲行行未得，風雨况頻頻。"]'),
('d331587d-711f-4464-8112-1810cf480d22','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其四','趙蕃','宋','宋诗','song-poetry','','[]','太史羲皇上，嵩山季孟間。',48,'全唐诗/poet.song.165000.json','["太史羲皇上，嵩山季孟間。", "諸孫均內外，文采被斕斑。", "顧我何足數，遺風莫可攀。", "知音愧流水，仰止在高山。"]'),
('f4668d2f-7f6e-45b1-bf8a-d25d93b36e39','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其五','趙蕃','宋','宋诗','song-poetry','','[]','有集能行世，初疑是古人。',48,'全唐诗/poet.song.165000.json','["有集能行世，初疑是古人。", "大波皆洶湧，小石亦嶙峋。", "時譽歸讎校，微官尚徼巡。", "竹塘春水滿，雙鶒會飛馴。"]'),
('981bb3c8-422c-48f4-8610-cb129af3263f','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其六','趙蕃','宋','宋诗','song-poetry','','[]','客裏仍爲客，天邊嬾問天。',48,'全唐诗/poet.song.165000.json','["客裏仍爲客，天邊嬾問天。", "春風幾經歷，老病一蹁躚。", "君句真嚴律，儂詩但散禪。", "錦囊如許借，不憚手親傳。"]'),
('f4da0e28-ee19-4004-b69f-09eafcb79ad4','移官巴陵行有日矣書呈唐德輿程士和梁和仲于去非段元衡邢大聲七首  其七','趙蕃','宋','宋诗','song-poetry','','[]','只道花爭發，那知雨較遲。',48,'全唐诗/poet.song.165000.json','["只道花爭發，那知雨較遲。", "病軀猶故絮，霜鬢益新絲。", "鄙性豈耽酒，寫懷聊賦詩。", "經過頓能爾，無久溷公爲。"]'),
('1765549e-139f-4d64-a424-ee9fdbcdb2c4','諸公皆和詩再用韻併屬湛挺之七首  其一','趙蕃','宋','宋诗','song-poetry','','[]','誼也期淹速，淵乎任去留。',48,'全唐诗/poet.song.165000.json','["誼也期淹速，淵乎任去留。", "服來占夏首，歸去及春頭。", "豈必憂懷累，當從樂處求。", "控揣終異物，窈窕一孤舟。"]'),
('acc6d9eb-15a7-4876-94b8-f512d7eb0d20','諸公皆和詩再用韻併屬湛挺之七首  其二','趙蕃','宋','宋诗','song-poetry','','[]','戢戢一天翮，紛紛凡馬羣。',48,'全唐诗/poet.song.165000.json','["戢戢一天翮，紛紛凡馬羣。", "回頭異生死，對面或公君。", "漸欲薰蕕等，反嫌黑白分。", "居然攖衆怒，政爾怯孤軍。"]'),
('9828c7fd-d8b2-4466-825e-bd19f64f0f4e','諸公皆和詩再用韻併屬湛挺之七首  其三','趙蕃','宋','宋诗','song-poetry','','[]','翰墨平生友，江山數面親。',48,'全唐诗/poet.song.165000.json','["翰墨平生友，江山數面親。", "誦騷悲楚國，訪古失秦民。", "丘壑豈無趣，塵埃空此身。", "風行思數數，糧食厭頻頻。"]'),
('bec5cfda-dc6a-4604-a60d-007fd5b520fd','諸公皆和詩再用韻併屬湛挺之七首  其四','趙蕃','宋','宋诗','song-poetry','','[]','吳楚他鄉外，沅湘久客間。',48,'全唐诗/poet.song.165000.json','["吳楚他鄉外，沅湘久客間。", "已知身若贅，詎惜鬢成斑。", "酒債貧常有，詩壇老倦攀。", "窮猿難擇木，怨鶴望還山。"]'),
('e2f57888-7b17-4895-9927-06375697f8a8','諸公皆和詩再用韻併屬湛挺之七首  其五','趙蕃','宋','宋诗','song-poetry','','[]','和我閒中句，俱來作者人。',48,'全唐诗/poet.song.165000.json','["和我閒中句，俱來作者人。", "步吟才勃窣，聳詠忽嶙峋。", "浪說能聲喜，端虞試問巡。", "天資固有分，野性雜難馴。"]'),
('5a6cbeca-1312-46ac-ba00-48f8e572032e','諸公皆和詩再用韻併屬湛挺之七首  其六','趙蕃','宋','宋诗','song-poetry','','[]','投老知何地，此生休問天。',48,'全唐诗/poet.song.165000.json','["投老知何地，此生休問天。", "未須悲坎軻，聊復寄蹁躚。", "但覺官如縛，渾忘詩似禪。", "不堪兒子誦，敢望故人傳。"]'),
('2985e84a-cf3c-4b1f-ad82-6d31befda29a','諸公皆和詩再用韻併屬湛挺之七首  其七','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','舊作游梁倦，今成去魯遲。',48,'全唐诗/poet.song.165000.json','["舊作游梁倦，今成去魯遲。", "跳珠先集霰，凍雨亂棼絲。", "蕭瑟夜來酒，悲涼別後詩。", "洞庭歸雁蚤，枉寄莫遲爲。"]'),
('664d70c4-b18a-4131-a384-dd223b7aaad5','既別晦庵復成二詩呈之近欲同游善權不果臨行錄其湖北道中詩一軸  其一','趙蕃','宋','宋诗','song-poetry','','[]','既返山前棹，還斟枕上杯。',48,'全唐诗/poet.song.165000.json','["既返山前棹，還斟枕上杯。", "雪飛如喚住，鴈叫苦催回。", "金瀨半篙綠，石亭千樹梅。", "竟孤陪李郭，亦愧匪鄒枚。"]'),
('b9aa7422-6dc6-48ae-966f-39669491e38c','既別晦庵復成二詩呈之近欲同游善權不果臨行錄其湖北道中詩一軸  其二','趙蕃','宋','宋诗','song-poetry','','[]','去始豐城劍，還終大仰禪。',48,'全唐诗/poet.song.165000.json','["去始豐城劍，還終大仰禪。", "縱橫幾詩句，摹寫百山川。", "竹使承流日，蓬山促召年。", "儂行亦何爲，白首使如遷。"]'),
('192a99a0-0cfa-4163-a79e-edda8bd6aa4a','玉汝置酒招二十一丈同之鄙句奉呈','趙蕃','宋','宋诗','song-poetry','','[]','薄宦一鷄肋，飽霜雙蟹螯。',48,'全唐诗/poet.song.165000.json','["薄宦一鷄肋，飽霜雙蟹螯。", "祗言成爾負，那卜會吾曹。", "我已媿蓬鬢，君俱追錦袍。", "團團石頭月，其下走江濤。"]'),
('b7a1e588-3f0b-4e8f-b89e-61c9659d3461','賈丈用昂字韻作詩中有見及復用韻奉呈併簡徐謝二丈','趙蕃','宋','宋诗','song-poetry','','[]','人謂先生老，詩壇近一昂。',48,'全唐诗/poet.song.165000.json','["人謂先生老，詩壇近一昂。", "共知文力健，何有鬢毛霜。", "自料才非敵，從今氣減狂。", "同宗有徐謝，我亦漫窺牆。"]'),
('796f0f3f-0398-4d7b-8a95-0e8c70645701','呈叔驥和叔','趙蕃','宋','宋诗','song-poetry','','[]','吳楚山川隔，塤箎笑語歡。',48,'全唐诗/poet.song.165000.json','["吳楚山川隔，塤箎笑語歡。", "柳遲因積雪，梅悴坐餘寒。", "痛飲還憂病，離愁孰可寬。", "故非元與白，壓倒又何難。"]'),
('97aa9ca1-bf7e-4df8-85e4-6538af9bf1f2','二十一日晚呈全真沅陵師契','趙蕃','宋','宋诗','song-poetry','','[]','酒味雖云薄，談端却甚長。',48,'全唐诗/poet.song.165000.json','["酒味雖云薄，談端却甚長。", "過從未能數，咫尺每相望。", "幾念乘羸出，還嫌觸熱妨。", "簷昏書掩卷，月晚坐移床。"]'),
('637a1040-81b7-4412-8b7a-85db1e1926ad','呈毛伯明李叔器','趙蕃','宋','宋诗','song-poetry','','[]','陰雨春三月，倦遊天一隅。',48,'全唐诗/poet.song.165000.json','["陰雨春三月，倦遊天一隅。", "故難同類我，還復歎猶吾。", "不惑防終蔽，無聞恐遂愚。", "猶欣得師友，可以慰羈孤。"]'),
('df08a677-6a69-495f-8fdc-3fc750c1e734','寄湯司諫','趙蕃','宋','宋诗','song-poetry','','[]','自發袁州使，侵尋復暮春。',48,'全唐诗/poet.song.165000.json','["自發袁州使，侵尋復暮春。", "何人話安否，官路政艱辛。", "章貢未歸客，湘沅薄宦人。", "何當一傾蓋，肯作白頭新。"]'),
('39212f5d-559a-44a2-b442-a1acfd2ace35','寄謝湯司諫二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','十往九不報，好辭開幾番。',48,'全唐诗/poet.song.165000.json','["十往九不報，好辭開幾番。", "誇張示朋友，問訊異寒溫。", "豈必待傾蓋，何時真掃門。", "絕勝東閣下，布粟對公孫。"]'),
('e6c17e44-274b-496c-9627-db8890fa5ac3','寄謝湯司諫二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','章水清初漲，梅花雪正飛。',48,'全唐诗/poet.song.165000.json','["章水清初漲，梅花雪正飛。", "不惟催我去，似亦待公歸。", "有弟能頻說，高情真見幾。", "男兒出處耳，麟閣與漁磯。"]'),
('03412c00-66ff-4d6a-8bb4-95623f91d27d','送湛挺之提幹自武陵迎侍於侯官兼寄鉛山尉曹馬莊父二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','太學聲名舊，文昌薦墨珍。',48,'全唐诗/poet.song.165000.json','["太學聲名舊，文昌薦墨珍。", "銓曹略常調，幕府得嘉賓。", "使檄辭南楚，安輿發故閩。", "春風滿行色，有賦不妨新。"]'),
('83a1fcf1-9df7-4815-bc48-959470145fc9','送湛挺之提幹自武陵迎侍於侯官兼寄鉛山尉曹馬莊父二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','未歷番君國，先乘汭口船。',48,'全唐诗/poet.song.165000.json','["未歷番君國，先乘汭口船。", "春波元甚駛，順水豈勞牽。", "我去殆同適，公行真若仙。", "壺頭雖不遠，不見馬文淵。"]'),
('2598c0fa-b170-461f-b7fb-e75effd2f941','寄吳吏部三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','捩眼看翺翔，經年尚省郎。',48,'全唐诗/poet.song.165000.json','["捩眼看翺翔，經年尚省郎。", "詔除應邇日，傳播未遐方。", "渺渺山連蜀，滔滔水接湘。", "有懷雖晝夜，其奈道塗長。"]'),
('18271b9a-c8ce-466f-917a-8f863c949127','寄吳吏部三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','元日送朝天，侵尋又一年。',48,'全唐诗/poet.song.165000.json','["元日送朝天，侵尋又一年。", "無詩供猥誦，有志辱哀憐。", "茅屋蒼苔合，芳洲杜若搴。", "去留俱未遂，兩鬢已蒼然。"]'),
('17afbdfc-51b9-40cc-9302-6a183bbf8b65','寄吳吏部三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','梅逐輕冰泮，春從細草生。',48,'全唐诗/poet.song.165000.json','["梅逐輕冰泮，春從細草生。", "孤山應最早，假日想頻行。", "竹閣思賢意，菊泉招隠情。", "柰渠歌鼓競，使我鷺鷗驚。"]'),
('9eff3739-6146-41cd-84b4-06d06580cff9','呈王平江二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','倦著尚書履，閑凝燕寢香。',48,'全唐诗/poet.song.165000.json','["倦著尚書履，閑凝燕寢香。", "聲猶傳漢殿，句豈羨韋郎。", "偃泊姑鈴閣，遄歸定玉堂。", "不惟資獻納，政復用文章。"]'),
('ba918dac-3a77-4ead-a5b7-03f3481756bf','呈王平江二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','先生自詞伯，舉世孰詩人。',48,'全唐诗/poet.song.165000.json','["先生自詞伯，舉世孰詩人。", "縱不藏人善，慚無佳句新。", "每懷青眼舊，應念白頭貧。", "未弭沅湘楫，蒸湘復問津。"]'),
('08adf328-baf2-4403-a063-9cfb50388a40','贈張次律司理三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','長沙有賢掾，京兆出名門。',48,'全唐诗/poet.song.165000.json','["長沙有賢掾，京兆出名門。", "筆力追前輩，陰功及後昆。", "龍門首加薦，樞府舊彌敦。", "看即飛騰去，寧當尋尺論。"]'),
('6644c47b-be30-466b-a7a1-13c1f6764fc2','贈張次律司理三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','及是凡幾見，於今乃白頭。',48,'全唐诗/poet.song.165000.json','["及是凡幾見，於今乃白頭。", "殷勤蒙飯設，緩急與醫謀。", "夫子自爲德，畸人何足憂。", "諸家何所歷，更有若人不。"]'),
('f63c4519-06c0-4b5f-824d-d7d17e980465','贈張次律司理三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','長沙今十日，曾未及湘山。',48,'全唐诗/poet.song.165000.json','["長沙今十日，曾未及湘山。", "舊疾痁頻作，方爐火自跧。", "風高知木脫，雨細念梅斑。", "飄泊方茲始，林園未遽還。"]'),
('c9a69259-de66-47cf-aa6a-321bad9fc897','次韻師契詩中及賑貸事','趙蕃','宋','宋诗','song-poetry','','[]','督賦停勾赤，開倉體詔黄。',48,'全唐诗/poet.song.165000.json','["督賦停勾赤，開倉體詔黄。", "舊唯優附郭，近乃略諸鄉。", "天意終深卹，人謀豈盡長。", "要須梅雨歇，快放麥風凉。"]'),
('c78b6878-c6e7-491e-9d89-4fdcfad01b94','早出小北門','趙蕃','宋','宋诗','song-poetry','','[]','聞道灊皖下，雜然仙佛居。',48,'全唐诗/poet.song.165000.json','["聞道灊皖下，雜然仙佛居。", "心期窮杖屨，宿昔戒車輿。", "晨起先僧磬，逢人盡趁虛。", "烟霏欣在望，風露儘侵裾。"]'),
('9f26bd89-19c6-459e-99df-51d7790ddd89','夜賦二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','欲寐已成寤，暫欣還作悲。',48,'全唐诗/poet.song.165000.json','["欲寐已成寤，暫欣還作悲。", "三更風雨聽，四海友朋思。", "拊榻蟲頻息，挑燈鼠屢窺。", "莫呼僮僕覺，翻到自題詩。"]'),
('389725b5-5f07-46c5-b529-5de80d0cb585','夜賦二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','下上嚴婺路，往來苕霅舟。',48,'全唐诗/poet.song.165000.json','["下上嚴婺路，往來苕霅舟。", "何勝百篇詠，不啻十年遊。", "志願終漁釣，經蹊熟鷺鷗。", "清風慕唐漢，高友得孫劉。"]'),
('f03864d8-b42d-4524-a8ee-5a44038664bc','二十日同官相約過水鄉蕃雨中先至偶成二詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','約客客來至，尋詩詩偶生。',48,'全唐诗/poet.song.165000.json','["約客客來至，尋詩詩偶生。", "秋如驚柳色，雨未改荷聲。", "渺渺江湖趣，悠悠鷗鷺盟。", "意雖能浩蕩，筆迺欠縱橫。"]'),
('eab0ce41-33e6-4bec-861b-98ca0c144525','二十日同官相約過水鄉蕃雨中先至偶成二詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','此雨不易得，有秋端可期。',48,'全唐诗/poet.song.165000.json','["此雨不易得，有秋端可期。", "微官如飽飯，餘事亦窮詩。", "鷄遠村場聽，鳩深客路疑。", "是身真已老，何事此長羈。"]'),
('643d2487-5e48-4584-b4ef-599cd8895718','秉文以田事入村歸而寄之二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','村村穫稻急，得得跨馿行。',48,'全唐诗/poet.song.165000.json','["村村穫稻急，得得跨馿行。", "別野片時役，好詩無數成。", "羸軀難並出，病眼待渠明。", "落日斜猶掛，涼風晚更生。"]'),
('4976e9a7-67a8-4f65-bb68-b53947b00143','秉文以田事入村歸而寄之二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','屢雨不濡土，凉風茲已秋。',48,'全唐诗/poet.song.165000.json','["屢雨不濡土，凉風茲已秋。", "不知今歲事，定獲幾分收。", "日糴每懷慮，歲餘當逭憂。", "題詩纔紙尾，又起望雲頭。"]'),
('15b0367a-2042-42fa-aa22-6df352ea9325','伯威和章記祥符定交云爾蕃之次韻曾未及此再用韻作二首後一首重寄伯山尚留太和伯威詩乃去臘既望寫四月晦蕃始得之  其一','趙蕃','宋','宋诗','song-poetry','','[]','前賢嗟不及，夫子蓋其流。',48,'全唐诗/poet.song.165000.json','["前賢嗟不及，夫子蓋其流。", "海內聞詩熟，言間愜意投。", "午暄同靜廡，暮雪阻高樓。", "別似崇晨耳，一年今半休。"]'),
('334e8896-c1e8-42cc-95e7-5142f2c9dca0','伯威和章記祥符定交云爾蕃之次韻曾未及此再用韻作二首後一首重寄伯山尚留太和伯威詩乃去臘既望寫四月晦蕃始得之  其二','趙蕃','宋','宋诗','song-poetry','','[]','不作山王詠，故聞嵇阮流。',48,'全唐诗/poet.song.165000.json','["不作山王詠，故聞嵇阮流。", "龍淵失珍襲，猿木悔窮投。", "子句成江閣，余懷限戍樓。", "碧雲嗟暮合，黄髮誦歸休。"]'),
('1fbfcfd9-32ce-4afb-8323-7ca1ffeedf3c','別沈二弟','趙蕃','宋','宋诗','song-poetry','','[]','一別動五載，此生能幾回。',48,'全唐诗/poet.song.165000.json','["一別動五載，此生能幾回。", "其間何不有，祇是恐生哀。", "我病真衰矣，君才盍勉哉。", "要留還索去，風雨更漼漼。"]'),
('dd26ef22-f45e-4b60-b2ca-a7ff7e6ffa2b','呈逢宣子','趙蕃','宋','宋诗','song-poetry','','[]','歎息逢宣子，頻爲郡國賓。',48,'全唐诗/poet.song.165000.json','["歎息逢宣子，頻爲郡國賓。", "人皆說才具，我獨愛詞人。", "邂逅殊方見，淒涼半月春。", "但能詩似鏡，從使鬢如銀。"]'),
('0e025455-fc3f-4079-954f-72d01b73852d','昭禮書來告其行日再寄以詩','趙蕃','宋','宋诗','song-poetry','','[]','已執臨岐手，仍通敘別書。',48,'全唐诗/poet.song.165000.json','["已執臨岐手，仍通敘別書。", "絕知於我厚，何敢向君疎。", "江上留殘歲，吳中擬定居。", "莫爲南北恨，天地一蘧廬。"]'),
('066699d5-e678-4a93-8864-98a4c47c7cc3','自作','趙蕃','宋','宋诗','song-poetry','','[]','素仰儒先德，兼聞內助人。',48,'全唐诗/poet.song.165000.json','["素仰儒先德，兼聞內助人。", "齊家真有道，相敬儼如賓。", "女已節義著，兒仍經行醇。", "他年書附傳，落落衆星陳。"]'),
('cb8c74bb-64b5-40f5-bac2-3f1898ab97f6','聞劉凝遠丈病已欣然成詩并懷伯瑞仲文叔驥二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','我行過苕水，公疾卧漳濱。',48,'全唐诗/poet.song.165000.json','["我行過苕水，公疾卧漳濱。", "底處書傳鴈，如聞藥有神。", "作詩應更老，比舊想增貧。", "坐與江山隔，何緣杖履頻。"]'),
('978af9a8-2923-4dfa-aa87-1d5e42b27c39','聞劉凝遠丈病已欣然成詩并懷伯瑞仲文叔驥二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','諸子皆文士，仍傳驥絕羣。',48,'全唐诗/poet.song.165000.json','["諸子皆文士，仍傳驥絕羣。", "連牀思聽雨，拄笏漫看雲。", "病有交遊念，書無歲月勤。", "扁舟問歸路，應見老參軍。"]'),
('23f2f533-78b2-4ce6-92d6-e06e6aa2c697','呈楊溥子','趙蕃','宋','宋诗','song-poetry','','[]','曉過子雲居，霜風柳未疎。',48,'全唐诗/poet.song.165000.json','["曉過子雲居，霜風柳未疎。", "飄零五年別，斷絕一行書。", "安否勞苦外，詩編吟誦餘。", "君寧老騏驥，我已媿舂鉏。"]'),
('9450f470-0df8-470a-9289-513184317184','呈公擇二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','背郭纔數里，深林溪四環。',48,'全唐诗/poet.song.165000.json','["背郭纔數里，深林溪四環。", "精廬于此建，寓舍即其間。", "我已成棲遁，君能數往還。", "故知交義厚，不與世情關。"]'),
('8fa16e70-7c95-4004-b573-9e44cd0d5802','呈公擇二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','此地無此客，若人吾故人。',48,'全唐诗/poet.song.165000.json','["此地無此客，若人吾故人。", "論文皆意到，出語見情真。", "未議作輕別，且當留浹旬。", "畦蔬飽春雨，小摘未妨頻。"]'),
('adf0e7b8-8bfb-4360-9a57-6a5bcc3ee29c','呈邢叔三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','前輩已云遠，公身親見之。',48,'全唐诗/poet.song.165000.json','["前輩已云遠，公身親見之。", "老成疑故在，風俗未憂衰。", "問學本日用，文章先達辭。", "從茲得夷步，不復困多歧。"]'),
('5bbfcc4a-0e70-4360-ba97-0cf5c100bcd7','呈邢叔三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','瀏瀏晴簷響，愔愔蘭斛香。',48,'全唐诗/poet.song.165000.json','["瀏瀏晴簷響，愔愔蘭斛香。", "時于簿書暇，樂是話言長。", "政可晝連夕，興懷參與商。", "平生事賢志，烱烱未嘗忘。"]'),
('c4f493e0-4d34-4fac-8384-28a3673ced11','呈邢叔三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','聽說桃川事，憑虛意欲仙。',48,'全唐诗/poet.song.165000.json','["聽說桃川事，憑虛意欲仙。", "真成在人境，無用覓漁船。", "卜宅自何載，賦詩凡幾篇。", "揮毫儻毋靳，圖貌並流傳。"]'),
('1bc1b8cd-42ff-42c9-8d78-62198f835019','呈亦韓','趙蕃','宋','宋诗','song-poetry','','[]','寒食寒未歸，清明清曉時。',48,'全唐诗/poet.song.165000.json','["寒食寒未歸，清明清曉時。", "花殘渺無迹，柳細不勝垂。", "即事須詩寫，多憂頼酒支。", "雖親友朋益，更苦弟兄思。"]'),
('fe777bd0-0c90-4f55-b414-1285a3b735e9','呈審知','趙蕃','宋','宋诗','song-poetry','','[]','晨出及未熱，飯餘因就談。',48,'全唐诗/poet.song.165000.json','["晨出及未熱，飯餘因就談。", "結交真有道，致此亦何堪。", "靜聽多聞益，微吟佳句耽。", "疎簷有新月，當共影成三。"]'),
('828d19e3-c979-4734-bd90-0477605746cb','次韻和叔并呈叔魚','趙蕃','宋','宋诗','song-poetry','','[]','望望吳楚隔，悠悠兄弟思。',48,'全唐诗/poet.song.165000.json','["望望吳楚隔，悠悠兄弟思。", "經行偶來過，喜極爲成詩。", "二父已名世，諸郎皆好辭。", "誰云前輩遠，未覺此風衰。"]'),
('f18664e1-2f80-40e9-bf4e-887820dd20d0','呈全真魯山','趙蕃','宋','宋诗','song-poetry','','[]','有懷思放曠，茲地窘幽潛。',48,'全唐诗/poet.song.165000.json','["有懷思放曠，茲地窘幽潛。", "屋脊山微見，庭前樹莫添。", "把書唯立壁，扶杖祗巡簷。", "深羨憑江宅，登臨萬象兼。"]'),
('622f75df-9085-4019-b60e-285f60101331','呈唐德輿兼寄呈可久三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','白頭四海客，青眼幾何人。',48,'全唐诗/poet.song.165000.json','["白頭四海客，青眼幾何人。", "况復平生舊，端殊數面親。", "文聲雖益振，仕簿亦何屯。", "好在章江水，聊堪濯世塵。"]'),
('687cabcc-e254-41bc-8163-26c3fe8f090d','呈唐德輿兼寄呈可久三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','前歲長安雪，從公飲屢過。',48,'全唐诗/poet.song.165000.json','["前歲長安雪，從公飲屢過。", "放談成絕歎，狂態亦悲歌。", "我仕魚緣竹，公行漩繞渦。", "相逢雖足慰，相別奈愁何。"]'),
('c1693363-03ac-4345-9e2f-5bf23e6f9109','呈唐德輿兼寄呈可久三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','敬作沙隨問，歸來安穩不。',48,'全唐诗/poet.song.165000.json','["敬作沙隨問，歸來安穩不。", "一官成棄却，微恙想今瘳。", "詩篋猶堪倒，錢囊不用謀。", "更思從二老，何日具扁舟。"]'),
('3918d206-6179-4be3-9f3c-66bc14df8fd6','呈陳深父二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','相望僅一水，相賒逾十年。',48,'全唐诗/poet.song.165000.json','["相望僅一水，相賒逾十年。", "尋君向蕭寺，歎我已華顛。", "老至是其理，窮來當益堅。", "雲深雪溪樹，塵暗曲肱弦。"]'),
('56e3256d-8cef-4a75-9432-deed34fdc970','呈陳深父二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','役役到番國，悠悠誰故人。',48,'全唐诗/poet.song.165000.json','["役役到番國，悠悠誰故人。", "僧房半牢落，湖水失清淪。", "我豈倚樓趙，君真驚座陳。", "何爲辱傾倒，相與盡情親。"]'),
('03338526-ddc9-4a6e-8061-dce5387875f1','呈晁舅祖叔藴','趙蕃','宋','宋诗','song-poetry','','[]','輩行雖如祖，年齡僅可兄。',48,'全唐诗/poet.song.165000.json','["輩行雖如祖，年齡僅可兄。", "經過得屢見，文字有同盟。", "門戶當深責，饑寒厭此生。", "良農務穮蔉，初不計秋成。"]'),
('320c4f21-47cc-47cc-8283-a34e9e756f50','呈許深父及之','趙蕃','宋','宋诗','song-poetry','','[]','路入分宜縣，心馳月旦評。',48,'全唐诗/poet.song.165000.json','["路入分宜縣，心馳月旦評。", "參差萬木合，曲折亂灘行。", "江右孰茂宰，斯人垂大名。", "鳬飛看公入，鳶墮黯余情。"]'),
('1d9c05cf-56bb-427e-a8a2-46971ca2a6e8','俗有雪上加霜之諺今日之謂也二詩呈知縣契丈教授尊兄  其一','趙蕃','宋','宋诗','song-poetry','','[]','歎我貧兼病，當渠雪上霜。',48,'全唐诗/poet.song.165000.json','["歎我貧兼病，當渠雪上霜。", "忍饑無異術，炙背有奇方。", "重憶茅簷下，還嗟楚水傍。", "官曹竟疎闊，詩病得商量。"]'),
('f563e58f-3450-4022-b1ef-905a1f490845','俗有雪上加霜之諺今日之謂也二詩呈知縣契丈教授尊兄  其二','趙蕃','宋','宋诗','song-poetry','','[]','雨雪欣能霽，冰霜苦未和。',48,'全唐诗/poet.song.165000.json','["雨雪欣能霽，冰霜苦未和。", "體孱寒有相，絮敗暖無多。", "二妙今誰敵，有詩皆可歌。", "暗中知沈謝，灰裏撥陰何。"]'),
('17cc494c-a10b-457f-a3dd-9de6b03f0000','呈李思永','趙蕃','宋','宋诗','song-poetry','','[]','往見劉夫子，得聞君姓名。',48,'全唐诗/poet.song.165000.json','["往見劉夫子，得聞君姓名。", "飄零方客路，邂逅若平生。", "學要精微講，文須仔細評。", "道林并嶽麓，他日得經行。"]'),
('3398ba22-a1db-4f0e-a519-2dceb3a4cb51','呈宋伯潛','趙蕃','宋','宋诗','song-poetry','','[]','學有南軒派，文仍二宋家。',48,'全唐诗/poet.song.165000.json','["學有南軒派，文仍二宋家。", "泉源端有本，玉立更無瑕。", "儻遂成三徑，當從讀五車。", "朋游有如此，未恨落長沙。"]'),
('c30b9c0a-841f-4fac-89f7-2ee3d72e9bc7','再呈伯潛','趙蕃','宋','宋诗','song-poetry','','[]','政爾羞餘子，胡然說故家。',48,'全唐诗/poet.song.165000.json','["政爾羞餘子，胡然說故家。", "人方笑藍縷，君乃不疵瑕。", "厚義重縞紵，空言非笠車。", "委思精絕處，百鍊出披沙。"]'),
('d3c76ccd-6243-4573-a556-b10fc6309e2c','再呈思永','趙蕃','宋','宋诗','song-poetry','','[]','寶氣疑猶在，諸公盛得名。',48,'全唐诗/poet.song.165000.json','["寶氣疑猶在，諸公盛得名。", "新知雖可樂，舊恨卒難平。", "我句野無格，君詩工莫評。", "青錢宜妙選，墨綬盍遲行。"]'),
('3567ec27-c0ab-40c5-a8e0-56cfe540f56e','呈劉子卿四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','南渡六十載，况談元祐時。',48,'全唐诗/poet.song.165000.json','["南渡六十載，况談元祐時。", "故家垂欲盡，遺事莽難知。", "文字既多舛，傳聞寧破疑。", "唯公有源委，萬折必東之。"]'),
('87fc7fa9-b8cf-4325-939a-d21b43534922','呈劉子卿四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','近喜周公相，初傳薦士章。',48,'全唐诗/poet.song.165000.json','["近喜周公相，初傳薦士章。", "非才孰爲治，與國倍生光。", "故國異喬木，白駒空食場。", "彈冠與結綬，吾道不其昌。"]'),
('a316aded-7b4d-4418-a141-500ef4dd5f06','呈劉子卿四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','王氣東南盛，流風西北疎。',48,'全唐诗/poet.song.165000.json','["王氣東南盛，流風西北疎。", "往猶稱旅寓，今迺逐鄉閭。", "要熟兒童聽，惟傳父祖書。", "如公不一二，安得亦相於。"]'),
('d4b28a32-91c1-447b-98db-90bfcdcfa221','呈劉子卿四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','往自清江別，于今近十年。',48,'全唐诗/poet.song.165000.json','["往自清江別，于今近十年。", "依僧聊避暑，擁節會朝天。", "我愧不如昔，公乎真過前。", "政規期斷手，明本已終篇。"]'),
('bc6866ac-69d5-4259-bf0f-23efecfff775','別邢公昭丈','趙蕃','宋','宋诗','song-poetry','','[]','適遠能忘別，衝行敢憚泥。',48,'全唐诗/poet.song.165000.json','["適遠能忘別，衝行敢憚泥。", "野航初喚渡，茅屋正啼鷄。", "雨後妨梅步，風前對竹題。", "因公動高興，憶我舊幽棲。"]'),
('23cb1d9a-7dd3-4906-80e3-84719658a5be','次韻周欽止送別','趙蕃','宋','宋诗','song-poetry','','[]','不見送將歸，惟聞遠別離。',48,'全唐诗/poet.song.165000.json','["不見送將歸，惟聞遠別離。", "身今成老大，官豈計高卑。", "蕭寺已移酒，便人還枉詩。", "臨風三復罷，有恨落無涯。"]'),
('1b43674d-f430-43a3-8be0-31d29d4e2fe0','留別子肅子儀三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','度橋遵野徑，夾樹啟籬門。',48,'全唐诗/poet.song.165000.json','["度橋遵野徑，夾樹啟籬門。", "剝啄傳呼疾，周旋色笑溫。", "萬金纔到幾，一棹復過村。", "却恨儂來獨，飄零說在原。"]'),
('67e34094-0ec2-4af0-a7ee-e4ff862f561f','留別子肅子儀三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','長年夢黄堰，今日飲紅灰。',48,'全唐诗/poet.song.165000.json','["長年夢黄堰，今日飲紅灰。", "徑綠無多草，庭陰半是梅。", "海棠留雨醉，楊柳傲風媒。", "對此渾無事，一杯重一杯。"]'),
('7044512f-4437-463a-adc3-491b7907aa30','留別子肅子儀三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','一別動五載，人生都幾何。',48,'全唐诗/poet.song.165000.json','["一別動五載，人生都幾何。", "談端方間起，行色又犇波。", "賸欲攄離語，不成翻醉歌。", "飛騰與流浪，已矣兩無那。"]'),
('2f264bcc-9b2f-4cc1-975d-bca27af1e7e8','留別陳明叔兼屬胡仲威五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','我去孰君友，君留誰我遊。',48,'全唐诗/poet.song.165000.json','["我去孰君友，君留誰我遊。", "定應緣宿契，不待分今投。", "年事鬢俱白，時名詩獨優。", "未知茲日別，重見又何由。"]'),
('b5f4ef15-5b60-4a18-be76-9f742623f26b','留別陳明叔兼屬胡仲威五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','論事從違數，題詩竄定頻。',48,'全唐诗/poet.song.165000.json','["論事從違數，題詩竄定頻。", "客君徒得重，愛我不言貧。", "薄俗無兄弟，我曹相主賓。", "別觴終作惡，別語要須真。"]'),
('e27bb8fd-e619-465b-8821-ae5bba2810a0','留別陳明叔兼屬胡仲威五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','簿領三年吏，江天百里居。',48,'全唐诗/poet.song.165000.json','["簿領三年吏，江天百里居。", "我非拘雁鶩，君乃傲樵漁。", "得譽且得謗，似高仍似疎。", "襄陽耆舊傳，書子定聯予。"]'),
('1762c895-8b81-4da4-a55c-30d1b93275ac','留別陳明叔兼屬胡仲威五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','我覓祠官俸，君携異縣書。',48,'全唐诗/poet.song.165000.json','["我覓祠官俸，君携異縣書。", "一窮直若此，五字果何如。", "底用頻看鏡，終當老荷鉏。", "未知渠作計，頗亦似儂無。"]'),
('79b36ddb-b265-4c2e-b7fd-f1da13a55640','留別陳明叔兼屬胡仲威五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','汲汲求交友，良由不敏姿。',48,'全唐诗/poet.song.165000.json','["汲汲求交友，良由不敏姿。", "風流伯始後，文獻澹菴師。", "此士世亦寡，因君交不疑。", "倡酬凡幾紙，別後慰相思。"]'),
('1f4f6a7f-8a57-4dca-a2ec-06a0efe35a0b','留別折子明丈二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','久作湘中客，數從林下遊。',48,'全唐诗/poet.song.165000.json','["久作湘中客，數從林下遊。", "契繇先世敘，誼向古人求。", "我敢逃黄綬，公寧卧白頭。", "廟堂有北客，人物想中州。"]'),
('92b79ae2-06d8-4fb9-99ea-091c31d15b89','留別折子明丈二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','行橐何輕重，新詩得卷藏。',48,'全唐诗/poet.song.165000.json','["行橐何輕重，新詩得卷藏。", "猶須與先集，併爲補山房。", "更欲詢言行，持將益廢忘。", "匆匆語難盡，莽莽恨空長。"]'),
('7a2abad0-32f4-436a-9560-87891f83fc29','留別徐季純','趙蕃','宋','宋诗','song-poetry','','[]','隠墅夙未到，扁舟空屢經。',48,'全唐诗/poet.song.165000.json','["隠墅夙未到，扁舟空屢經。", "灘長石璧寺，洲遶縠波亭。", "厚祿頭空白，新知眼倍青。", "雖云遽離闊，也足慰飄零。"]'),
('01b8b951-3bbe-4d54-a0b8-6d9370f2fc6e','重別成父二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','盡室蘄偕隠，持家又即浮。',48,'全唐诗/poet.song.165000.json','["盡室蘄偕隠，持家又即浮。", "可憐居不易，還是食爲謀。", "風雨連朝暗，江山千里遊。", "不能携汝去，翻覺重吾憂。"]'),
('d911137b-0ec0-42c3-b9bf-a9ab014e1188','重別成父二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','中原歸尚棘，三墓久成蕪。',48,'全唐诗/poet.song.165000.json','["中原歸尚棘，三墓久成蕪。", "未議增封樹，先宜禁牧芻。", "便須營虎落，將以護龍雛。", "不用平安報，惟期剪伐無。"]'),
('2325bbb9-3afc-4f0d-bbb3-b98d97c94621','送恭叔赴海門尉端叔約同過湘西酌別四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','寓舍我至晚，官期君已催。',48,'全唐诗/poet.song.165000.json','["寓舍我至晚，官期君已催。", "猶當載酒別，共作訪山來。", "雪谷看題字，風雩話昔開。", "樂山并樂水，隨處一裴回。"]'),
('a407c3de-980c-4b3f-b59e-d511126b97a9','送恭叔赴海門尉端叔約同過湘西酌別四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君歎父兄別，我嗟朋友疎。',48,'全唐诗/poet.song.165000.json','["君歎父兄別，我嗟朋友疎。", "窮冬仍遠道，異縣復離居。", "僅得追隨再，何由懷抱攄。", "因來湖外使，爲寄海邊書。"]'),
('2a6b58bd-8c1c-40ef-9e06-c6e20842dadb','送恭叔赴海門尉端叔約同過湘西酌別四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','楚岫新經雪，湘江半露沙。',48,'全唐诗/poet.song.165000.json','["楚岫新經雪，湘江半露沙。", "蕭蕭斷行鴈，渺渺後棲鴉。", "別意渾相似，詩成祇重嗟。", "未嫌杯酒滿，直恐鬢霜加。"]'),
('43944c54-a8e2-45eb-92f2-762a0165a937','送恭叔赴海門尉端叔約同過湘西酌別四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','入自芝蘭室，重之珠玉淵。',48,'全唐诗/poet.song.165000.json','["入自芝蘭室，重之珠玉淵。", "一官從草草，萬卷本便便。", "對鏡平多壘，閒郊闢廢田。", "尉曹應事少，賓友定誰延。"]'),
('1868be59-2ed7-4730-8824-fbfef962c9e0','留別徐斯遠時斯遠將赴朱晦菴之約三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','共有山林趣，相期問學功。',48,'全唐诗/poet.song.165000.json','["共有山林趣，相期問學功。", "一官重此去，三逕幾時同。", "我鬢因詩白，君顔非酒紅。", "從遊縱有日，羸疾柰相攻。"]'),
('0d1a34df-495b-4f20-94a1-1c57163c2105','留別徐斯遠時斯遠將赴朱晦菴之約三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君質故甚美，加之仍得師。',48,'全唐诗/poet.song.165000.json','["君質故甚美，加之仍得師。", "今爲李君御，何後老人期。", "念欲通名姓，還憂辱棄遺。", "何當武夷下，與子共追隨。"]'),
('cbce2c26-3b99-4eb8-b57a-5727ce0d2342','留別徐斯遠時斯遠將赴朱晦菴之約三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','事變將酬萬，身分若化千。',48,'全唐诗/poet.song.165000.json','["事變將酬萬，身分若化千。", "淒涼辭古寺，辛苦問江船。", "秋得村村雨，凉生樹樹蟬。", "重哦五七字，還約四三年。"]'),
('283d1483-c962-4204-b1bf-f1029c6e40cf','坐中留別正之','趙蕃','宋','宋诗','song-poetry','','[]','已別還成住，多君意甚真。',48,'全唐诗/poet.song.165000.json','["已別還成住，多君意甚真。", "自非敦友好，寧復見情親。", "月已秋中過，雨如春暮頻。", "臨分匪杯酒，幽獨恐傷神。"]'),
('fa6f8cf5-46cb-4180-8e2c-378359294898','別趙信州','趙蕃','宋','宋诗','song-poetry','','[]','拍拍桃花水，輕輕蓮葉舟。',48,'全唐诗/poet.song.165000.json','["拍拍桃花水，輕輕蓮葉舟。", "生憎衝野馬，失喜見沙鷗。", "漫浪端如此，饑寒信有不。", "未探懷玉藴，且訪九華幽。"]'),
('b7a05744-fc25-4bcf-a3c0-fea8b887bcbf','別趙叔','趙蕃','宋','宋诗','song-poetry','','[]','漢廷無出右，天下舉歸心。',48,'全唐诗/poet.song.165000.json','["漢廷無出右，天下舉歸心。", "歲晚雪霜榦，春餘桃李陰。", "班崇貳卿貴，掾落五溪深。", "勿謂無回鴈，郵傳可嗣音。"]'),
('34fe0bf7-b489-495a-a660-f8dadeeee40b','別宗父','趙蕃','宋','宋诗','song-poetry','','[]','許日問何滯，今晨真遂行。',48,'全唐诗/poet.song.165000.json','["許日問何滯，今晨真遂行。", "人生苦飄泊，歲事復崢嶸。", "鶴髮欠亡恙，燕雛憐未成。", "臨分再三語，不爲別離情。"]'),
('32d80558-e647-430b-b6dc-31a9841bbbe5','別馬莊甫','趙蕃','宋','宋诗','song-poetry','','[]','邂逅成深識，慇懃不作遥。',48,'全唐诗/poet.song.165000.json','["邂逅成深識，慇懃不作遥。", "鵝湖書後約，汭口騎能招。", "奔逸君誠俊，衰摧我不聊。", "嗜書甘寂寞，破敵看嫖姚。"]'),
('fbcf9a52-d6a9-45bd-912b-49d46be5ce16','別楊謹仲','趙蕃','宋','宋诗','song-poetry','','[]','籬竹又離籜，沼荷還疊錢。',48,'全唐诗/poet.song.165000.json','["籬竹又離籜，沼荷還疊錢。", "我來成佇立，公爲起高眠。", "清靜子雲宅，扶疎陶令篇。", "三年渾易爾，此別各蒼然。"]'),
('5795bac6-2fab-4629-92f9-8ce474e49b17','別季承','趙蕃','宋','宋诗','song-poetry','','[]','兼旬眠食同，慷慨豁心胸。',48,'全唐诗/poet.song.165000.json','["兼旬眠食同，慷慨豁心胸。", "尚喜斯文在，未憂吾道窮。", "鵝湖余舊歷，鷲嶺子新逢。", "四海均同宇，休言兩地中。"]'),
('969fbc5e-4561-40ab-9c20-092a1250667d','初六日呈明叔','趙蕃','宋','宋诗','song-poetry','','[]','冷澹清明節，蕭疎斑白翁。',48,'全唐诗/poet.song.165000.json','["冷澹清明節，蕭疎斑白翁。", "不知春事減，但見綠陰重。", "坐卧書窗裏，陰晴啼鳥中。", "年齡故爾似，貧病亦應同。"]'),
('77bba743-c787-4e20-86ba-8d34988cfea3','二十五日呈明叔','趙蕃','宋','宋诗','song-poetry','','[]','七十且强半，駸駸數日間。',48,'全唐诗/poet.song.165000.json','["七十且强半，駸駸數日間。", "不成悲白髮，猶說愛青山。", "五斗雖爲累，千篇政不慳。", "與君同甲子，此事合相關。"]'),
('c2e1e6d5-898d-46e3-bfae-18e3fe42fa95','別近呈明叔','趙蕃','宋','宋诗','song-poetry','','[]','靖節甘忤俗，子雲空解嘲。',48,'全唐诗/poet.song.165000.json','["靖節甘忤俗，子雲空解嘲。", "紛紛多面友，了了獨心交。", "四海歎浮梗，三年嗟繫匏。", "語離無幾日，梅蕊况江郊。"]'),
('81f32c7f-a176-4534-91c5-b2b1182ba726','再呈明叔','趙蕃','宋','宋诗','song-poetry','','[]','欲過江天閣，出門如有方。',48,'全唐诗/poet.song.165000.json','["欲過江天閣，出門如有方。", "乍聞禽磔磔，還是雨浪浪。", "放意官曹外，關心藥裹旁。", "聽渠桃李退，蘭斛政幽香。"]'),
('b598f9fc-a16f-45c6-a56e-5b55dea9d388','呈潘文叔二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','嶽寺分携後，郵亭邂逅時。',48,'全唐诗/poet.song.165000.json','["嶽寺分携後，郵亭邂逅時。", "鳴鞭萍實驛，分韻木犀詩。", "契闊書忘素，飄零鬢益絲。", "我歸寧偶爾，君至忽於斯。"]'),
('ef39b8c0-d129-4c0a-80c0-357620af9c34','呈潘文叔二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','寓舍莓苔合，春郊花草香。',48,'全唐诗/poet.song.165000.json','["寓舍莓苔合，春郊花草香。", "忽逢寧比料，欲語未能長。", "大阮爲勿藥，阿連欣對牀。", "嗟予重多感，有弟各殊方。"]'),
('28a75457-45bc-47a6-8c23-44cc1b55fb0f','呈叔文諸公','趙蕃','宋','宋诗','song-poetry','','[]','村村迎湫水，戶戶𬋖鑪香。',48,'全唐诗/poet.song.165000.json','["村村迎湫水，戶戶𬋖鑪香。", "何以救我穡，但知呼彼蒼。", "儻寬饑欲死，聊聽醒而狂。", "困極惟思睡，詩來得助凉。"]'),
('1f263972-77ee-4e48-8308-e632476ff354','和答黎季成送行','趙蕃','宋','宋诗','song-poetry','','[]','自坐還山計，如同去魯情。',48,'全唐诗/poet.song.165000.json','["自坐還山計，如同去魯情。", "水風元不斷，山月每同明。", "試問詩能和，何如酒共傾。", "吾家近京驛，側耳聽車聲。"]'),
('959edbaf-78bd-4e41-a500-deec2a945c47','蕃近有鄙句簡諸公而廣文先生專以見貺盛意自不可不答','趙蕃','宋','宋诗','song-poetry','','[]','居然自駑驥，陋矣說玄黄。',48,'全唐诗/poet.song.165000.json','["居然自駑驥，陋矣說玄黄。", "章貢昔連地，沅湘今一鄉。", "談端驚絕倒，詩學味尤長。", "對月他時白，披風此日凉。"]'),
('52d94acc-6817-48e9-9340-56b3dd621f24','再和諸公','趙蕃','宋','宋诗','song-poetry','','[]','官故玄尚白，山能青又黄。',48,'全唐诗/poet.song.165000.json','["官故玄尚白，山能青又黄。", "娵隅學蠻詠，欵乃和漁鄉。", "世用有公等，我才無日長。", "盍簪休間闊，回首易悲凉。"]'),
('b11caab6-62fb-4033-9d7a-c79510847ca3','簡黄子耕','趙蕃','宋','宋诗','song-poetry','','[]','不見吾叔度，侵尋將六年。',48,'全唐诗/poet.song.165000.json','["不見吾叔度，侵尋將六年。", "林間迂子步，江上望余船。", "會合信不易，往來成屢愆。", "孤山梅未老，曷日訪三賢。"]'),
('b41935ba-a295-41da-84fe-dde4086783b9','簡李伯仁節甫','趙蕃','宋','宋诗','song-poetry','','[]','溧水忽再到，清明無隔晨。',48,'全唐诗/poet.song.165000.json','["溧水忽再到，清明無隔晨。", "一翁方上府，二季曲留賓。", "詩律歎仍舊，鬢霜驚漸新。", "君家真李杜，我乃愧黄陳。"]'),
('1e1c9c21-b50d-4902-a169-2e98c83ede14','簡彥博','趙蕃','宋','宋诗','song-poetry','','[]','憶昨連郛住，猶爲解榻期。',48,'全唐诗/poet.song.165000.json','["憶昨連郛住，猶爲解榻期。", "古書相是正，餘事劇娛嬉。", "近者間何闊，懷哉我所思。", "如聞穫稻畢，當是入山時。"]'),
('7deba11b-dd3e-4fff-bc25-6b3076582d7b','簡元衡','趙蕃','宋','宋诗','song-poetry','','[]','鳩喚林深擁，蛙鳴草亂科。',48,'全唐诗/poet.song.165000.json','["鳩喚林深擁，蛙鳴草亂科。", "群生爲疵癘，首夏失清和。", "謝病游故倦，尊天問可何。", "政須聞妙語，一爲洗煩痾。"]'),
('0f0af6e0-a95f-4901-a69a-138b449f37e2','再簡元衡','趙蕃','宋','宋诗','song-poetry','','[]','積雨朝收礎，清陰晝滿庭。',48,'全唐诗/poet.song.165000.json','["積雨朝收礎，清陰晝滿庭。", "驟乾無雨候，忽動有風輕。", "藥裹長羸疾，茶甌蹔一醒。", "故人纔咫尺，願見兀如扃。"]'),
('e7e96bba-2512-46b4-b5af-4e5a3bd998b1','用初三日韻簡伯玉昆仲','趙蕃','宋','宋诗','song-poetry','','[]','雨勢忽已過，雲峰空復生。',48,'全唐诗/poet.song.165000.json','["雨勢忽已過，雲峰空復生。", "蹔能蘇暑病，未足慰農情。", "同社推詩好，今宵况月明。", "三人非對影，難弟與難兄。"]'),
('7187cadd-2f8d-436d-bb9f-1b9738c672ef','遠父往富沙兼簡馬莊父二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','徐郎既吳越，王子又甌閩。',48,'全唐诗/poet.song.165000.json','["徐郎既吳越，王子又甌閩。", "孰與還仍往，惟餘病與貧。", "尚寒花有信，欲盡雨催春。", "子去寧關抱，余留獨損神。"]'),
('699e5fff-2bda-4987-b0a2-d9fb4fcc24bf','遠父往富沙兼簡馬莊父二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','子過鉛山縣，知名有尉曹。',48,'全唐诗/poet.song.165000.json','["子過鉛山縣，知名有尉曹。", "談端抽繭紝，文力壯波濤。", "見子心應識，思渠首屢搔。", "共爲徐庶友，而獨不能高。"]'),
('a6a25207-13a4-485a-9541-5152fb2254f0','念欲春遊春既莫矣而在伯微恙不近杯勺作小詩代簡便呈沅陵何鄧二尉曹','趙蕃','宋','宋诗','song-poetry','','[]','屢有一杯約，况今三月來。',48,'全唐诗/poet.song.165000.json','["屢有一杯約，况今三月來。", "屬君繙藥裹，而我欠詩材。", "楚塞稀紅蕊，僧坊剩綠苔。", "幾時能出郭，分韻與徘徊。"]'),
('7f0f78da-a4a4-4286-b42d-5c032f1e532d','十一日簡王進之','趙蕃','宋','宋诗','song-poetry','','[]','曉枕聞簷溜，閒筇立寺門。',48,'全唐诗/poet.song.165000.json','["曉枕聞簷溜，閒筇立寺門。", "宿酲連卯酒，幽趣落無言。", "山色丹青濕，梅花璧玉溫。", "誰能此乘興，風味昔人存。"]'),
('c044d2a1-17f2-42b1-844f-80d09b9a680a','簡徐季益二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','野寺鐘鳴後，溪橋雨合時。',48,'全唐诗/poet.song.165000.json','["野寺鐘鳴後，溪橋雨合時。", "杖藜能過我，酌酒更論詩。", "意作匆匆別，仍愆得得期。", "近知疎問訊，不那費懷思。"]'),
('e780a827-6505-4e28-89e8-47e5b0f03bcf','簡徐季益二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','好士今誰是，憐才亦漫云。',48,'全唐诗/poet.song.165000.json','["好士今誰是，憐才亦漫云。", "詎須隨進士，直擬慕徵君。", "確論終當有，浮言斷莫聞。", "兒曹與餘子，錄錄更紛紛。"]'),
('ad1b15aa-4c18-431c-90eb-1fa2eb8de161','簡王元宗','趙蕃','宋','宋诗','song-poetry','','[]','相望兩招提，林深路不迷。',48,'全唐诗/poet.song.165000.json','["相望兩招提，林深路不迷。", "微軀敢高卧，借屋且幽棲。", "問訊聊題句，經過阻杖藜。", "良由日日雨，山徑亦成泥。"]'),
('3ebf3ba5-edca-4483-b005-8b2db1afdf13','簡斯遠兄','趙蕃','宋','宋诗','song-poetry','','[]','已辦入城府，尚留緣雨陰。',48,'全唐诗/poet.song.165000.json','["已辦入城府，尚留緣雨陰。", "相期著屐過，空想掉頭吟。", "子故因貧出，余寧歎老侵。", "鵷鸞滿臺閣，麋鹿自山林。"]'),
('0c117b5b-7367-484d-9d20-4f9e2047c15d','簡文顯','趙蕃','宋','宋诗','song-poetry','','[]','敬問周夫子，端居又半春。',48,'全唐诗/poet.song.165000.json','["敬問周夫子，端居又半春。", "初無酒作祟，合有句如神。", "桃李已陳迹，谿山同故人。", "何能過茅宇，談笑奉清真。"]'),
('533d9514-0a6f-4523-89b9-bbfad9013bb6','簡全真','趙蕃','宋','宋诗','song-poetry','','[]','方喧思獨坐，當靜想清言。',48,'全唐诗/poet.song.165000.json','["方喧思獨坐，當靜想清言。", "我掃庭前樹，君憑江上軒。", "有詩煩共賦，無酒與重論。", "既乏公田秫，仍孤老瓦盆。"]'),
('1a71e753-2ca8-4749-b545-3b8b658290fb','過周文顯所居','趙蕃','宋','宋诗','song-poetry','','[]','不謂於茲世，而能有若人。',48,'全唐诗/poet.song.165000.json','["不謂於茲世，而能有若人。", "藤蘿爲遮屋，圖史漫娛身。", "安邑誰爲令，黔婁自守貧。", "他時獨行傳，端可並麒麟。"]'),
('06e12f18-4720-4d6f-98d4-3cb51ed67cc4','喜見周司法和詩有贈仍用元韻','趙蕃','宋','宋诗','song-poetry','','[]','路絕嶺梅贈，江摇沅茝春。',48,'全唐诗/poet.song.165000.json','["路絕嶺梅贈，江摇沅茝春。", "敢云傾蓋故，喜甚誦詩新。", "刀筆非吾事，文章可致身。", "江陵法曹掾，寧久滯斯人。"]'),
('68cd684f-78d5-455e-acee-76e183d982c4','至日與明叔逸及明叔之子凉孫飲','趙蕃','宋','宋诗','song-poetry','','[]','至日還爲客，窮愁亦去年。',48,'全唐诗/poet.song.165000.json','["至日還爲客，窮愁亦去年。", "陰陽自升伏，老壯只推遷。", "易險安常度，呴濡無妄憐。", "兒能壽翁酒，不必問遇賢。"]'),
('f72e8d5a-8295-47fe-92f9-481a11da219b','過介庵舊宅','趙蕃','宋','宋诗','song-poetry','','[]','悠悠西州路，慘慘日暮雲。',48,'全唐诗/poet.song.165000.json','["悠悠西州路，慘慘日暮雲。", "天不慦此老，世孰張吾軍。", "成都揚雄宅，青山太白墳。", "可憐車馬迹，不如鷗鷺羣。"]'),
('4e79eb92-6efc-4fa9-b9dd-1091233d9c6d','連日與邢伯言兄弟飲成四十字','趙蕃','宋','宋诗','song-poetry','','[]','江上風雖橫，林間月自新。',48,'全唐诗/poet.song.165000.json','["江上風雖橫，林間月自新。", "探囊看墨妙，酌酒話情親。", "感歎思前日，飄零媿此身。", "未妨頻夕醉，初不污車茵。"]'),
('2b4c5315-ba4e-49c0-a7b5-325546844c3c','雨中與公擇對飲已而大醉既醒作此','趙蕃','宋','宋诗','song-poetry','','[]','身世一飄摇，羈愁兩寂寥。',48,'全唐诗/poet.song.165000.json','["身世一飄摇，羈愁兩寂寥。", "怨歌空耿耿，晚雨况蕭蕭。", "飲强真能醉，詩成或當謠。", "明朝對清鏡，鬢恐十分凋。"]'),
('3f569b86-2b03-48f8-984f-073c3c9afe29','與伯玉元衡大聲兄弟飲','趙蕃','宋','宋诗','song-poetry','','[]','何方應雨落，此地祇凉生。',48,'全唐诗/poet.song.165000.json','["何方應雨落，此地祇凉生。", "杯酒偶相屬，晤言聊敘情。", "登樓念王粲，促席想淵明。", "鄉里無新故，情親總弟兄。"]'),
('c8ade2d2-c192-4a7e-97e4-1666debbae00','劉萬二弟置酒與八九兄同飲','趙蕃','宋','宋诗','song-poetry','','[]','每憶疎詩卷，何期共酒尊。',48,'全唐诗/poet.song.165000.json','["每憶疎詩卷，何期共酒尊。", "高棲子苕霅，孤宦我湘沅。", "暮夜風仍吼，途窮志自存。", "悠悠幾山嶽，泛泛一乾坤。"]'),
('fc4c97ba-a8fb-40e6-86b3-dbc3723a9422','二月初十日自荻浦絕湖三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','二月風濤壯，扁舟性命輕。',48,'全唐诗/poet.song.165000.json','["二月風濤壯，扁舟性命輕。", "白頭高浪接，青眼遠山橫。", "客子空懷怖，漁家自樂生。", "須渠一杯酒，助我五言城。"]'),
('17ba0214-dcd8-489c-8304-78519af04366','二月初十日自荻浦絕湖三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','遠浪已摇目，疾風仍打頭。',48,'全唐诗/poet.song.165000.json','["遠浪已摇目，疾風仍打頭。", "翩翻仰飛鳥，矯捷羨輕鷗。", "湖有萬頃白，舟才一葉浮。", "意行從泛泛，吾道本悠悠。"]'),
('a9f5e3da-28c7-4301-950f-8fb2b88c384b','二月初十日自荻浦絕湖三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','倚頼尊中酒，枝梧卷裏詩。',48,'全唐诗/poet.song.165000.json','["倚頼尊中酒，枝梧卷裏詩。", "貧嗟居不易，境對語成危。", "往日行猶記，沖風去不疑。", "舟師笑相謂，未有若人癡。"]'),
('aad8845f-93ee-4ce6-b0d7-ad6a1c55dc56','三月八日發舟後作','趙蕃','宋','宋诗','song-poetry','','[]','沙步行初改，津亭望且遥。',48,'全唐诗/poet.song.165000.json','["沙步行初改，津亭望且遥。", "青山出圖畫，白鷺立風標。", "境熟詩難就，愁深酒易消。", "雲歸還漠漠，雨靜復蕭蕭。"]'),
('d8df81bf-b22f-444a-88a7-37ed2e359be4','寄建寧韓尚書二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','今代韓夫子，頻年刺兩州。',48,'全唐诗/poet.song.165000.json','["今代韓夫子，頻年刺兩州。", "官崇古常伯，地重漢諸侯。", "父老記茂宰，山川皆昔遊。", "懸知里閭化，不待教條修。"]'),
('8fd0f4f2-8dfb-4aa8-a80a-7213ceadc8dd','寄建寧韓尚書二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','宰席猶虛位，尚書合賜環。',48,'全唐诗/poet.song.165000.json','["宰席猶虛位，尚書合賜環。", "進賢同拔茹，去佞已無山。", "誥命從天下，延登指日間。", "蘄公爲大厦，我亦會歡顔。"]'),
('087ca2af-15e8-4685-9f31-40b03804dc9c','三月審知以余行有日置酒於智門寺後竹間小亭時與者王彥博審知之姪彥章余之弟成父審知命以尊前失詩流爲韻分得流字書以呈之','趙蕃','宋','宋诗','song-poetry','','[]','林下有高興，眼前無此流。',48,'全唐诗/poet.song.165000.json','["林下有高興，眼前無此流。", "並溪村逕入，背佛野亭投。", "綠竹依人好，紅蕖取意秋。", "病多寬酒債，別近耿離憂。"]'),
('a5bdf25c-0825-4ac8-bcc0-c2cb77e96228','讀東坡和陶詩','趙蕃','宋','宋诗','song-poetry','','[]','食已無餘事，坡詩信手繙。',48,'全唐诗/poet.song.165000.json','["食已無餘事，坡詩信手繙。", "飄零落蠻蜑，收拾重璵璠。", "未易窮關鍵，纔能味語言。", "向來陶謝並，今日要重論。"]'),
('24e63d96-b81f-4766-9709-9529d5c187b7','讀王有道詩','趙蕃','宋','宋诗','song-poetry','','[]','校書非隱遯，逢亂偶棲遲。',48,'全唐诗/poet.song.165000.json','["校書非隱遯，逢亂偶棲遲。", "少日治安策，暮年忠義詩。", "空聞狩岐隴，不見頌浯溪。", "有墓荒叢棘，無祠奠酒巵。"]'),
('fd876c6f-dec1-4695-9735-e74cb573633f','讀林子仁詩','趙蕃','宋','宋诗','song-poetry','','[]','連林泥滑滑，遍地苹青青。',48,'全唐诗/poet.song.165000.json','["連林泥滑滑，遍地苹青青。", "多病愁難却，春風夢已經。", "曾過蘄水郡，不見少微星。", "獨行慙方駕，清詩許乞靈。"]'),
('27b99072-55d7-489d-8ed0-cbac32e907d0','王璠伯玉携詩見過二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','大熱有如此，凉風安在哉。',48,'全唐诗/poet.song.165000.json','["大熱有如此，凉風安在哉。", "書憑長日度，客欠好懷開。", "豹立妨看竹，蟾飛爲掃槐。", "欣然王氏子，枉步袖詩來。"]'),
('55037062-7b7b-45bc-8840-23ebcb73244d','王璠伯玉携詩見過二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','故國聞江左，名家數建隆。',48,'全唐诗/poet.song.165000.json','["故國聞江左，名家數建隆。", "南遊新識內，東里舊鄉中。", "有句君真癖，無詩我浪窮。", "更期風月夕，相與課新功。"]'),
('1584abe6-afc4-40f7-a988-237776abda9f','二十四日一日作十詩季承同之既罷復書四十字並呈季承','趙蕃','宋','宋诗','song-poetry','','[]','米盡不憂饑，行行且賦詩。',48,'全唐诗/poet.song.165000.json','["米盡不憂饑，行行且賦詩。", "相看一大笑，從謂兩真癡。", "未用追元白，聊須效陸皮。", "流傳君不媿，附益我奚爲。"]'),
('4041e412-b26f-4e3c-bcef-d8d91b83951b','偶作二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','舊箑已成揮，還披御臘衣。',48,'全唐诗/poet.song.165000.json','["舊箑已成揮，還披御臘衣。", "乘除固人事，變化亦天機。", "道路飄零久，形容少壯非。", "無徒微祿眷，長與故人違。"]'),
('a18d2926-e829-46ae-9d74-6afe26616425','偶作二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','未仕思從仕，言歸盍賦歸。',48,'全唐诗/poet.song.165000.json','["未仕思從仕，言歸盍賦歸。", "世方疎直道，身亦墮危機。", "舊宅存松桂，春山富蕨薇。", "淵明覺今是，伯玉悟前非。"]'),
('8a7df962-2243-4820-a7d0-483cf344f5e3','十三夜秉文携詩見過','趙蕃','宋','宋诗','song-poetry','','[]','餐玉我無術，點金君有方。',48,'全唐诗/poet.song.165000.json','["餐玉我無術，點金君有方。", "胡爲仍各瘦，更復問何長。", "月好橋同步，詩佳袖取將。", "歸來未成寐，看葉墮危黄。"]'),
('38b7ae76-d9dd-4ed3-933d-35a89cfa4730','書管掾所抄張安國詩','趙蕃','宋','宋诗','song-poetry','','[]','天上張公子，詩輕萬戶侯。',48,'全唐诗/poet.song.165000.json','["天上張公子，詩輕萬戶侯。", "駕車追熟路，順水放輕舟。", "化鶴驚何遠，藏山散莫收。", "可人秋浦掾，著力爲冥搜。"]'),
('aff682d4-576b-4a98-8f73-f9ae5deb3d33','題三徑圖','趙蕃','宋','宋诗','song-poetry','','[]','憶在宜春日，曾看三徑圖。',48,'全唐诗/poet.song.165000.json','["憶在宜春日，曾看三徑圖。", "腥羶尚京洛，覊旅久江湖。", "豈曰有安宅，絕然忘故都。", "人琴悵俱已，松菊孰充娛。"]'),
('ce60b97e-0029-4ada-bad3-79944618ac21','題舊日所藏晉陶淵明採菊東籬下悠然見南山畫','趙蕃','宋','宋诗','song-poetry','','[]','未必形模似，良由意象高。',48,'全唐诗/poet.song.165000.json','["未必形模似，良由意象高。", "見山非得得，遇酒輒陶陶。", "蕪沒念三徑，飄零悲二毛。", "南征儻亡恙，歸老舊蓬蒿。"]'),
('dfa8545e-23bd-4ae7-a8dc-611b3b1e1075','寄呈壽岡先生二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','竹戶與松窗，當年拜老龐。',48,'全唐诗/poet.song.165000.json','["竹戶與松窗，當年拜老龐。", "鬢毛霜自滿，文力鼎猶扛。", "我句何堪讀，公詩舊所降。", "寧聞曹與鄶，可並楚三江。"]'),
('ccec6de5-c179-40a5-a0fe-2b09b1f7bc20','寄呈壽岡先生二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我愛清江郡，端如屋上烏。',48,'全唐诗/poet.song.165000.json','["我愛清江郡，端如屋上烏。", "掛冠推二老，縫掖盛諸儒。", "吳蜀書難得，荆蠻病益癯。", "飛黄去騰踏，局趣效轅駒。"]'),
('44b7e04f-42b6-43f0-8c8a-50fdc7c1538a','二詩敬寄致政大夫先生  其一','趙蕃','宋','宋诗','song-poetry','','[]','每見清江使，常詢向子平。',48,'全唐诗/poet.song.165000.json','["每見清江使，常詢向子平。", "徐行爲山健，老眼對書明。", "世共尊耆舊，愚猶及老成。", "誰人要半道，願與一門生。"]'),
('4f7de8d0-53af-409f-a0bb-85f777e86e7f','二詩敬寄致政大夫先生  其二','趙蕃','宋','宋诗','song-poetry','','[]','不向薌林去，于今又四年。',48,'全唐诗/poet.song.165000.json','["不向薌林去，于今又四年。", "琴書故間止，草木想蒼然。", "安否音書曠，飄零日月還。", "禮加如下榻，興盡敢回船。"]'),
('54f3287d-4614-4f33-9378-6c90d7b785bc','投介庵先生并寄廬陵周侍郎四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','忽憶滄洲去，何心漢節持。',48,'全唐诗/poet.song.165000.json','["忽憶滄洲去，何心漢節持。", "上書期得請，勇退復奚疑。", "用舍非吾事，榮枯自彼時。", "疾風勁草見，松柏歲寒知。"]'),
('b51de951-8882-49d0-b55b-5d29a7d4aa03','投介庵先生并寄廬陵周侍郎四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','貳卿辭郡日，刺史乞身年。',48,'全唐诗/poet.song.165000.json','["貳卿辭郡日，刺史乞身年。", "往事甑已墮，歸來璧顧全。", "坐令頹俗振，未覺古人賢。", "白鷺思高舉，琵琶有直絃。"]'),
('521636bf-8c15-4402-b48e-6cdb41b3f943','投介庵先生并寄廬陵周侍郎四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','桐鄉曾作令，使者復乘車。',48,'全唐诗/poet.song.165000.json','["桐鄉曾作令，使者復乘車。", "風俗因子厚，溪山要我居。", "此聲聞舊矣，今日見歸歟。", "祇恐功名事，毋庸遽舍諸。"]'),
('83e02414-5d02-49fe-8f5a-3f323f7c7186','投介庵先生并寄廬陵周侍郎四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','粗識詩中趣，翻憐筆下難。',48,'全唐诗/poet.song.165000.json','["粗識詩中趣，翻憐筆下難。", "中流疑失檝，遠舉慮摧翰。", "起我七十病，蘄公九轉丹。", "韓豪非所敢，曾未到郊寒。"]'),
('df47d890-0461-44a1-bedb-0c025e0df3d0','周愚卿以二蘇先生李公擇黄魯直秦少遊真跡見示敬賦四十字','趙蕃','宋','宋诗','song-poetry','','[]','蘇李是吾師，黄秦實嗣之。',48,'全唐诗/poet.song.165000.json','["蘇李是吾師，黄秦實嗣之。", "愛其吟可老，得自買傾資。", "有本皆如是，斯文不在茲。", "因知迺翁意，遺子以鎡基。"]'),
('993bc96b-f11a-47dc-9406-02d9b46948fe','文叔見餞于郊外且有所論復賦此','趙蕃','宋','宋诗','song-poetry','','[]','已辱臨岐送，還能喚酒來。',48,'全唐诗/poet.song.165000.json','["已辱臨岐送，還能喚酒來。", "欲行雖倥傯，數刻爲裴回。", "出處豈漫爾，古今寧異哉。", "滔滔勿渠歎，落落自余哀。"]'),
('b0c43f5e-d9fc-40c1-9f63-972932bce9a6','蕃艤舟湘西之明夕鄭仲理吳德夫周伯壽黎季成共置酒於書院閣下追餞者邢廣聲王衡甫時戊申仲秋七日','趙蕃','宋','宋诗','song-poetry','','[]','已別還重送，情親獨數君。',48,'全唐诗/poet.song.165000.json','["已別還重送，情親獨數君。", "贈詩難卒和，別酒易成醺。", "渺渺江山恨，飄飄鴻鴈羣。", "不忘相博約，未可間知聞。"]'),
('5dab0cc9-04a9-4019-b66e-dd2399c58864','趨上饒道中','趙蕃','宋','宋诗','song-poetry','','[]','風雨催梅子，溪山進客舟。',48,'全唐诗/poet.song.165000.json','["風雨催梅子，溪山進客舟。", "登臨雖慰眼，悵望復增愁。", "歲月常爲旅，饑寒不自謀。", "翩翩羨林鳥，閑逸愧沙鷗。"]'),
('7f36d03c-5557-4ac6-8355-603ea4fb43d2','周愚卿同丁永年陳明叔見餞于去城之十里致嚴堂經夕乃別','趙蕃','宋','宋诗','song-poetry','','[]','林表楓能赤，崖邊菊許長。',48,'全唐诗/poet.song.165000.json','["林表楓能赤，崖邊菊許長。", "別情俱慘憺，風日倍荒凉。", "豈爲鍾情極，端由取友良。", "頹然醒雜意，初不累杯觴。"]'),
('97b0ee0a-de26-4861-882b-826a82a51bea','李叔器方養源叔器之姪填載酒餞余於思敬亭','趙蕃','宋','宋诗','song-poetry','','[]','倦客理舟楫，高情携酒肴。',48,'全唐诗/poet.song.165000.json','["倦客理舟楫，高情携酒肴。", "有亭當水澨，共步轉江臯。", "我已乘流去，渠猶佇立勞。", "風前醉難倚，月照首頻搔。"]'),
('0809b1a8-22a0-4ca0-bd5f-d5be40a5c7aa','新漕道中','趙蕃','宋','宋诗','song-poetry','','[]','夜雨響屋瓦，曙煙遮樹林。',48,'全唐诗/poet.song.165000.json','["夜雨響屋瓦，曙煙遮樹林。", "田行疑倍滑，水度覺知深。", "顧望勞雙目，顛躋怖此心。", "垂堂不知戒，家故乏千金。"]'),
('a8931a88-7280-4649-b2ab-62cdeaa912f4','宿分水','趙蕃','宋','宋诗','song-poetry','','[]','夜枕疑爲雨，曉檐還見星。',48,'全唐诗/poet.song.165000.json','["夜枕疑爲雨，曉檐還見星。", "驟聞成摵摵，熟聽乃泠泠。", "信矣無不下，況於高建瓴。", "此行非絕遠，楚粵自相因。"]'),
('0031fd01-50b2-4b43-9788-ec95aeeefd57','舟行','趙蕃','宋','宋诗','song-poetry','','[]','下水復上水，暮秋仍早秋。',48,'全唐诗/poet.song.165000.json','["下水復上水，暮秋仍早秋。", "暫歸非去吏，觸緒苦添愁。", "本乏風雅作，謾于山水遊。", "經營欲終日，人謂我何求。"]'),
('74122f81-4910-466e-b505-6eafa0838016','二十一日湖中','趙蕃','宋','宋诗','song-poetry','','[]','歲晚仍湖路，客中還病身。',48,'全唐诗/poet.song.165000.json','["歲晚仍湖路，客中還病身。", "似聞今大熟，那故獨長貧。", "方朔一囊栗，季鷹千里蓴。", "扁舟固高蹈，金馬亦沉淪。"]'),
('08b8476a-df60-4602-a7b9-e7a4d6511f01','舟中讀子進昆仲西遊集有懷其人作詩寄之并示成父弟二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','君是三珠樹，子非兩玉人。',48,'全唐诗/poet.song.165000.json','["君是三珠樹，子非兩玉人。", "水南留步武，竹隠記風神。", "往者兄同弟，今焉越與秦。", "細哦詩語妙，如款笑談真。"]'),
('ee1c2b4e-ba19-4f58-9837-bbdf0a45e1f0','舟中讀子進昆仲西遊集有懷其人作詩寄之并示成父弟二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','文士今固有，未聞居一門。',48,'全唐诗/poet.song.165000.json','["文士今固有，未聞居一門。", "松筠無異操，繭蕙若同根。", "試問臨風讀，何如把酒論。", "茲行羨吾弟，弭檝向湖村。"]'),
('b6dbb071-67d4-489a-9ef6-f4d70b0802cf','聞晦庵罷宜春留南昌亟往見之將至貴溪逆風大作','趙蕃','宋','宋诗','song-poetry','','[]','下水放輕舠，真期快意遭。',48,'全唐诗/poet.song.165000.json','["下水放輕舠，真期快意遭。", "那知吾道蹇，還值逆風鏖。", "空闊初憑棹，淵洄竟倚篙。", "三山信非遠，弱水謾增勞。"]'),
('598406c9-472b-4caa-a0a7-287ff3a9ec24','約斯遠同謁晦翁先生八月十六日發章泉夜宿永豐','趙蕃','宋','宋诗','song-poetry','','[]','比夕皆佳月，幾年無此期。',48,'全唐诗/poet.song.165000.json','["比夕皆佳月，幾年無此期。", "親朋方戰蟻，而我自驅羸。", "夜作銀河隔，明當玉樹窺。", "猶須發高詠，于以慰長思。"]'),
('2feacfa5-700a-4052-a055-9e5fe94a6f38','初二日蚤發親捷','趙蕃','宋','宋诗','song-poetry','','[]','水落灘鳴急，山高霧散遲。',48,'全唐诗/poet.song.165000.json','["水落灘鳴急，山高霧散遲。", "夜愁餘響遞，晨幸日光披。", "頗憶茱萸飲，還思薏苡齎。", "異鄉逢物色，老病益清羸。"]'),
('918da71d-13cb-4559-bbd3-ade82e393c9a','放舟始作','趙蕃','宋','宋诗','song-poetry','','[]','扁舟落吾手，遠役愴余心。',48,'全唐诗/poet.song.165000.json','["扁舟落吾手，遠役愴余心。", "道路經過數，秋風日夜深。", "青林向摇落，白髮益侵尋。", "况說瀟湘去，仍懷屈賈吟。"]'),
('738111d9-a7dc-4eea-9c49-a8d21c20de13','九月二日發舟快閣下','趙蕃','宋','宋诗','song-poetry','','[]','開船風打頭，舉棹水分流。',48,'全唐诗/poet.song.165000.json','["開船風打頭，舉棹水分流。", "到處皆成客，今年未識秋。", "意哀吟蟋蟀，聲苦亂颼飀。", "拊枕仍推枕，誰知夢覺優。"]'),
('3d7d1286-f006-4535-8fb3-bb623a1d56fe','次韻成父舟中','趙蕃','宋','宋诗','song-poetry','','[]','久客日復日，窮冬冰復冰。',48,'全唐诗/poet.song.165000.json','["久客日復日，窮冬冰復冰。", "知還憐倦鳥，側翅耻饑鷹。", "搔髮傷今老，沿塘記昔曾。", "舒憂足行卷，教諂謝書縢。"]'),
('14f566d2-b6ff-45a7-a7ac-8e81b32358ea','初五日晚雨欲艤舟大琛而舟行過焉示成父弟','趙蕃','宋','宋诗','song-poetry','','[]','一雨晚來凉，山長水又長。',48,'全唐诗/poet.song.165000.json','["一雨晚來凉，山長水又長。", "尋詩貪嶼島，沽酒誤村場。", "蕭瑟聽連夕，飄流入異鄉。", "對眠還晤語，渾憶在山房。"]'),
('7cd2f22c-577c-4a6f-aa3b-bb78953fdfdd','餘干放舟後作時以病不飲故見之詩','趙蕃','宋','宋诗','song-poetry','','[]','月駛雲俱駛，風恬浪亦恬。',48,'全唐诗/poet.song.165000.json','["月駛雲俱駛，風恬浪亦恬。", "渾如畫橫軸，又似鏡開奩。", "蠻子釣未已，長年行不厭。", "素羸同李賀，止酒效陶潛。"]'),
('08a3892c-5474-4edf-887d-3435de6f3680','舟中病思三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','桑葉綠已病，楓林黄亦危。',48,'全唐诗/poet.song.165000.json','["桑葉綠已病，楓林黄亦危。", "行舟得秋日，滿路入新詩。", "照水驚非昔，臨風病不支。", "乾坤一惠施，吾事獨多奇。"]'),
('898e7aef-47e9-4b44-85a9-bcfc751f9bfc','舟中病思三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','已見橫山塔，蘭溪路不多。',48,'全唐诗/poet.song.165000.json','["已見橫山塔，蘭溪路不多。", "青銅吾欠此，竹葉奈渠何。", "貧病成驅役，幽憂復放歌。", "平生釣臺下，老矣負漁蓑。"]'),
('1ad23f64-eea5-4c1d-881a-a201fab47fc9','舟中病思三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','日脚陰晴屢，船身坐卧俱。',48,'全唐诗/poet.song.165000.json','["日脚陰晴屢，船身坐卧俱。", "溪山無入望，覊旅孰爲娛。", "路識長安近，名非短策圖。", "無迷蔡謨蟹，且覓季鷹鱸。"]'),
('8ab0dcb6-b512-4b24-b83a-7422eba0e219','初到舒州','趙蕃','宋','宋诗','song-poetry','','[]','承平非不久，淮地祗凋疎。',48,'全唐诗/poet.song.165000.json','["承平非不久，淮地祗凋疎。", "負販資它郡，蒿萊塞舊閭。", "近江猶若此，窮徼復何如。", "可議輕征戰，仍聞急轉輸。"]'),
('5016f885-8022-4155-9d33-a1f98314c157','旅食有作','趙蕃','宋','宋诗','song-poetry','','[]','旅食頻年倦，田居樂事遥。',48,'全唐诗/poet.song.165000.json','["旅食頻年倦，田居樂事遥。", "春餘桑柘靜，波泛鷺鷗驕。", "折竹深防笋，撐船滿載苗。", "新詩隨見寫，舊髮不勝凋。"]'),
('e115f866-d08c-485d-9bee-4b11614baec6','萬安道中二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','雨小亦滑道，馬遲元自佳。',48,'全唐诗/poet.song.165000.json','["雨小亦滑道，馬遲元自佳。", "金章橘弄色，玉面茶吐花。", "科科初種菜，叢叢未收麻。", "人生皆有理，吾事獨無涯。"]'),
('8241f1be-0cc8-4c7e-8976-452cce93a772','萬安道中二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','籬落未經霜，林園尚吐芳。',48,'全唐诗/poet.song.165000.json','["籬落未經霜，林園尚吐芳。", "豆花連豆角，榴朶映榴房。", "摇落雖茲候，敷榮未爾妨。", "我懷收柿栗，物色自凄凉。"]'),
('28bd9823-c295-477b-968f-e2260763be21','將至鄔子','趙蕃','宋','宋诗','song-poetry','','[]','湖水冬猶壯，林烟晚更孤。',48,'全唐诗/poet.song.165000.json','["湖水冬猶壯，林烟晚更孤。", "荒凉詩莫狀，零落鴈成圖。", "歷歷舊行路，蕭蕭新鬢鬚。", "不知造物意，投老又何如。"]'),
('1bf5399a-4462-46c7-897d-ea12019a6e6d','宣風市作','趙蕃','宋','宋诗','song-poetry','','[]','不誤晨霜白，但驚濃霧黄。',48,'全唐诗/poet.song.165000.json','["不誤晨霜白，但驚濃霧黄。", "過橋初有迹，著木頓生光。", "未怕寒如許，殊勝雨見妨。", "燎薪仍酌酒，一笑作哄堂。"]'),
('79ed01d6-3481-4185-bd99-6c40c1757b8c','上寵市早飯','趙蕃','宋','宋诗','song-poetry','','[]','霧合疑爲雨，雲開復變晴。',48,'全唐诗/poet.song.165000.json','["霧合疑爲雨，雲開復變晴。", "梨花高朶盛，柳樹弱枝榮。", "問寺山場遠，逢虛旅飯營。", "侵晨王事起，亭午野田行。"]'),
('d295c132-f6d8-462a-9ba9-c0f869d24800','九月二十七日題桂溪鋪','趙蕃','宋','宋诗','song-poetry','','[]','昨日方摇扇，今朝可擁裘。',48,'全唐诗/poet.song.165000.json','["昨日方摇扇，今朝可擁裘。", "頓能驚北客，方覺是南州。", "歲儻不逢閏，時今寧復秋。", "無庸歎疎漏，聊得避颼颼。"]'),
('08839e50-fea8-485c-8e38-d215fd1c5be8','飯楓橋鋪','趙蕃','宋','宋诗','song-poetry','','[]','隻堠復雙堠，晨鷄仍午雞。',48,'全唐诗/poet.song.165000.json','["隻堠復雙堠，晨鷄仍午雞。", "春風空浩浩，客意只凄凄。", "驅我因微祿，言歸欠薄畦。", "有懷無與共，聊以命詩題。"]'),
('077944d7-91c0-4e16-bb46-85e2452d51e0','自荔支鋪至楠木鋪偶成書楠木','趙蕃','宋','宋诗','song-poetry','','[]','勿謂夷邦陋，深行亦或嘉。',48,'全唐诗/poet.song.165000.json','["勿謂夷邦陋，深行亦或嘉。", "林空聞落葉，澗淺度枯槎。", "蓐食能支午，勞歌不致嗟。", "道邊惟驛舍，山後有人家。"]'),
('b781cb6f-dbbd-43aa-bfd3-5496b04d633d','夜過半村李商叟謂不可無所賦爲作唐律二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','舊竹茶山宅，新松南澗墳。',48,'全唐诗/poet.song.165000.json','["舊竹茶山宅，新松南澗墳。", "閒風與識面，老我及夫君。", "瘦馬政長路，哀鳼仍莫雲。", "雖然當努力，亡奈復離羣。"]'),
('cd42bfad-c009-46d9-bb20-146d2f19f3eb','夜過半村李商叟謂不可無所賦爲作唐律二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','訪子林間宅，繫余溪上船。',48,'全唐诗/poet.song.165000.json','["訪子林間宅，繫余溪上船。", "還成一夕語，宛似五年前。", "白髮驚新夢，青燈讀近編。", "黎明又當別，相對欲忘眠。"]'),
('c2342b22-de35-4d2f-b196-c4f23da9c721','將至豫章','趙蕃','宋','宋诗','song-poetry','','[]','棹落歸雲底，帆飛夕照間。',48,'全唐诗/poet.song.165000.json','["棹落歸雲底，帆飛夕照間。", "起予爲白社，極目是西山。", "蘆雪新鬚鬢，楓丹昔面顔。", "炊遲餓已慣，酒貴醉能慳。"]'),
('dfde777b-6d9c-4b34-baca-c1ea20da1d33','巴丘驛晚題二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','水驛聊容借，官曹少逭勞。',48,'全唐诗/poet.song.165000.json','["水驛聊容借，官曹少逭勞。", "關門對風雨，策杖看波濤。", "浩浩心疑壯，悠悠首遽搔。", "忽來雙白鷺，佇立久江臯。"]'),
('7a4d3463-fd2e-4344-afff-85283f8b273f','巴丘驛晚題二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','戰伐求三國，覊縻自五溪。',48,'全唐诗/poet.song.165000.json','["戰伐求三國，覊縻自五溪。", "歸飛慕鴻鴈，沿戲狎鳧鷖。", "酒以忘憂酌，詩因訪古題。", "是身真老矣，南北更東西。"]'),
('73d60dc0-245f-403f-b0d7-259fc45132d5','綠蘿道中','趙蕃','宋','宋诗','song-poetry','','[]','人間白馬渡，世外綠蘿山。',48,'全唐诗/poet.song.165000.json','["人間白馬渡，世外綠蘿山。", "水駛舟何蹇，人危境故閑。", "傳呼屢落膽，應接一怡顔。", "更擬桃川路，明朝得意攀。"]'),
('9858a92a-a58b-44ef-bdd2-44543d470877','宿野人家','趙蕃','宋','宋诗','song-poetry','','[]','凜若將崩石，狂哉既倒流。',48,'全唐诗/poet.song.165000.json','["凜若將崩石，狂哉既倒流。", "詩危欠好語，日晚覓安投。", "勞我行何苦，嗟渠戍未休。", "田居與官籍，俱坐有身憂。"]'),
('9cf84599-8b6e-4201-8f32-cd6995a51828','宿藍畬寺','趙蕃','宋','宋诗','song-poetry','','[]','嶺斷仍分徑，林紆更著行。',48,'全唐诗/poet.song.165000.json','["嶺斷仍分徑，林紆更著行。", "畏人嫌俗駕，留客得僧房。", "脊記年何古，吾家句亦香。", "茲行經寺五，於此獨難忘。"]'),
('5cdf5918-81fc-4c60-9f4a-6bdd07bff876','遊浮洲寺','趙蕃','宋','宋诗','song-poetry','','[]','久客渾忘頼，羣山得細看。',48,'全唐诗/poet.song.165000.json','["久客渾忘頼，羣山得細看。", "身如悟浮沒，詩喜助波瀾。", "塑象觀殊詭，作鐘懷叛干。", "東湖空壯麗，芝嶺漫林巒。"]'),
('b5844dec-9331-488d-a75b-b62454c306b1','宿彭湖寺懷斯遠','趙蕃','宋','宋诗','song-poetry','','[]','路仄山崖滑，庭中桂樹蒼。',48,'全唐诗/poet.song.165000.json','["路仄山崖滑，庭中桂樹蒼。", "驟衝疎雨過，徐步晚風長。", "沽酒尋官道，哦詩遶佛廊。", "曠懷思我友，林趣憶支郎。"]'),
('d02e9578-5153-480d-933f-0d61c381a586','過石陂少焉至曲睹寺','趙蕃','宋','宋诗','song-poetry','','[]','朝雨自應雨，晚晴真是晴。',48,'全唐诗/poet.song.165000.json','["朝雨自應雨，晚晴真是晴。", "猶經水曲折，方得寺紆縈。", "鳥喚聲何好，雲歸迹故經。", "青山能見導，破衲可無迎。"]'),
('042d1439-9da5-4d35-a0ba-0b474304a615','早飯大明寺因題','趙蕃','宋','宋诗','song-poetry','','[]','晨起渾疑晚，山晴尚踏泥。',48,'全唐诗/poet.song.165000.json','["晨起渾疑晚，山晴尚踏泥。", "花邊花鴨卧，竹裏竹鷄啼。", "問店欣逢寺，命車仍杖藜。", "松篁猶有徑，桃李得無蹊。"]'),
('5db99565-a306-4db1-9d22-98d225d91290','投宿龍溪寺夜行迷道者久之','趙蕃','宋','宋诗','song-poetry','','[]','已辨龍溪宿，寧知鳥路迂。',48,'全唐诗/poet.song.165000.json','["已辨龍溪宿，寧知鳥路迂。", "林光收瑣碎，山月失須臾。", "見約雖田父，歸尤自老夫。", "但知尋野寺，不擬問官途。"]'),
('d5bcc8a7-c54d-4dd2-b183-2de281122a60','將至信州二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','長年遇百艱，十步九逢灘。',48,'全唐诗/poet.song.165000.json','["長年遇百艱，十步九逢灘。", "龍湫平淵蓄，靈山列岫寒。", "庖厨朝飯薄，絺綌晚衣單。", "獨抱高深意，知音誰爲彈。"]'),
('ae08e8ea-4724-4695-986f-480e42fd50ee','將至信州二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','溪日照人明，溪風著鬢清。',48,'全唐诗/poet.song.165000.json','["溪日照人明，溪風著鬢清。", "一生長是客，半日詎留程。", "綠水浮梁貼，青林古塔擎。", "雖然異鄉國，聊爾寄歸情。"]'),
('26a39ea7-1e86-44f0-a9c0-c0f6c381d9b6','漁門舟中','趙蕃','宋','宋诗','song-poetry','','[]','霜落蘆可殺，水歸湖漸洲。',48,'全唐诗/poet.song.165000.json','["霜落蘆可殺，水歸湖漸洲。", "遵鴻歲棲集，振鷺日優遊。", "鄔子兵巡徼，豫章吳地頭。", "茲生凡幾過，時序古囊收。"]'),
('59af3752-f5a1-4082-a632-9c1d00bd3fd5','十三夜使風','趙蕃','宋','宋诗','song-poetry','','[]','雪浪湧如山，乘風失泝灘。',48,'全唐诗/poet.song.165000.json','["雪浪湧如山，乘風失泝灘。", "窮途雖粗慰，悸魄敢懷安。", "燈閃漁家迥，鴈哀江渚寒。", "怪來詩語瘦，良欠酒杯寬。"]'),
('5db26977-2d3a-4389-8df7-a973bb26b9eb','三日風果止早行','趙蕃','宋','宋诗','song-poetry','','[]','側枕聽風吹，撐篷避雨絲。',48,'全唐诗/poet.song.165000.json','["側枕聽風吹，撐篷避雨絲。", "不忘披敗帙，何暇問朝炊。", "浪靜川無迹，雲行山不移。", "自知非畫手，游戲一於詩。"]'),
('39de9972-20b0-4291-836e-03f0787d56ce','六日早途中見耕者','趙蕃','宋','宋诗','song-poetry','','[]','夜雨未收脚，宿耕初起頭。',48,'全唐诗/poet.song.165000.json','["夜雨未收脚，宿耕初起頭。", "聊茲一日力，慰此半年愁。", "長路厭策蹇，還家思借牛。", "未須論旨蓄，端爾待來牟。"]'),
('1fae5cef-eb1c-4770-9a61-df90977ab889','杭橋道間二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','屢起瞻雲物，頻成聽雨聲。',48,'全唐诗/poet.song.165000.json','["屢起瞻雲物，頻成聽雨聲。", "與憂明所歷，咸謂曉當晴。", "一水通高下，千山雜晦明。", "逢人問前路，爲報已堪行。"]'),
('3ecf546c-8fb8-44bb-9d23-d502088ce797','杭橋道間二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','安穩侵晨發，杭橋薄暮休。',48,'全唐诗/poet.song.165000.json','["安穩侵晨發，杭橋薄暮休。", "山窮多石峙，渡涉亂川流。", "野性安猿馬，歸心逐鷺鷗。", "時平從路險，吾在豈人謀。"]'),
('1314cc25-e9a9-47fb-9f07-ea2cafe66e2a','玉田道中','趙蕃','宋','宋诗','song-poetry','','[]','釋屩雲移樹，批崖水暗橋。',48,'全唐诗/poet.song.165000.json','["釋屩雲移樹，批崖水暗橋。", "殷勤勸耕鳥，勞苦趁虛樵。", "晨起人忘憊，泥行馬不驕。", "哦詩殊有味，造謁未妨遥。"]'),
('13f1b0c0-9bed-4f87-9e4e-7db8992eb069','過分水嶺二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','水激風仍疾，山叢日易收。',48,'全唐诗/poet.song.165000.json','["水激風仍疾，山叢日易收。", "才欣稍妍暖，忽恐變颼飀。", "久客奚多感，對茲真欲愁。", "無爲尚絺綌，當復念衣裘。"]'),
('54906416-f18d-4872-9dc6-687c88ba3fe2','過分水嶺二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','不歷閩山險，空云蜀道難。',48,'全唐诗/poet.song.165000.json','["不歷閩山險，空云蜀道難。", "有泉皆瀑布，無路不紆盤。", "酒薄愁難破，詩成鼻爲酸。", "舉頭唯見日，何處是長安。"]'),
('688770ba-b35f-416a-ae30-c4f5d2033ce7','下七盤嶺','趙蕃','宋','宋诗','song-poetry','','[]','路絕疑無地，山窮復有天。',48,'全唐诗/poet.song.165000.json','["路絕疑無地，山窮復有天。", "林園更田畝，鷄犬亦人烟。", "江右名疆界，南中勢接連。", "周書信無外，禹別自何年。"]'),
('395a70ac-557a-4e72-8d2b-1820b8d7a0bf','宿永福院','趙蕃','宋','宋诗','song-poetry','','[]','白塔轉青林，微聞谷鳥音。',48,'全唐诗/poet.song.165000.json','["白塔轉青林，微聞谷鳥音。", "行餘四回顧，風至一披襟。", "半日春遊當，勞生落景沈。", "眷焉聊稅駕，老矣盍抽簪。"]'),
('92dcf170-6acd-45be-9780-c55979487587','早過興福寺','趙蕃','宋','宋诗','song-poetry','','[]','謁客因過寺，無車且借馿。',48,'全唐诗/poet.song.165000.json','["謁客因過寺，無車且借馿。", "晴嵐四填擁，我意一凋疎。", "僧勸茱萸飲，身能瘴癘祛。", "寧堪久居此，曷日遂歸與。"]'),
('504de7e3-8238-41ee-bfe7-a0d1cde698e1','過水寺  其一','趙蕃','宋','宋诗','song-poetry','','[]','步向溪南寺，行尋白社徐。',48,'全唐诗/poet.song.165000.json','["步向溪南寺，行尋白社徐。", "祗言猶作客，不悟已遷居。", "照壁詩無恙，當軒竹未疎。", "掛包蘄異日，我欲掇其餘。"]'),
('771f87d7-3b4c-404b-8c12-c94c3844cbf8','過水寺  其二','趙蕃','宋','宋诗','song-poetry','','[]','未見南溪泛，一看洞府家。',48,'全唐诗/poet.song.165000.json','["未見南溪泛，一看洞府家。", "徑荒衝暮雀，林靜起棲鴉。", "鎖鑰何其密，推敲漫自加。", "及歸已薄暮，漁火在園沙。"]'),
('56227b8c-6d8b-475a-9f70-7cd08dfc8f9e','廣平寺次孫子肅壁間韻','趙蕃','宋','宋诗','song-poetry','','[]','野寺夙所歷，山程行苦賒。',48,'全唐诗/poet.song.165000.json','["野寺夙所歷，山程行苦賒。", "桂榮秋賸馥，蓬勃旱吹沙。", "徙倚俄成久，飛騰已向斜。", "異時如問隠，此地亦吾家。"]'),
('eb16d37c-1b61-4a48-aff8-e2e8f3f8dfbe','重陽日','趙蕃','宋','宋诗','song-poetry','','[]','僕夫催蓐食，客子歎蕭晨。',48,'全唐诗/poet.song.165000.json','["僕夫催蓐食，客子歎蕭晨。", "青嶂如迎客，黄花似笑人。", "所思空脈脈，何是罷踆踆。", "未慕龍山達，深懷靖節真。"]'),
('383cf2fd-bf91-4b2a-be7b-791b5eb28896','歸途馬上二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','兀兀真成去，悠悠莫自嫌。',48,'全唐诗/poet.song.165000.json','["兀兀真成去，悠悠莫自嫌。", "陽光施德惠，風力霽威嚴。", "不待投醪賜，端同挾纊兼。", "山林從爾老，歲月豈余淹。"]'),
('72c83456-f189-43e4-baa4-55ec36aed5f9','歸途馬上二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','赤葉江南少，黄花秋後開。',48,'全唐诗/poet.song.165000.json','["赤葉江南少，黄花秋後開。", "禾場皆藁秸，茅屋半蒿萊。", "負日兒童樂，背人鷗鳥猜。", "歸心已飄忽，鞭影顧裴徊。"]'),
('779d867e-71c8-4b4c-a7d1-9f997d89e3ba','早行五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','前邁不待曉，昔歸何苦稽。',48,'全唐诗/poet.song.165000.json','["前邁不待曉，昔歸何苦稽。", "掛帆欣暫逸，薄險悸深擠。", "試問危行水，何如穩杖藜。", "梅花好調護，春事有端倪。"]'),
('3dc9c60c-2823-47da-9eec-2c087f32ca82','早行五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','萬石湖南港，楊林湖北潭。',48,'全唐诗/poet.song.165000.json','["萬石湖南港，楊林湖北潭。", "不勝摇櫓倦，顧欲使風貪。", "凜凜巖牆戒，悠悠鴆毒耽。", "頻能愧沙鳥，數可傲征帆。"]'),
('3d561c03-bd3b-460f-9529-99aee66919b3','早行五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','蓐食催束擔，候月不待鷄。',48,'全唐诗/poet.song.165000.json','["蓐食催束擔，候月不待鷄。", "始焉星垂野，轉已霧寒溪。", "葦杭悸欹側，鷄栖困攀躋。", "何可數道路，無爲厭蒿藜。"]'),
('4fba5892-b546-494b-bfdc-0ddaf5ba04d6','早行五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','茅屋雞初遞，楓林月半殘。',48,'全唐诗/poet.song.165000.json','["茅屋雞初遞，楓林月半殘。", "灘傾驚枕仄，露下覺衾寒。", "客子愁無那，舟人語未闌。", "蘭溪今夜泊，須酒慰艱難。"]'),
('ceb0ad70-de27-41fa-949a-f74ebbc10eb8','早行五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','落月掛林高，溪行屢著篙。',48,'全唐诗/poet.song.165000.json','["落月掛林高，溪行屢著篙。", "不令驚水宿，頻覺送鷄號。", "此趨今成熟，吾生毋乃勞。", "何能永謝去，自學小舟操。"]'),
('38b9e9ab-0ea1-4d52-a344-d2ec0f5638cf','早發建德','趙蕃','宋','宋诗','song-poetry','','[]','雨霧連晴霧，山行近水行。',48,'全唐诗/poet.song.165000.json','["雨霧連晴霧，山行近水行。", "悠悠成小駐，役役又前征。", "底處衝煙泊，誰家趁曉耕。", "詩材動鄉邑，點檢欠經營。"]'),
('16d54400-3ae9-44df-8add-8fda276cd7a6','隆興城外作','趙蕃','宋','宋诗','song-poetry','','[]','風動雲昏月，櫓鳴鷗避船。',48,'全唐诗/poet.song.165000.json','["風動雲昏月，櫓鳴鷗避船。", "秋清生既夕，客意怯幽眠。", "滯爾江行駛，病余人事牽。", "府公仍仲舉，白屋定誰賢。"]'),
('cdf29837-2196-4121-b66e-d78a896de331','問宿','趙蕃','宋','宋诗','song-poetry','','[]','川原泥滑汰，山嶺石麤疎。',48,'全唐诗/poet.song.165000.json','["川原泥滑汰，山嶺石麤疎。", "經歷雖云惡，馳驅不暇徐。", "逢人詢野寺，對宿祗村墟。", "薄莫須安止，平明議所如。"]'),
('f38bea49-ab51-4d3a-aa3d-6eb0c16d4e3e','二十日夜宿小楊','趙蕃','宋','宋诗','song-poetry','','[]','儂問何村泊，人詢底處船。',48,'全唐诗/poet.song.165000.json','["儂問何村泊，人詢底處船。", "凶年無善俗，永夜少安眠。", "僅有多年被，猶無舊物氈。", "未應能我累，瑟縮自成然。"]'),
('966d3a9b-bfd6-4d66-b203-00fbe198cfce','秋陂道中三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','晨鐘離野寺，早市出村墟。',48,'全唐诗/poet.song.165000.json','["晨鐘離野寺，早市出村墟。", "山在空濛裏，路經崩缺餘。", "崎嶇方自此，阻絕信非虛。", "却羨林間翮，飛翔得自如。"]'),
('3d56293d-eafc-4b20-a0d2-94d0173db214','秋陂道中三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','止水通流水，前陂接後陂。',48,'全唐诗/poet.song.165000.json','["止水通流水，前陂接後陂。", "農夫秧馬駛，客子竹輿危。", "五斗真聊爾，百艱誰使之。", "不能懲創在，猶後强裁詩。"]'),
('49ba18ab-fa8d-4c95-8148-18b6c0af9079','秋陂道中三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','雨止鳩頻喚，雨來鳩蹔停。',48,'全唐诗/poet.song.165000.json','["雨止鳩頻喚，雨來鳩蹔停。", "愁懷惟慘慘，望極更冥冥。", "鷺舉青林破，牛行白水經。", "渾忘峻嶺在，便擬午鐘聽。"]'),
('f98886a1-f9ff-48e0-822c-d351c67dea44','投宿湘東','趙蕃','宋','宋诗','song-poetry','','[]','霧雨雜炊烟，山巔復樹巔。',48,'全唐诗/poet.song.165000.json','["霧雨雜炊烟，山巔復樹巔。", "初疑但紛若，有聽忽騷然。", "立馬看題壁，衝鷗喚渡船。", "莫嗟饑鴈外，且及暮鴉前。"]'),
('606ad699-028f-45ce-a7c7-aee74bdee858','晨起行菜','趙蕃','宋','宋诗','song-poetry','','[]','勿謂山園瘠，能令菜本肥。',48,'全唐诗/poet.song.165000.json','["勿謂山園瘠，能令菜本肥。", "相雖無肉食，穀免病年饑。", "看此鮭三九，何時腰十圍。", "試評能自照，孰愈莫勝衣。"]'),
('15067bae-e2e8-4e68-a2c5-cb59f386ff87','安福界上遠山之巔樵者頗衆而山色如墨蓋燒餘也路逢村婦携籃者數輩問之云採野菜去','趙蕃','宋','宋诗','song-poetry','','[]','日上野燒沒，雲端樵路分。',48,'全唐诗/poet.song.165000.json','["日上野燒沒，雲端樵路分。", "猿猱同矯矯，斤斧競紛紛。", "有婦能供餉，携籃更採芹。", "田桑雖未動，爾事亦云勤。"]'),
('6408afc5-0d81-49aa-bad4-9d69f6906ebd','夙約簽判丈運屬丈同迓客於玉田比出郊側聞二丈已先行及抵所期二丈元未到也因成此四十字','趙蕃','宋','宋诗','song-poetry','','[]','晨起不爲晚，所期安在哉。',48,'全唐诗/poet.song.165000.json','["晨起不爲晚，所期安在哉。", "如言屐上下，復道手敲推。", "久立酴醿架，頻憐玉雪堆。", "睇瞻殊莫及，欹幘屢裴回。"]'),
('320fd901-ce87-40bd-a160-b9b9bcbc2fae','初四日同諸公飲餞共叔於株林明日再往共叔爲置飯歸途賦此寄之','趙蕃','宋','宋诗','song-poetry','','[]','一別定不免，重來聊見情。',48,'全唐诗/poet.song.165000.json','["一別定不免，重來聊見情。", "匆匆置朝飯，憒憒困餘酲。", "會合知何日，升沉恐異情。", "毋忘尺書寄，慰此寸心傾。"]'),
('238d7a37-abbb-4a80-8385-ceb2bea9c48e','贈顔文昺子明用孫從之韻','趙蕃','宋','宋诗','song-poetry','','[]','微風醒蝶夢，驟雨瀉天瓢。',48,'全唐诗/poet.song.165000.json','["微風醒蝶夢，驟雨瀉天瓢。", "剝啄携詩過，丁寧寄語邀。", "詞臣上雍橐，勳閥侍中貂。", "試問龜藏櫝，何如鶴唳霄。"]'),
('f13e9467-67fd-4025-bcc7-a568bb1ec0dd','湖州贈劉二弟兼呈伯瑞昆仲二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','人物稱吾弟，空疎愧老兄。',48,'全唐诗/poet.song.165000.json','["人物稱吾弟，空疎愧老兄。", "別來書更數，相見眼增明。", "行李雖亡恙，艱危實飽更。", "到家春已動，政可及農耕。"]'),
('5c502bd9-f843-4efa-ab63-944a6236b2b6','湖州贈劉二弟兼呈伯瑞昆仲二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','流落又窮歲，漂零悲此生。',48,'全唐诗/poet.song.165000.json','["流落又窮歲，漂零悲此生。", "詩才元自窘，日近轉銷聲。", "後會未可必，離懷空作驚。", "平生願交意，爲我謝諸兄。"]'),
('79cde835-81b8-4a01-896d-f117f3f2f534','贈劉子卿時劉將赴官鎮江併以道別三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','幕府江寧日，校書元祐時。',48,'全唐诗/poet.song.165000.json','["幕府江寧日，校書元祐時。", "堂堂公可作，岌岌我何衰。", "孰有入門冠，而淹管庫卑。", "用長宜顧問，誰與薦天墀。"]'),
('2655982c-e847-493c-9720-b308407ed9d7','贈劉子卿時劉將赴官鎮江併以道別三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','江驛頻臨我，林園屢過公。',48,'全唐诗/poet.song.165000.json','["江驛頻臨我，林園屢過公。", "只言成遂別，何意復來同。", "有用期思勉，無詩枉坐窮。", "舊聞京口酒，準擬醉孤蓬。"]'),
('ef2020d7-39bc-4381-8bb9-5c1d4c95e4fb','贈劉子卿時劉將赴官鎮江併以道別三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','吾友周信道，坐思終死窮。',48,'全唐诗/poet.song.165000.json','["吾友周信道，坐思終死窮。", "眼中寧復有，地下亦難同。", "夢絕西州路，愁聞北固鴻。", "並遊惟伯厚，還愧尺書通。"]'),
('ca5b82d9-6b5c-4ff7-a6e7-ed81d8c4fdcc','贈別鄒君昆仲','趙蕃','宋','宋诗','song-poetry','','[]','湖北湖南路，俱行不憚疲。',48,'全唐诗/poet.song.165000.json','["湖北湖南路，俱行不憚疲。", "難追燎須意，姑慰倚門思。", "世士才華取，君家孝友基。", "更能知我友，相與切磋爲。"]'),
('4255dd73-8ec2-4ca7-8bdf-a641e798aab7','用思叔韻贈通神郎翁思明','趙蕃','宋','宋诗','song-poetry','','[]','吾友徐思叔，會稀多阻離。',48,'全唐诗/poet.song.165000.json','["吾友徐思叔，會稀多阻離。", "要知名下士，看取卷中詩。", "識面恨已晚，因渠端可知。", "通神定何物，莫致孔方疑。"]'),
('b3cbec71-5572-4a52-a4f5-299fc5e9aa57','盧誼伯宜之見過要斯遠同賦以贈二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','近別溪山郡，忽過風雨村。',48,'全唐诗/poet.song.165000.json','["近別溪山郡，忽過風雨村。", "濁醪成共把，佳句得深論。", "舊價真齊駱，新題復到元。", "從今得還往，寧只問寒暄。"]'),
('11e9c127-2382-4cc7-b85e-8c7820933f98','盧誼伯宜之見過要斯遠同賦以贈二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','苕水固多勝，吾州亦可鄰。',48,'全唐诗/poet.song.165000.json','["苕水固多勝，吾州亦可鄰。", "卜居雖匪舊，取友不妨新。", "佛屋從堪寓，溪亭更可人。", "莫嫌鵝鴨惱，最喜鷺鷗馴。"]'),
('bbb02c03-781b-4e5d-b8fc-10e7a639181a','再見王進之於潭王即有岳鄂之行贈之四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','我客猶湖外，君行返漢中。',48,'全唐诗/poet.song.165000.json','["我客猶湖外，君行返漢中。", "乖離從此異，邂逅復茲同。", "始見忘曾識，徐言乃漸通。", "怪來顔重渥，深感鬢成蓬。"]'),
('d8606c1a-e102-4c2e-ab73-73715cbc9549','再見王進之於潭王即有岳鄂之行贈之四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','別日故已久，願言今則多。',48,'全唐诗/poet.song.165000.json','["別日故已久，願言今則多。", "寒溫一勞苦，身世兩蹉跎。", "在己須當勉，其餘莫問他。", "昔賢雖已矣，吾輩合如何。"]'),
('fa0b4071-d54c-4555-a1c3-1fb452fbe9b1','再見王進之於潭王即有岳鄂之行贈之四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','既見雖云喜，語離仍復悲。',48,'全唐诗/poet.song.165000.json','["既見雖云喜，語離仍復悲。", "未知今日別，還是幾年期。", "風雨方頻日，波濤絕壯時。", "長途久已廹，苦語遂成詩。"]'),
('4df0eae1-823e-4ab1-ac2e-9fd900e98537','再見王進之於潭王即有岳鄂之行贈之四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','君髮未可白，親顔元自紅。',48,'全唐诗/poet.song.165000.json','["君髮未可白，親顔元自紅。", "旨甘知有子，婚嫁趣成翁。", "世豈無高義，途寧嘆久窮。", "但當言計拙，不可怨詩工。"]'),
('d81cff9e-40ea-4336-9433-efe7c2b15f7f','讀東湖集二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','世競江西派，人吟老杜詩。',48,'全唐诗/poet.song.165000.json','["世競江西派，人吟老杜詩。", "五言真有律，徐穉是吾師。", "不但時相似，還能猛出奇。", "平生誤學處，深恐不能醫。"]'),
('f34b83bd-077b-4255-989b-5d2a73787d70','讀東湖集二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','頼爾破孤悶，讀之惟恐殘。',48,'全唐诗/poet.song.165000.json','["頼爾破孤悶，讀之惟恐殘。", "行間雖舊熟，句外得新看。", "已後平生學，懸知欲到難。", "堂堂寧復有，凜凜故疑寒。"]'),
('df929238-d24f-4677-aeab-adc036411f25','移官萬安道中','趙蕃','宋','宋诗','song-poetry','','[]','立春今幾日，物色已全回。',48,'全唐诗/poet.song.165000.json','["立春今幾日，物色已全回。", "青入株株柳，芳殘樹樹梅。", "自由人歷落，莫怨馬虺尵。", "總是天涯客，何傷歲盡來。"]'),
('88ea5860-6f0c-4a35-b253-c7b1f1d8cc60','贈筆','趙蕃','宋','宋诗','song-poetry','','[]','管城封已失，少室價難高。',48,'全唐诗/poet.song.165000.json','["管城封已失，少室價難高。", "外作蕭嵩表，中慙去病鏖。", "縱橫才適用，脫略已陳勞。", "自分當頻棄，毋庸謂不遭。"]'),
('314c2c66-675d-403d-be72-64a47173f1bb','筆答','趙蕃','宋','宋诗','song-poetry','','[]','拔毛知不免，受縛歎何窮。',48,'全唐诗/poet.song.165000.json','["拔毛知不免，受縛歎何窮。", "屢沐雖蒙賜，披心每盡忠。", "憤然成臆對，老矣實頭童。", "醉素今安在，歸真託此公。"]'),
('03b2aa15-571f-4d54-b774-21735cdca775','宋行中履叔以其先兄時中亨伯窮藁借觀歸之','趙蕃','宋','宋诗','song-poetry','','[]','古寺秋風客，難兄昔日詩。',48,'全唐诗/poet.song.165000.json','["古寺秋風客，難兄昔日詩。", "人間非舊識，地下有新知。", "爲祿歸難早，知窮計已遲。", "因聲語吾弟，吾亦類渠癡。"]'),
('8354a02e-14f2-4280-9779-70e040991998','錄去冬舟行詩一編呈陳丞并作四十字致見而不款之恨','趙蕃','宋','宋诗','song-poetry','','[]','舊誦流傳句，今逢訾謷丞。',48,'全唐诗/poet.song.165000.json','["舊誦流傳句，今逢訾謷丞。", "不除湖海氣，何急簿書仍。", "禿麈期相對，歸車顧已乘。", "井眢誠漫汲，城壯敢輕登。"]'),
('96748507-f907-4be1-9b6b-411b0b29fbf0','題重脩玉光亭','趙蕃','宋','宋诗','song-poetry','','[]','山無古今異，亭有廢興因。',48,'全唐诗/poet.song.165000.json','["山無古今異，亭有廢興因。", "地迥輪蹄隔，官閒鷗鳥馴。", "仆碑還屋壁，老柳困樵薪。", "載酒論文處，重來感歎頻。"]'),
('1a60601d-99fa-4f67-8407-8c199bea06e9','過叔文園亭題於竹上','趙蕃','宋','宋诗','song-poetry','','[]','一亭幽入徑，萬竹上參天。',48,'全唐诗/poet.song.165000.json','["一亭幽入徑，萬竹上參天。", "我欲成閒詠，君能起醉眠。", "清風誰爲起，宿雨晝猶懸。", "莫厭此物聒，管絃非自然。"]'),
('9d11d933-ac0d-4ac3-8f4c-c847dda1b5fb','邢氏園池上作','趙蕃','宋','宋诗','song-poetry','','[]','可意于茲夕，乃能來此風。',48,'全唐诗/poet.song.165000.json','["可意于茲夕，乃能來此風。", "稻畦初吠蛤，草岸已鳴蟲。", "三徑思茅屋，歸艎憶釣筒。", "淵明寧隠者，魯望豈漁翁。"]'),
('3bb48fc2-c802-44c0-b463-3628d3534ab9','遊妙香院','趙蕃','宋','宋诗','song-poetry','','[]','說似桃花寺，逢人舉舊題。',48,'全唐诗/poet.song.165000.json','["說似桃花寺，逢人舉舊題。", "山門循古磴，閣檻枕清溪。", "三老催人去，孤筇得暫携。", "龜峰仍不遠，觸熱未能躋。"]'),
('96b5d517-7c3d-4bdf-93ea-4d8295097d48','莫萬安要平題知津閣','趙蕃','宋','宋诗','song-poetry','','[]','勢並江磯起，簷因佛屋高。',48,'全唐诗/poet.song.165000.json','["勢並江磯起，簷因佛屋高。", "青羅一縈带，石黛四周遭。", "謂我其留句，誰知老不豪。", "蹔來還亟去，豈亦病滔滔。"]'),
('783b9304-af91-4831-9502-fc09ab0d79ca','游彰法寺打擢秀閣詩以行','趙蕃','宋','宋诗','song-poetry','','[]','四海擢秀閣，茲晨彰法遊。',48,'全唐诗/poet.song.165000.json','["四海擢秀閣，茲晨彰法遊。", "名隨寺俱徙，地入道家流。", "尚喜黄詩在，仍容墨本求。", "從今茅屋底，自有皖山幽。"]'),
('8e851ec7-9444-4bcd-bc2d-a30bc3c13574','留題鄭山人','趙蕃','宋','宋诗','song-poetry','','[]','昔到曾看竹，茲來待酌茶。',48,'全唐诗/poet.song.165000.json','["昔到曾看竹，茲來待酌茶。", "林深驚吠犬，路曲轉脩蛇。", "愛客自不惡，教兒仍足佳。", "半園如可買，欲種邵平瓜。"]'),
('ae1a3168-5a03-45f8-ab3c-e1afb33a1a3c','懷舊','趙蕃','宋','宋诗','song-poetry','','[]','千林猶自綠，一樹獨能紅。',48,'全唐诗/poet.song.165000.json','["千林猶自綠，一樹獨能紅。", "午靄全收外，夕陽將墜中。", "畫誰能事獨，詩我故人工。", "物色凄凉甚，裴回諷詠同。"]'),
('97f40ed7-3043-4cd9-88ee-28433ae700d2','詠智門寺前古樹','趙蕃','宋','宋诗','song-poetry','','[]','愛此山中木，真能閲盛衰。',48,'全唐诗/poet.song.165000.json','["愛此山中木，真能閲盛衰。", "近從吾祖日，遠至迺孫時。", "往往多摧折，堂堂獨保持。", "何殊孔明柏，但乏少陵詩。"]'),
('e75625b9-5291-43ea-a1b7-cee618628541','題梅山','趙蕃','宋','宋诗','song-poetry','','[]','望覺林巒合，行知隴畝分。',48,'全唐诗/poet.song.165000.json','["望覺林巒合，行知隴畝分。", "轉亭橋跨壑，入寺閣連雲。", "薪水僮奴事，經禪長少勤。", "令人生愛敬，何止息塵氛。"]'),
('6e378e9e-b44f-4e56-b1ad-b33d7164d5aa','詠武安山塔','趙蕃','宋','宋诗','song-poetry','','[]','矗矗南山塔，亭亭古邑標。',48,'全唐诗/poet.song.165000.json','["矗矗南山塔，亭亭古邑標。", "閑遊賒積歲，共宿憶清宵。", "尖出知天近，層分見木彫。", "未須輪犢健，直欲便鵬摇。"]'),
('2bb201dd-00f4-422e-ad6c-24eb14fd4709','再登愚卿無盡藏時已重脩','趙蕃','宋','宋诗','song-poetry','','[]','凉風簷外入，皎月坐中流。',48,'全唐诗/poet.song.165000.json','["凉風簷外入，皎月坐中流。", "白首無新句，青山非舊樓。", "一杯寧惜醉，萬事入搔頭。", "勿向欄干拍，恐驚江上鷗。"]'),
('81fdcb52-6cb7-4c2d-b1b5-9080ac0c6269','吉水落霞亭觀程運使師孟留題作','趙蕃','宋','宋诗','song-poetry','','[]','倦客扁舟泊，危亭落照微。',48,'全唐诗/poet.song.165000.json','["倦客扁舟泊，危亭落照微。", "餘霞信如綺，孤鶩更齊飛。", "感嘆昔所作，傳聞今則非。", "江山有如此，風俗應未違。"]'),
('0de66023-9472-4a90-997c-471cc7420745','書買江天閣壁','趙蕃','宋','宋诗','song-poetry','','[]','趙壹鄉黨擯，陳登湖海豪。',48,'全唐诗/poet.song.165000.json','["趙壹鄉黨擯，陳登湖海豪。", "飄飄風欲舉，凜凜雪爭高。", "眼界自無極，畫圖空復勞。", "未須驚白髮，聊得湛春醪。"]'),
('17c856de-5336-41c5-a579-e7e318823aef','成父弟作書室於前山舉予舊名堂曰青氈以榜之其旁一窗政直瑞峰取曾大父留題之句榜曰霞牖賦詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','土斷既已久，北人誰復論。',48,'全唐诗/poet.song.165000.json','["土斷既已久，北人誰復論。", "莫嗟前輩遠，尚有束書存。", "未免文科事，猶須素業尊。", "悵余今白首，寧復振吾門。"]'),
('07c4d83c-1bee-47d2-baa3-7dc416e11dfd','成父弟作書室於前山舉予舊名堂曰青氈以榜之其旁一窗政直瑞峰取曾大父留題之句榜曰霞牖賦詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','避地初尚走，吾家住瑞峰。',48,'全唐诗/poet.song.165000.json','["避地初尚走，吾家住瑞峰。", "曾門有遺刻，一代仰高蹤。", "幾恨煙霞隔，忽欣窗戶逢。", "眼明聊隠几，足倦免扶筇。"]'),
('d5eb7bf6-85fb-4116-aa27-6a2a79300cd5','書方伯謨窗間','趙蕃','宋','宋诗','song-poetry','','[]','問此林間屋，何年所築成。',48,'全唐诗/poet.song.165000.json','["問此林間屋，何年所築成。", "開窗山自入，遶屋水長鳴。", "可靜看書眼，如參琢句聲。", "白雲原上宅，比並孰堪兄。"]'),
('24c1d5b8-67eb-4d4e-855b-0e2d60863230','題乾明庵','趙蕃','宋','宋诗','song-poetry','','[]','誰結道人廬，前臨博士湖。',48,'全唐诗/poet.song.165000.json','["誰結道人廬，前臨博士湖。", "名非竄荒李，官是避秦廬。", "隠德雖無述，清風不可渝。", "嚴元有孫子，往往混樵漁。"]'),
('bcb7b8a9-4fda-4aef-88c0-0f82fa114e13','俞孝楊殖齋','趙蕃','宋','宋诗','song-poetry','','[]','士患不知學，既學思有終。',48,'全唐诗/poet.song.165000.json','["士患不知學，既學思有終。", "一年農作計，十稔圃收功。", "四業獨爲重，九經皆寓中。", "勉哉期歲晚，禹稷與顔同。"]'),
('aa57263a-3120-4999-b1f4-0e5c6c6c4467','無盡藏境界','趙蕃','宋','宋诗','song-poetry','','[]','窈窕磯頭路，參差木末簷。',48,'全唐诗/poet.song.165000.json','["窈窕磯頭路，參差木末簷。", "朝嵐變明晦，晚照出濃纖。", "舊日詩故好，新來才更添。", "嗟余已衰薄，彈壓不渠厭。"]'),
('2bff9819-88a4-467b-924d-a687af84323c','題劉正之所得綿州摹本畫鷹','趙蕃','宋','宋诗','song-poetry','','[]','姿態何雄傑，盤拏更崛奇。',48,'全唐诗/poet.song.165000.json','["姿態何雄傑，盤拏更崛奇。", "曾聞左綿畫，舊熟少陵詩。", "說似殊方寄，還容老眼窺。", "君手速收卷，燕雀恐驚疑。"]'),
('ca4af07d-a00b-4497-98da-5cb167f8c25a','隠山寺梁昭明題額','趙蕃','宋','宋诗','song-poetry','','[]','山深不知暑，五月冷如冰。',48,'全唐诗/poet.song.165000.json','["山深不知暑，五月冷如冰。", "寂寞前朝寺，風流帝子能。", "田荒空野水，樹老半枯藤。", "不盡懷人興，鐘樓日暮登。"]'),
('dd78c923-e6cc-45e2-9649-3c50e95948b2','寄題分宜簿舍懷古閣爲劉公度賦','趙蕃','宋','宋诗','song-poetry','','[]','雖云閑主簿，曷日顧能閑。',48,'全唐诗/poet.song.165000.json','["雖云閑主簿，曷日顧能閑。", "因榜白雲句，遂追千古還。", "功名常慕藺，事業亦希顔。", "易地能同道，高山俯仰間。"]'),
('9bc8a5a3-31a2-45c4-a390-7498c9bebac5','覓應氏庵','趙蕃','宋','宋诗','song-poetry','','[]','祇知嫌湫隘，何意落崎嶇。',48,'全唐诗/poet.song.165000.json','["祇知嫌湫隘，何意落崎嶇。", "問路因居者，褰裳媿僕夫。", "慟曾憐阮籍，泣豈效楊朱。", "不費幽尋勝，寧思捷徑趨。"]'),
('d193f69a-7800-4367-8011-335bcd98420d','與契兄','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','因懷碧雲友，發興青林端。',48,'全唐诗/poet.song.165000.json','["因懷碧雲友，發興青林端。", "要盡深幽趣，渾忘下上難。", "泉聲流咽絕，松韻響高寒。", "久作廬山別，疑從夢境看。"]'),
('92f00146-a6b3-4836-8b6b-af40298ffe70','與契兄相遇於鄱陽同遊薦福寺','趙蕃','宋','宋诗','song-poetry','','[]','佛寺誠避俗，道宮還少休。',48,'全唐诗/poet.song.165000.json','["佛寺誠避俗，道宮還少休。", "摩挲湯餠腹，嚥漱乳花甌。", "愛此當簷趣，同爲解带留。", "不惟紓我暇，聊亦散吾憂。"]'),
('71bdef5e-e798-420e-aadd-fe6e920cf3f2','同成父逸遠自桃花遊龜峰復回桃花賦詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','杖策入龜峰，行穿數里松。',48,'全唐诗/poet.song.165000.json','["杖策入龜峰，行穿數里松。", "殿依山立壁，門逕石成蹤。", "藥有仙靈異，僧纔粥飯供。", "青冥誰爲斲，衰疾奈何攻。"]'),
('0ee3f1bb-2dd7-4972-9d2d-a17a24dd1a01','同成父逸遠自桃花遊龜峰復回桃花賦詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','薄暮出龜峰，何嫌細雨衝。',48,'全唐诗/poet.song.165000.json','["薄暮出龜峰，何嫌細雨衝。", "道邊方閉戶，溪閣正鳴鐘。", "客意冷如水，詩情哀似蛩。", "更思眠借榻，終夕聽淙淙。"]'),
('5dd427df-c9a7-4ee3-b06b-25e4f9e6e1f6','遊吉祥寺','趙蕃','宋','宋诗','song-poetry','','[]','寒深朝未定，暖翠晚能佳。',48,'全唐诗/poet.song.165000.json','["寒深朝未定，暖翠晚能佳。", "不飲青帘酒，來尋古寺茶。", "連枝空綠竹，獨木漫桃花。", "埋沒聰明水，凄凉六一家。"]'),
('8f28c367-5e01-463c-9226-154b912b50e0','遊太平寺','趙蕃','宋','宋诗','song-poetry','','[]','一水縈紆渡，千松高下栽。',48,'全唐诗/poet.song.165000.json','["一水縈紆渡，千松高下栽。", "童師空有塔，皖伯已無臺。", "似爲尋山至，那因問法來。", "茶香從汝供，詩味遣誰陪。"]'),
('81f3fbae-74aa-42aa-a210-363cffe78a4e','遊茶山廣教寺','趙蕃','宋','宋诗','song-poetry','','[]','在昔鴻漸宅，當年東野詩。',48,'全唐诗/poet.song.165000.json','["在昔鴻漸宅，當年東野詩。", "兩賢雖可象，二士豈難追。", "汩汩泉鳴谷，青青竹守墀。", "平生志獨往，晚歲敢乖期。"]'),
('14ba4173-0e00-4a26-9316-b72c1b1aa864','題東臺寺','趙蕃','宋','宋诗','song-poetry','','[]','日日東臺寺，今朝一葦杭。',48,'全唐诗/poet.song.165000.json','["日日東臺寺，今朝一葦杭。", "不關公事了，政以病軀妨。", "大士遷居夢，寒爐得聖香。", "世人空自異，吾道本何方。"]'),
('e9b4c301-ad02-4155-b368-b5e8bc937d59','假宿總持寺從僧如應借讀高僧詩法欽所編無爲子所敘者','趙蕃','宋','宋诗','song-poetry','','[]','携衾林下寺，借讀碧雲詞。',48,'全唐诗/poet.song.165000.json','["携衾林下寺，借讀碧雲詞。", "窗迥月資白，林疎風起悲。", "生平故耽此，坐久覺忘疲。", "造請非吾事，幽期不在茲。"]'),
('759dd62b-805a-4d8d-93dc-9855f99c8c2a','蓮蕩','趙蕃','宋','宋诗','song-poetry','','[]','舟涉越溪悲，梯攀玉井危。',48,'全唐诗/poet.song.165000.json','["舟涉越溪悲，梯攀玉井危。", "何如澹成映，更有綠相欹。", "不作騷人恨，頻成謝客詩。", "釣船如許坐，簑笠不辭披。"]'),
('d3e4042f-48e4-4ec6-9d51-4cc8686ebee0','題白龍洞三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','循除初㶁㶁，出谷重潺潺。',48,'全唐诗/poet.song.165000.json','["循除初㶁㶁，出谷重潺潺。", "驟或鳴琴瑟，幽疑雜佩環。", "茶經不載陸，瓢飲合居顔。", "借問龍君事，異辭紛莫刪。"]'),
('25e43294-ca8f-4dce-ba56-5942ea207b02','題白龍洞三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','瘦竹依奇石，流清照古梅。',48,'全唐诗/poet.song.165000.json','["瘦竹依奇石，流清照古梅。", "那知道傍舍，遽絕眼中埃。", "肯憚巾衝雨，深防屐破苔。", "病來無脚力，一爲上崔嵬。"]'),
('092139b3-a0b1-4c34-8235-0c28d8ed2855','題白龍洞三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','俞君昔行倦，曾此見留題。',48,'全唐诗/poet.song.165000.json','["俞君昔行倦，曾此見留題。", "丘壑胸中具，煙雲筆下躋。", "如聞在干越，復道走江西。", "使我登臨處，依依獨杖藜。"]'),
('64cecbe2-635d-439d-b6d7-d107df16beaf','王巖  其一','趙蕃','宋','宋诗','song-poetry','','[]','夜入王巖觀，真同久客回。',48,'全唐诗/poet.song.165000.json','["夜入王巖觀，真同久客回。", "望松知窈窕，次背識崔嵬。", "有客成幽屏，談詩記昔來。", "暫遊還契闊，欲去重徘徊。"]'),
('eaf8455f-de39-4c1c-91dd-e2381d3eb67b','王巖  其二','趙蕃','宋','宋诗','song-poetry','','[]','灑落松摇雨，飛流谷墜泉。',48,'全唐诗/poet.song.165000.json','["灑落松摇雨，飛流谷墜泉。", "畫圖難寫貌，詩語易流傳。", "射虎石誰沒，說猿童謾顛。", "徐巖蓋可買，羞澀欠囊錢。"]'),
('51c01d85-d55d-4b41-ab09-39b7c6bcd0aa','李通判休日約僚屬追凉於浄因已復酌於芙蕖館既題名於寺之壁爲賦唐律','趙蕃','宋','宋诗','song-poetry','','[]','野寺依林木，官園带芰荷。',48,'全唐诗/poet.song.165000.json','["野寺依林木，官園带芰荷。", "飯蔬朝共集，尊酒晚成過。", "歲月記遊勝，禮容寬俗苛。", "公能數傾倒，我得慰蹉跎。"]'),
('dad3df30-26f4-4f65-8bb8-e68d6e4753c1','題飛霞亭','趙蕃','宋','宋诗','song-poetry','','[]','處處江邊閣，悠悠客子詩。',48,'全唐诗/poet.song.165000.json','["處處江邊閣，悠悠客子詩。", "欲知歲不與，驗取鬢中絲。", "風雨凄其作，江山益爾奇。", "憐渠不解語，有恨莫能知。"]'),
('6ef951ab-72b9-40a1-955a-7e950b677608','謁孺子祠  其一','趙蕃','宋','宋诗','song-poetry','','[]','務創西都弊，寧知此一時。',48,'全唐诗/poet.song.165000.json','["務創西都弊，寧知此一時。", "忠邪爭憤嫉，基業竟陵遲。", "豈曰忘五就，哀哉逢百罹。", "嚴陵亦同趣，始盛及終衰。"]'),
('b118df04-899a-4839-a9bb-fe0f51e87e81','謁孺子祠  其二','趙蕃','宋','宋诗','song-poetry','','[]','潛德固宜祀，高文寧可埋。',48,'全唐诗/poet.song.165000.json','["潛德固宜祀，高文寧可埋。", "凄凉危像設，漬蝕半莓苔。", "昧爾前賢貴，空令見者哀。", "欲言寧我聽，小立謾徘徊。"]'),
('24d5f9f8-a1a6-42cf-b831-d571a7c7cf64','避雨入總持寺謁澹臺子羽墓','趙蕃','宋','宋诗','song-poetry','','[]','瀕湖有幽寺，避雨適來過。',48,'全唐诗/poet.song.165000.json','["瀕湖有幽寺，避雨適來過。", "吏役毋庸遽，幽尋所得多。", "雷祠真詭特，古墓絕微訛。", "鳥篆森奇畫，龜趺載雅歌。"]'),
('3f542c6e-a035-497f-b3e9-0197798a837c','慈泉','趙蕃','宋','宋诗','song-poetry','','[]','山骨何時鑿，泉泓幾許深。',48,'全唐诗/poet.song.165000.json','["山骨何時鑿，泉泓幾許深。", "羶薌四時供，教養百年心。", "派可栽蓮實，傍宜引竹林。", "勿云閑草木，于以助徽音。"]'),
('a6cc3d08-0edb-4bd7-8600-eae688e0a16c','周十三丈約同馬三丈入青原山賦詩五首以記行  其一','趙蕃','宋','宋诗','song-poetry','','[]','渡江不待餉，勝士約三行。',48,'全唐诗/poet.song.165000.json','["渡江不待餉，勝士約三行。", "夢境故常在，重來年漫更。", "又成春霧掃，何日野田耕。", "要向思公問，燈明香縷橫。"]'),
('3f59627c-dbcd-4159-ac9d-5dd486909eb2','周十三丈約同馬三丈入青原山賦詩五首以記行  其二','趙蕃','宋','宋诗','song-poetry','','[]','有見匪山色，所聞非市聲。',48,'全唐诗/poet.song.165000.json','["有見匪山色，所聞非市聲。", "思公藏有塔，釣士隠無名。", "兀兀故林願，悠悠流俗情。", "經禪雖未暇，樵牧念餘生。"]'),
('e133745c-67be-414b-a4ca-325711d74a2b','周十三丈約同馬三丈入青原山賦詩五首以記行  其三','趙蕃','宋','宋诗','song-poetry','','[]','艇子君先喚，籃輿我復追。',48,'全唐诗/poet.song.165000.json','["艇子君先喚，籃輿我復追。", "聞鐘疑寺直，見塔上林移。", "早起猶思睡，衝寒故覺羸。", "山遊定何得，飯飽細吟詩。"]'),
('5177fe96-5e39-46ac-9f95-c0c639e5d1c0','周十三丈約同馬三丈入青原山賦詩五首以記行  其四','趙蕃','宋','宋诗','song-poetry','','[]','蕭散得終日，驅馳難久居。',48,'全唐诗/poet.song.165000.json','["蕭散得終日，驅馳難久居。", "滅瘢蘇病竹，拋食引潛魚。", "問話僧尋蜀，多茶椀似盧。", "主人佛事外，游戲亦多餘。"]'),
('8f401ef4-3eda-4298-95b7-5a2f65cc5ffd','周十三丈約同馬三丈入青原山賦詩五首以記行  其五','趙蕃','宋','宋诗','song-poetry','','[]','游山忘襆被，喚渡已無航。',48,'全唐诗/poet.song.165000.json','["游山忘襆被，喚渡已無航。", "隔岸初更動，緣沙數里長。", "大呼空亟疾，小立更微茫。", "莫遣眠鷗覺，笑人朝夕忙。"]'),
('03e708ea-73ff-4767-bbab-16604c92f6a0','二十八日同臨湘尉曹呂益卿登岳陽樓  其一','趙蕃','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','地已兼旬住，樓孤百尺登。',48,'全唐诗/poet.song.165000.json','["地已兼旬住，樓孤百尺登。", "誰與同我適，政爾待君曾。", "韓杜愁來讀，西南樂得朋。", "仲春新雨霽，山遠水波興。"]'),
('0b7d897f-151f-4360-aa81-8211b1a2f934','二十八日同臨湘尉曹呂益卿登岳陽樓  其二','趙蕃','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','草沒重湖路，帆孤一葉舟。',48,'全唐诗/poet.song.165000.json','["草沒重湖路，帆孤一葉舟。", "飄風來復斷，凍雨落還收。", "游目窮天末，題詩欠筆頭。", "登臨有如此，好在岳陽樓。"]'),
('d5ceaf32-7937-4085-a8c1-56e1c69adb1c','自九度至衡岳呈同遊潘文叔二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','犖确渾因石，颼飀半以松。',48,'全唐诗/poet.song.165000.json','["犖确渾因石，颼飀半以松。", "秋雞添老狀，老木怯秋容。", "邇日朱張句，當年韓杜蹤。", "辭工欠詩本，理到倚談鋒。"]'),
('d95bf27b-480a-43c3-8fb5-1909147061ce','自九度至衡岳呈同遊潘文叔二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','衡岳文公寺，南昌梅福官。',48,'全唐诗/poet.song.165000.json','["衡岳文公寺，南昌梅福官。", "意馳雖若近，身到每疑難。", "社木悵鳴樐，集賢欣解鞍。", "未須論契闊，聊復話團欒。"]'),
('512e7a90-19d2-489c-ab93-98b19d29702d','送趙一叔江西漕赴召三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','兩載皇華使，江湖得少寬。',48,'全唐诗/poet.song.165000.json','["兩載皇華使，江湖得少寬。", "見皆儒雅錄，聞絕惠文彈。", "內外有輕重，言行無易難。", "春秋賢者責，傾耳向長安。"]'),
('b14a3fc7-6776-42d2-89b9-b32ed6e66bfc','送趙一叔江西漕赴召三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','聖朝無闕政，賤子有私憂。',48,'全唐诗/poet.song.165000.json','["聖朝無闕政，賤子有私憂。", "盜賊何多報，邊防益弛謀。", "循良宜擇守，德政合交脩。", "懷此言無路，公今近冕旒。"]'),
('ac3de7cf-5c37-4436-92bf-92b49c673f3c','送趙一叔江西漕赴召三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','我捧江西檄，公乘使者車。',48,'全唐诗/poet.song.165000.json','["我捧江西檄，公乘使者車。", "飛騰今已去，留落又何如。", "誰敢懷離闊，惟思讀詔除。", "九州期大庇，寧獨愛吾廬。"]'),
('1e0f5eb5-be8f-44c3-8207-3acf5379d2e7','奉送達之秘郎還豫章親庭','趙蕃','宋','宋诗','song-poetry','','[]','吾友不藏善，相逢過所聞。',48,'全唐诗/poet.song.165000.json','["吾友不藏善，相逢過所聞。", "政茲欣再見，忽爾歎離羣。", "舉子名場事，躬行聖處勳。", "相期在白首，勿漫躡青雲。"]'),
('b1c17048-c1f0-44b1-b85e-1948035cef05','感懷二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','無聞真已矣，曷不遂歸哉。',48,'全唐诗/poet.song.165000.json','["無聞真已矣，曷不遂歸哉。", "試問惠文治，何如三徑開。", "人嗤曹是馬，夢覺蟻安槐。", "得喪吾知已，詎須呼去來。"]'),
('811bf3d4-a28c-49a3-b9fa-c48956069f41','感懷二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','佳客與凉風，俱來破藴隆。',48,'全唐诗/poet.song.165000.json','["佳客與凉風，俱來破藴隆。", "風流自江左，材秀又湘中。", "未暇嗟渠屈，端知慰我窮。", "囊錢歎元叔，斗酒羨無功。"]'),
('070d3f4a-1edd-4095-a43d-9dd752314ef2','送常寧吳尉并屬寄聲吳交代尉比行余亦行追作此詩與之','趙蕃','宋','宋诗','song-poetry','','[]','我有章貢役，而君亦解舟。',48,'全唐诗/poet.song.165000.json','["我有章貢役，而君亦解舟。", "飛騰今有路，憔悴不同謀。", "黄甲昔簿尉，秘書行校讎。", "同年若同舍，好爲話綢繆。"]'),
('39dd0ddd-9b0e-41d2-a951-6e351bec7e17','送王亢宗赴建德尉','趙蕃','宋','宋诗','song-poetry','','[]','雁斷行連雨，梧乾葉隕風。',48,'全唐诗/poet.song.165000.json','["雁斷行連雨，梧乾葉隕風。", "悲凉今日別，邂逅幾時同。", "末路多浮梗，吾生甚轉蓬。", "青衫溧陽尉，不歎孟郊窮。"]'),
('baf42710-abc0-4e28-928f-905ccef38b1c','寄送周子中監丞赴舒州二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','引嫌初補外，懷綬復頻年。',48,'全唐诗/poet.song.165000.json','["引嫌初補外，懷綬復頻年。", "自得山水勝，定由仙佛緣。", "往遊成舊矣，有夢尚依然。", "六字今誰嗣，留題乞我傳。"]'),
('4695e52f-2d6b-4ad8-b129-7db8f378253c','寄送周子中監丞赴舒州二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','欲問淮南米，皆云歲不登。',48,'全唐诗/poet.song.165000.json','["欲問淮南米，皆云歲不登。", "疲羸不難活，摩撫政須能。", "但使荒田闢，無勞鑄鐵增。", "素書寧敢寄，苦語未宜憎。"]'),
('6b41dd33-4a01-4cc2-b21a-bac2c1f6a10e','送趙成都五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','蜀道當謀帥，維城孰愈公。',48,'全唐诗/poet.song.165000.json','["蜀道當謀帥，維城孰愈公。", "夷陵護江左，斜谷顧關中。", "北虜心豺虎，南蠻勢蟻蠭。", "守攻雖有異，鎮撫不妨同。"]'),
('f6a87245-d851-41b9-882c-435f06352f0d','送趙成都五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','不但元戎貴，仍兼制使雄。',48,'全唐诗/poet.song.165000.json','["不但元戎貴，仍兼制使雄。", "深沉天與度，簡敬學成功。", "人士薰陶內，兵民教訓中。", "詎應先郤縠，寧復後文翁。"]'),
('3f5473bf-a40a-4727-bcaa-205a6effb695','送趙成都五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','甫也會依武，君平直見强。',48,'全唐诗/poet.song.165000.json','["甫也會依武，君平直見强。", "沈冥幾大隠，坦率異真狂。", "此士不易得，遺風今未亡。", "經過下簾肆，好覓浣花堂。"]'),
('03405696-aafc-41bb-9d8d-11750d0203e9','送趙成都五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','是別且萬里，可無書數行。',48,'全唐诗/poet.song.165000.json','["是別且萬里，可無書數行。", "經過連鄂岳，留滯隔沅湘。", "渺渺孤鴻送，悠悠一葦杭。", "有懷春水闊，無奈暮雲長。"]'),
('8ed31af9-7f67-466c-9924-69051a9c3303','送趙成都五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','雪嶺瞻新鎮，冰溪想舊州。',48,'全唐诗/poet.song.165000.json','["雪嶺瞻新鎮，冰溪想舊州。", "向來欣御李，今日悵依劉。", "有志思乘興，無才稱拔尤。", "深知取義負，不假採薪槱。"]'),
('3ab451e9-128d-4b54-aee8-ca7dd1124d3c','劉茂實赴省袖澹庵舊贈見過索送行詩用韻','趙蕃','宋','宋诗','song-poetry','','[]','蚤日已俊茂，高交仍老成。',48,'全唐诗/poet.song.165000.json','["蚤日已俊茂，高交仍老成。", "貫通雖七略，陶冶異長城。", "聖世患才少，忠言繇主明。", "平生捩眼看，得雋每知名。"]'),
('da309a4a-6250-4edb-ac4b-e318282f946a','追路送誠齋到灘頭驛','趙蕃','宋','宋诗','song-poetry','','[]','樹樹春花阜，田田秀麥滋。',48,'全唐诗/poet.song.165000.json','["樹樹春花阜，田田秀麥滋。", "雖持玉節貴，不廢笋輿詩。", "追送寧辭遠，乖離故在茲。", "無嗔白頭舊，一見有深知。"]'),
('9d28da6e-12ed-4738-846b-ee36e57cee5b','書灘頭驛','趙蕃','宋','宋诗','song-poetry','','[]','閉戶只書癡，郊行粗有詩。',48,'全唐诗/poet.song.165000.json','["閉戶只書癡，郊行粗有詩。", "翠深千頃嶠，煙迥幾茅茨。", "雨作衣添袷，炊遲晝不饑。", "舊題看好在，重是一春期。"]'),
('924e353c-58ce-439c-8b9a-6c19c962a648','送李袁州汎舟入浙','趙蕃','宋','宋诗','song-poetry','','[]','晦庵無處著，泛宅又吳淞。',48,'全唐诗/poet.song.165000.json','["晦庵無處著，泛宅又吳淞。", "載月初尋棹，看山不藉筇。", "聽渠猿鶴怨，心喜鷺鷗逢。", "遥想題詩處，楓橋半夜鐘。"]'),
('0c2ff23d-cd0d-4766-bbc2-2ed0c3ed1db9','送李元藻入浙三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','唐室登科士，多因行卷知。',48,'全唐诗/poet.song.165000.json','["唐室登科士，多因行卷知。", "至今傳不朽，猶或謂能詩。", "辟置仍於取，山林亦罔遺。", "莫嗟今古異，窮達豈人爲。"]'),
('359f1002-4cc0-4405-8329-db9fa73183a8','送李元藻入浙三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','漢廣求才路，嚴徐出上書。',48,'全唐诗/poet.song.165000.json','["漢廣求才路，嚴徐出上書。", "朝猶辱徒步，暮已待公車。", "今世無茲轍，夫君欲振裾。", "雖然寧有限，或者爲吹噓。"]'),
('467da979-621b-4317-afd7-ef4483e5f913','送李元藻入浙三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','我作長沙客，諸公多與遊。',48,'全唐诗/poet.song.165000.json','["我作長沙客，諸公多與遊。", "聞風亦云舊，識面悵無由。", "忽辱高軒過，仍蒙古句投。", "偶從旁舍去，不辦小淹留。"]'),
('78e1be72-ebca-43f4-be56-356add3aba20','送信豐詹丞并寄贛陳丞二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','此地已窮域，更乘惶恐灘。',48,'全唐诗/poet.song.165000.json','["此地已窮域，更乘惶恐灘。", "家聲詞學舊，勇退急流難。", "使者威嚴霽，尚書禮數寬。", "聽渠丞訾謷，也勝尉酸寒。"]'),
('95ea0f87-f407-4594-8168-367065891a1d','送信豐詹丞并寄贛陳丞二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君見陳夫子，懸知問我能。',48,'全唐诗/poet.song.165000.json','["君見陳夫子，懸知問我能。", "江鷗慣眠草，野鴈怯逢矰。", "矯首困疾首，折肱懷曲肱。", "携家能有弟，託死豈無朋。"]'),
('72656dd0-85e9-45b8-9af5-56f33ab1aaab','送王子尊赴衡陽丞','趙蕃','宋','宋诗','song-poetry','','[]','王郎妙人物，獨步向江東。',48,'全唐诗/poet.song.165000.json','["王郎妙人物，獨步向江東。", "昔尉既不醉，今丞寧肯聾。", "相依脣齒國，忽去馬牛風。", "清絕官曹外，何年著我同。"]'),
('70781893-2ef2-4971-8c83-36be11f5a379','送趙詠道還侍兼簡然道昆仲','趙蕃','宋','宋诗','song-poetry','','[]','既見章江水，重逢懷玉山。',48,'全唐诗/poet.song.165000.json','["既見章江水，重逢懷玉山。", "匆匆成履躧，草草僅荆班。", "遥想獻觴後，應多對雨閒。", "期君好兄弟，並轡古人間。"]'),
('689e4759-1724-4d95-a18d-2c93405d8d32','寄晦庵二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','道大誰能與，才難聖所歎。',48,'全唐诗/poet.song.165000.json','["道大誰能與，才難聖所歎。", "浮雲雖蹔掩，寶氣不終蟠。", "走卒稱司馬，蒼生起謝安。", "縱無臨賀送，當有翰林觀。"]'),
('7760017a-98a4-4a4c-b963-4bd88f0a2496','寄晦庵二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','張膽言何壯，擎天志未摧。',48,'全唐诗/poet.song.165000.json','["張膽言何壯，擎天志未摧。", "真成一夔足，何有萬牛回。", "感興能無句，憂時謾舉杯。", "江湖嗟屨役，巾屢阻追倍。"]'),
('507ec54e-e387-4fa1-aca7-2d79c404ed9a','寄趙元歸并屬元默三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶在袁州見，曾遺滿紙詩。',48,'全唐诗/poet.song.165000.json','["憶在袁州見，曾遺滿紙詩。", "臨川得再面，近作重相貽。", "我老已成退，君才真爾奇。", "縱能連日語，寧慰積年思。"]'),
('317db8f9-44e2-4237-abe6-883cb38219c7','寄趙元歸并屬元默三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','撫信元相近，乖離乃爾賒。',48,'全唐诗/poet.song.165000.json','["撫信元相近，乖離乃爾賒。", "何堪落湖外，動即阻天涯。", "嘆我干微祿，期君起故家。", "文科須中早，學力更功加。"]'),
('599b54de-0380-4832-bedd-57261803207b','寄趙元歸并屬元默三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','默也未識面，向來曾予書。',48,'全唐诗/poet.song.165000.json','["默也未識面，向來曾予書。", "由來幾兄弟，絕嘆每乖疎。", "見說長沙驛，猶遲古寺車。", "差池今再矣，佇立又何如。"]'),
('cb4b8e36-814e-4c19-807c-e41f4c7936a7','寄韓季蕭二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','怕到看經院，愁登擬峴臺。',48,'全唐诗/poet.song.165000.json','["怕到看經院，愁登擬峴臺。", "人言已仙佛，我意祗悲哀。", "此道誰人付，陵陽有後來。", "款門期一見，投刺只空回。"]'),
('fffc485b-6087-4299-a12e-bb1b42d3e741','寄韓季蕭二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','近與李商叟，共談韓季蕭。',48,'全唐诗/poet.song.165000.json','["近與李商叟，共談韓季蕭。", "舊氈餘翰墨，幽寺樂簞瓢。", "問友多冥漠，須君慰寂寥。", "云胡又相失，於此亦何聊。"]'),
('7c49ae05-3739-4c0a-a053-d0d8f0e41fa0','代書寄襄陽令于去非','趙蕃','宋','宋诗','song-poetry','','[]','來往豐城縣，尋君總不遭。',48,'全唐诗/poet.song.165000.json','["來往豐城縣，尋君總不遭。", "如聞漾鳬舄，已復用牛刀。", "往事多遺跡，邊庭簡吏曹。", "莫由同古訪，尚擬見詩豪。"]'),
('494043d4-73cd-4864-bff8-ba2e53a08d31','寄喻叔奇丈二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','不見喻工部，經今兩暮春。',48,'全唐诗/poet.song.165000.json','["不見喻工部，經今兩暮春。", "遥知磬湖上，不減浣花濱。", "佳句能名世，浮雲豈絆身。", "爲貪煙雨勝，聊復駕朱輪。"]'),
('cdef15f6-d1c9-491d-896f-d506eddc8081','寄喻叔奇丈二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','飲我長安酒，歌公亦好詩。',48,'全唐诗/poet.song.165000.json','["飲我長安酒，歌公亦好詩。", "試思猶宿昔，忽念已差池。", "要識園林好，何由杖履隨。", "有時觀敘夢，亦復嘆吾衰。"]'),
('684237dd-5110-49d0-b6a1-305e8b66e404','代書寄劉伯瑞仲文叔驥二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','每憶分携地，蒸湘綠遍春。',48,'全唐诗/poet.song.165000.json','["每憶分携地，蒸湘綠遍春。", "于今懷想處，苕霅暗迷津。", "但有乖離數，何由宿昔親。", "附書書復懶，君自識吾真。"]'),
('a54a36fd-6a8e-4d94-9dd4-154750188a93','代書寄劉伯瑞仲文叔驥二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','難兄兩別駕，難弟一參軍。',48,'全唐诗/poet.song.165000.json','["難兄兩別駕，難弟一參軍。", "從仕信多譽，傳家仍茂文。", "嗟余空白髮，期子在青雲。", "寂寞題詩罷，林窗日半曛。"]'),
('4dfd521d-f406-44d0-b14f-1d74bbcdaa66','代書寄俞玉汝','趙蕃','宋','宋诗','song-poetry','','[]','送弟秦淮遠，懷人楚驛長。',48,'全唐诗/poet.song.165000.json','["送弟秦淮遠，懷人楚驛長。", "素書慵寫得，白髮漫相望。", "再見知何日，孤懷只自傷。", "春風桃李徑，流淚不成行。"]'),
('4eec3a86-a6db-494e-8e60-ee57c05e6fb3','寄懷趙南紀二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','聞道君先我，論交我愧君。',48,'全唐诗/poet.song.165000.json','["聞道君先我，論交我愧君。", "長沙辱傾蓋，懷玉悵離羣。", "怪底書多枉，情知義薄雲。", "金蘭雖甚篤，藥石願時分。"]'),
('7e70c05a-bdbf-40c7-bc21-d3832e5a0a9b','寄懷趙南紀二首  其二','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','自別匡廬去，名山不再逢。',48,'全唐诗/poet.song.165000.json','["自別匡廬去，名山不再逢。", "圖看白鹿洞，詩詠紫霄峰。", "泉石難名狀，煙雲幾許重。", "巾車君儻命，襆被我斯從。"]'),
('aec64a3e-8890-47f8-ba10-309ed800b513','寄梁從善','趙蕃','宋','宋诗','song-poetry','','[]','舊說舂陵郡，全如石作州。',48,'全唐诗/poet.song.165000.json','["舊說舂陵郡，全如石作州。", "胸中飽丘壑，筆下剖琳球。", "遥想窗扉敞，多能磊落收。", "平生有餘嗜，安得致林幽。"]'),
('63fe2274-ec90-4279-9591-3358c03e3121','張王臣貺詩詰朝遂行次韻寄之','趙蕃','宋','宋诗','song-poetry','','[]','書貴在瘦硬，詩須成管絃。',48,'全唐诗/poet.song.165000.json','["書貴在瘦硬，詩須成管絃。", "典刑君尚有，老至我加年。", "早作諸侯客，遠勞從事賢。", "見來元不款，別去忽何邊。"]'),
('43ce158c-e087-4fd2-bd74-f7c02202be70','寄懷大聲兄弟叔文老丈兼屬三王叔姪二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','聽雨侵階竹，歸艎入檻荷。',48,'全唐诗/poet.song.165000.json','["聽雨侵階竹，歸艎入檻荷。", "天晴龜曝背，人靜鳥吟柯。", "挾冊弟兄對，煮茶賓客過。", "居閒在此樂，余乃事奔波。"]'),
('4aca9653-2339-4803-beea-d790c0655aa1','寄懷大聲兄弟叔文老丈兼屬三王叔姪二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','今代河南客，當年吏部孫。',48,'全唐诗/poet.song.165000.json','["今代河南客，當年吏部孫。", "青氈餘翰墨，白髮念田園。", "邂逅成相識，飄零忍重論。", "三王如見問，寄謝勿辭煩。"]'),
('9f2748a0-c9fe-45de-8cc2-74de7ff28bc5','九月一日晨起風物凄然不勝懷遠之思作五首寄和父憨申併煩轉致湖池二州也  其一','趙蕃','宋','宋诗','song-poetry','','[]','作別已半百，得書無二三。',48,'全唐诗/poet.song.165000.json','["作別已半百，得書無二三。", "飄零各天外，摇落共江南。", "此去仍加遠，相思轉不堪。", "懷哉對床約，老矣折腰慙。"]');
